// ── Mapa estático Google Maps ──────────────────────────────────────────────
function getMapaTramoUrl(origen, destino) {
  const base = "https://maps.googleapis.com/maps/api/staticmap";
  const params = new URLSearchParams({
    size: "600x200",
    maptype: "roadmap",
    markers: `color:blue|label:A|${origen}`,
    path: `weight:4|color:0x00AEEFff|${origen}|${destino}`,
    key: GOOGLE_MAPS_API_KEY,
    language: "es",
    region: "CL",
  });
  // Agregar marcador destino
  return `${base}?${params.toString()}&markers=color:red|label:B|${encodeURIComponent(destino)}`;
}

// ── Trazabilidad GPS: helpers ───────────────────────────────────────────────

// Codificación de polyline de Google (algoritmo estándar) para dibujar
// el recorrido completo en Static Maps sin exceder el límite de largo de URL.
function encodePolyline(points){
  let plat=0, plng=0, result="";
  const encNum=(num)=>{
    let sgn = num<<1;
    if(num<0) sgn = ~sgn;
    let out="";
    while(sgn>=0x20){ out+=String.fromCharCode((0x20|(sgn&0x1f))+63); sgn>>=5; }
    out+=String.fromCharCode(sgn+63);
    return out;
  };
  for(const [lat,lng] of points){
    const late5=Math.round(lat*1e5), lnge5=Math.round(lng*1e5);
    result += encNum(late5-plat) + encNum(lnge5-plng);
    plat=late5; plng=lnge5;
  }
  return result;
}

function distanciaMetros(lat1,lng1,lat2,lng2){
  const R=6371000, rad=x=>x*Math.PI/180;
  const dLat=rad(lat2-lat1), dLng=rad(lng2-lng1);
  const a=Math.sin(dLat/2)**2+Math.cos(rad(lat1))*Math.cos(rad(lat2))*Math.sin(dLng/2)**2;
  return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
}

// Detecta paradas: agrupa puntos consecutivos dentro de un radio (RADIO_M)
// que se mantienen así por al menos MIN_MIN minutos. No depende de la
// velocidad reportada (que en GPS de celular es poco confiable a baja
// velocidad), sino del desplazamiento real entre puntos.
function calcularParadas(puntos, MIN_MIN=3, RADIO_M=60){
  if(!puntos||puntos.length<2) return [];
  const paradas=[];
  let grupoInicio=0;
  for(let i=1;i<=puntos.length;i++){
    const p0=puntos[grupoInicio];
    const pActual=puntos[i];
    const fueraDeRadio = !pActual || distanciaMetros(p0.lat,p0.lng,pActual.lat,pActual.lng) > RADIO_M;
    if(fueraDeRadio){
      const pFin=puntos[i-1];
      const duracionMin=(new Date(pFin.timestamp_captura)-new Date(p0.timestamp_captura))/60000;
      if(duracionMin>=MIN_MIN){
        paradas.push({
          lat:p0.lat, lng:p0.lng,
          inicio:p0.timestamp_captura, fin:pFin.timestamp_captura,
          duracionMin:Math.round(duracionMin),
        });
      }
      grupoInicio=i;
    }
  }
  return paradas;
}

// Genera la URL de Static Maps con el recorrido completo + marcadores de
// inicio, fin y paradas detectadas. Reduce puntos si son muchos, para no
// exceder el límite de largo de URL de la API.
function getMapaTrazabilidadUrl(puntos, paradas, gruposPorVehiculo){
  if(!puntos||puntos.length===0) return null;
  const MAX_PUNTOS=300;
  // Si no vienen grupos (llamadas antiguas), cae al comportamiento previo
  // tratando todo como un solo grupo.
  const grupos=gruposPorVehiculo&&gruposPorVehiculo.length?gruposPorVehiculo:[puntos];
  const params=new URLSearchParams({
    size:"640x400", maptype:"roadmap", language:"es", region:"CL",
    key:GOOGLE_MAPS_API_KEY,
  });
  const paleta=["0x00AEEFff","0xFF7A00ff","0x22C55Eff","0xE11D48ff","0xA855F7ff"];
  const totalPuntos=grupos.reduce((a,g)=>a+g.length,0);
  const paso=Math.max(1,Math.ceil(totalPuntos/MAX_PUNTOS));
  grupos.forEach((grupo,gi)=>{
    if(grupo.length<2) return;
    const muestreados=grupo.filter((_,i)=>i%paso===0);
    const encoded=encodePolyline(muestreados.map(p=>[p.lat,p.lng]));
    params.append("path", `weight:4|color:${paleta[gi%paleta.length]}|enc:${encoded}`);
    const inicio=grupo[0], fin=grupo[grupo.length-1];
    params.append("markers", `color:green|label:A|${inicio.lat},${inicio.lng}`);
    params.append("markers", `color:red|label:B|${fin.lat},${fin.lng}`);
  });
  // Máximo ~8 paradas como marcadores para no saturar el mapa
  (paradas||[]).slice(0,8).forEach((pa,i)=>{
    params.append("markers", `color:orange|label:${i+1}|${pa.lat},${pa.lng}`);
  });
  return `https://maps.googleapis.com/maps/api/staticmap?${params.toString()}`;
}

async function calcularTramo(origen, destino) {
  try {
    const apiUrl = `https://maps.googleapis.com/maps/api/distancematrix/json?origins=${encodeURIComponent(origen)}&destinations=${encodeURIComponent(destino)}&mode=driving&language=es&key=${GOOGLE_MAPS_API_KEY}`;
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(apiUrl)}`;
    const res = await fetch(proxyUrl);
    if (!res.ok) return null;
    const raw = await res.json();
    const data = raw.contents ? JSON.parse(raw.contents) : raw;
    const element = data.rows?.[0]?.elements?.[0];
    if (element?.status === "OK") {
      return {
        km: (element.distance.value / 1000).toFixed(1),
        tiempo: element.duration.text,
        mapaUrl: getMapaTramoUrl(origen, destino),
      };
    }
    return null;
  } catch { return null; }
}

// ── Snap-to-Roads: ajusta una secuencia de puntos GPS crudos a la calle real ──
// Usa la Google Roads API (mismo proyecto/API key que Distance Matrix y Static
// Maps). La API acepta máx. 100 puntos por llamada, así que se fracciona en
// bloques y se concatena el resultado. interpolate=true rellena la ruta entre
// puntos para que siga la geometría real de la calle (curvas, esquinas), no
// solo los puntos capturados.
// Si la llamada falla (cuota, sin red, tramo fuera de cobertura de calles,
// etc.) retorna null y el llamador debe usar los puntos crudos como respaldo,
// para que la trazabilidad nunca quede sin datos por un corte de esta API.
async function snapToRoads(puntos){
  if(!puntos||puntos.length<2) return null;
  const CHUNK=100;
  const snapped=[];
  try{
    for(let i=0;i<puntos.length;i+=CHUNK){
      // Un punto de solape con el bloque anterior para no perder continuidad
      // en el punto de corte entre llamadas.
      const bloque = i===0 ? puntos.slice(i,i+CHUNK) : puntos.slice(i-1,i+CHUNK);
      const path = bloque.map(p=>`${p.lat},${p.lng}`).join("|");
      const apiUrl = `https://roads.googleapis.com/v1/snapToRoads?path=${encodeURIComponent(path)}&interpolate=true&key=${GOOGLE_MAPS_API_KEY}`;
      const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(apiUrl)}`;
      const res = await fetch(proxyUrl);
      if(!res.ok) return null;
      const raw = await res.json();
      const data = raw.contents ? JSON.parse(raw.contents) : raw;
      if(!data.snappedPoints||!data.snappedPoints.length) return null;
      for(const sp of data.snappedPoints){
        snapped.push([sp.location.latitude, sp.location.longitude]);
      }
    }
    return snapped;
  }catch{ return null; }
}


// ── Generador OT automático ────────────────────────────────────────────────
function generarOT(solicitudes) {
  // Basado en el máximo N° de OT ya existente (no en el largo de la lista):
  // así no choca si hay huecos, solicitudes borradas, o la lista local está
  // desactualizada respecto a la base.
  let max = 0;
  for (const s of (solicitudes||[])) {
    const m = /^QX-(\d+)$/.exec((s.ot||"").trim());
    if (m) { const n = parseInt(m[1], 10); if (n > max) max = n; }
  }
  return `QX-${String(max + 1).padStart(3, "0")}`;
}


// ── Cálculo distancia ──────────────────────────────────────────────────────
function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2-lat1)*Math.PI/180;
  const dLon = (lon2-lon1)*Math.PI/180;
  const a = Math.sin(dLat/2)*Math.sin(dLat/2) +
    Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*
    Math.sin(dLon/2)*Math.sin(dLon/2);
  return (R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a)) * 1.3).toFixed(1); // factor 1.3 para estimar ruta real
}

