async function geocodificar(direccion) {
  try {
    const dir = direccion.toLowerCase();
    // Buscar en coordenadas conocidas
    for(const [key, coords] of Object.entries(COORDS_CONOCIDAS)) {
      if(dir.includes(key)) return coords;
    }
    // Si no encuentra, intentar con Nominatim como fallback
    const query = encodeURIComponent(direccion + ", Chile");
    const url = `https://nominatim.openstreetmap.org/search?q=${query}&format=json&limit=1&countrycodes=cl`;
    const res = await fetch(url);
    const data = await res.json();
    if(data && data[0]) return {lat: parseFloat(data[0].lat), lon: parseFloat(data[0].lon)};
    return null;
  } catch { return null; }
}

// Coordenadas fijas de Pudahuel (Av. Los Alerces)
const PUDAHUEL_COORDS = {lat: -33.4372, lon: -70.7558};

async function calcularKmDesdePudahuel(direccionDestino) {
  try {
    const dest = await geocodificar(direccionDestino);
    if(!dest) return null;
    return parseFloat(haversineKm(PUDAHUEL_COORDS.lat, PUDAHUEL_COORDS.lon, dest.lat, dest.lon));
  } catch { return null; }
}

// Coordenadas de destino de una solicitud para el cálculo de km.
// Devolución (li_devol) sin dirección propia → vuelve a la bodega DHL (Pudahuel).
async function coordsSolicitud(s){
  const loc=(s.direccion||s.destino||"").trim();
  if(s.tipo==="li_devol" && !loc) return PUDAHUEL_COORDS;
  if(!loc) return null;
  return await geocodificar(loc);
}

// Minutos del log más tardío >= 17:00 de una solicitud (o null si no hay).
function ultimoLogPost17(log){
  let max=null;
  for(const e of (log||[])){
    const p=(e.fechaHora||"").split(" "); if(p.length<2) continue;
    const t=p[1].split(":"); const m=parseInt(t[0],10)*60+parseInt(t[1]||"0",10);
    if(!isNaN(m)&&m>=17*60){ if(max===null||m>max) max=m; }
  }
  return max;
}
// IDs de solicitudes con COBRO Overnight:
//  - carga_ol antes de 08:30 → por solicitud
//  - log después de 17:00 → UNA por PPU (la más tardía); sin PPU → por solicitud
function overnightIds(sols){
  const ids=new Set();
  const lateByPpu={};
  for(const s of (sols||[])){
    // Devolución normal: no genera overnight (no se cobra). La urgente sí participa.
    if(s.tipo==="li_devol" && s.devolucionUrgente!==true) continue;
    const h=(s.hora||"").split(":");
    const mins=s.hora?parseInt(h[0],10)*60+parseInt(h[1]||"0",10):null;
    if(s.tipo==="carga_ol" && mins!==null && !isNaN(mins) && mins<8*60+30) ids.add(s.id);
    const t=ultimoLogPost17(s.statusLog);
    if(t!==null){
      const ppu=(s.ppuAsignada||"").trim();
      if(!ppu){ ids.add(s.id); }
      else if(!lateByPpu[ppu] || t>lateByPpu[ppu].t){ lateByPpu[ppu]={id:s.id,t}; }
    }
  }
  for(const k of Object.keys(lateByPpu)) ids.add(lateByPpu[k].id);
  return ids;
}

// ── Motor de cobros centralizado ───────────────────────────────────────────
// Reglas acordadas:
//  SPOT Extra ($50.000): contador GLOBAL por día (todas las PPU juntas). Desde la 7ma
//    gestión del día, cada una es SPOT. NO cuentan: Carga OL (siempre) ni Devolución normal.
//    La Devolución urgente sí cuenta.
//  Overnight ($85.000), por PPU y por día:
//    · Temprano: PPU con ≥1 solicitud (≠ Carga OL, ≠ Devolución normal) agendada antes de 08:30.
//    · Tarde: PPU con ≥1 registro de log ≥17:00 (se cobra la que cierra más tarde).
//    · Temprano y tarde se cobran AMBOS (hasta 2 por PPU/día).
//  Prevalece overnight: si una misma solicitud es SPOT y además genera el cobro overnight,
//    se cobra solo overnight (se suprime su SPOT).
const PRECIO_SPOT = 50000, PRECIO_OVERNIGHT = 85000;
function _minHora(h){ if(!h) return null; const p=String(h).split(":"); const hh=parseInt(p[0],10); const mm=parseInt(p[1]||"0",10); return isNaN(hh)?null:hh*60+mm; }
// Momento de cierre (para numerar en orden ascendente según se cierran los registros)
function _parseFH(fh){
  if(!fh) return 0;
  const m = String(fh).match(/(\d{1,2})-(\d{1,2})-(\d{4})\s+(\d{1,2}):(\d{2})/);
  if(m) return new Date(+m[3],+m[2]-1,+m[1],+m[4],+m[5]).getTime();
  const d = Date.parse(fh); return isNaN(d)?0:d;
}
function _ordenCierre(s){
  const log = s.statusLog||[];
  if(log.length){ const t=_parseFH(log[log.length-1].fechaHora); if(t) return t; }
  const u = Date.parse(s.updatedAt||s.createdAt||"")||0;
  return u;
}
function calcularCobros(solicitudes){
  const sols = (solicitudes || []).filter(s=>!s.sinCobro); // exentas de cobro: fuera de todo cálculo
  const perId = {};
  for(const s of sols){
    const esCargaOL = s.tipo==="carga_ol";
    const esDevol = s.tipo==="li_devol";
    const esDevolUrg = esDevol && s.devolucionUrgente===true;
    const esDevolNormal = esDevol && !esDevolUrg;
    perId[s.id] = { esSpot:false, ohEarly:false, ohLate:false, nro:0,
      _cargaOL:esCargaOL, _devolNormal:esDevolNormal,
      _cuenta: !esCargaOL && !esDevolNormal };
  }
  // SPOT: contador global por día, numerado en ORDEN DE CIERRE ascendente
  const contN = {};
  const ordenadas = [...sols].sort((a,b)=>_ordenCierre(a)-_ordenCierre(b));
  for(const s of ordenadas){
    const r = perId[s.id]; if(!r || !r._cuenta) continue;
    const f = s.fecha || "sin-fecha";
    contN[f] = (contN[f]||0) + 1;
    r.nro = contN[f];
    if(contN[f] > 6) r.esSpot = true;
  }
  // Overnight TEMPRANO: solo Carga OL agendada antes de 08:30 (entregas/despachos NO aplican)
  const earlyRep = {}; const earlyNoPpu = [];
  for(const s of sols){
    const r = perId[s.id]; if(!r || s.tipo!=="carga_ol") continue;
    const mins = _minHora(s.hora);
    if(mins===null || mins >= 8*60+30) continue;
    const ppu = (s.ppuAsignada||"").trim();
    if(!ppu){ earlyNoPpu.push(s.id); continue; }
    const k = (s.fecha||"x")+"|"+ppu;
    if(!earlyRep[k] || mins < earlyRep[k].mins) earlyRep[k] = {id:s.id, mins};
  }
  for(const k of Object.keys(earlyRep)) perId[earlyRep[k].id].ohEarly = true;
  for(const id of earlyNoPpu) perId[id].ohEarly = true;
  // Overnight TARDE: por (fecha+PPU); candidata ≠DevolNormal con registro de log ≥17:00
  const lateRep = {}; const lateNoPpu = [];
  for(const s of sols){
    const r = perId[s.id]; if(!r || r._devolNormal) continue;
    const t = ultimoLogPost17(s.statusLog);
    if(t===null) continue;
    const ppu = (s.ppuAsignada||"").trim();
    if(!ppu){ lateNoPpu.push(s.id); continue; }
    const k = (s.fecha||"x")+"|"+ppu;
    if(!lateRep[k] || t > lateRep[k].t) lateRep[k] = {id:s.id, t};
  }
  for(const k of Object.keys(lateRep)) perId[lateRep[k].id].ohLate = true;
  for(const id of lateNoPpu) perId[id].ohLate = true;
  // ── Reclasificación puntual por OT (decisión comercial, no altera reglas) ──
  // QX-078: se factura como SPOT en lugar de Overnight. Sólo afecta a esta
  // solicitud; el resto de cobros se mantienen según las reglas vigentes.
  const OVERRIDE_OT_A_SPOT = ["QX-078"];
  for(const s of sols){
    if(OVERRIDE_OT_A_SPOT.includes((s.ot||"").trim())){
      const r = perId[s.id];
      if(r){ r.ohEarly = false; r.ohLate = false; r.esSpot = true; }
    }
  }
  // Prevalece overnight sobre SPOT
  let spotCount = 0, ohCount = 0;
  for(const s of sols){
    const r = perId[s.id]; if(!r) continue;
    if(r.esSpot && (r.ohEarly||r.ohLate)) r.esSpot = false;
    if(r.esSpot) spotCount++;
    if(r.ohEarly) ohCount++;
    if(r.ohLate) ohCount++;
  }
  return { perId, spotCount, ohCount, montoSpot: spotCount*PRECIO_SPOT, montoOH: ohCount*PRECIO_OVERNIGHT };
}

// Métricas ejecutivas de un período (mismas reglas que ResumenMes / Excel)
const COBRO_M1_FIJO = 2840000, COBRO_M2_FIJO = 2840000, DESC_NP_DIA = Math.round(2840000/30);
function metricasPeriodo(sols){
  const arr = sols || [];
  const c = calcularCobros(arr);
  const np = arr.filter(s=>s.noPresentacion).length * DESC_NP_DIA;
  // SPOT Regional — recargo por destinos fuera de la RM (misma tabla usada en el Excel/GraficoCobros)
  let montoSpotRegional=0, nSpotRegional=0;
  arr.forEach(s=>{
    if(s.sinCobro) return;
    const reg=detectarRegion(s.direccion||s.destino||"");
    const v=reg?(reg.valor||0):0;
    if(v>0){ montoSpotRegional+=v; nSpotRegional++; }
  });
  const extras = c.montoSpot + c.montoOH + montoSpotRegional;   // Overnight + Extra SPOT + SPOT Regional
  const facturacion = COBRO_M1_FIJO + COBRO_M2_FIJO + extras - np;
  const completadas = arr.filter(s=>s.status==="completada"||s.status==="devolucion").length;
  const noEnt = arr.filter(s=>s.status==="no_entregado").length;
  const baseEnt = completadas + noEnt;
  const cumplimiento = baseEnt>0 ? (completadas/baseEnt*100) : null;
  return { facturacion, extras, montoSpot:c.montoSpot, montoOH:c.montoOH, montoSpotRegional, nSpotRegional, spotCount:c.spotCount, ohCount:c.ohCount,
    total:arr.length, completadas, noEnt, cumplimiento };
}
function costosEnRango(gastos, di, df){
  if(!di||!df) return 0;
  return (gastos||[]).reduce((s,g)=>{ const f=g.fecha||""; return (f>=di&&f<=df)?s+(Number(g.monto)||0):s; },0);
}



