async function saveSolicitudes(data) {
  // Persiste cada registro mediante el guardado individual (upsert real).
  for (const s of (data||[])) await saveSolicitud(s);
}
async function saveSolicitud(s) {
  try {
    const row = {
      id:s.id, ot:s.ot||null, fecha:s.fecha||null, hora:s.hora||null, tipo:s.tipo||null,
      titulo:s.titulo||null, descripcion:s.descripcion||null, direccion:s.direccion||null,
      contacto:s.contacto||null, guia:s.guia||null, prioridad:s.prioridad||null,
      notas:s.notas||null, solicitante:s.solicitante||null, canal_solicitud:s.canalSolicitud||null,
      usuario_dt:s.usuarioDT||null, ppu_asignada:s.ppuAsignada||null, destino:s.destino||null,
      chofer_asignado:s.choferAsignado||null, documentos:s.documentos||null,
      status:s.status||"pendiente", status_log:s.statusLog||[],
      no_presentacion:s.noPresentacion||false, vehiculo_np:s.vehiculoNP||null,
      motivo_np:s.motivoNP||null, geo_entrega:s.geoEntrega||null,
      hora_entrega:s.horaEntrega||null, hora_llegada:s.horaLlegada||null,
      tiempo_en_punto:s.tiempoEnPunto||null, coords_entrega:s.coordsEntrega||null,
      nombre_receptor:s.nombreReceptor||null, rechazo_firma:s.rechazoFirma||false,
      cancelado_por:s.canceladoPor||null, km_desde_pudahuel:s.kmDesdePudahuel||null,
      devolucion_urgente:s.devolucionUrgente||false,
      observacion_chofer:s.observacionChofer||null,
      observacion_autor:s.observacionAutor||null,
      observacion_fecha:s.observacionFecha||null,
      observacion_cobro:s.observacionCobro||null,
      facturar_en_periodo:s.facturarEnPeriodo||null,
      sin_cobro:!!s.sinCobro,
      updated_at:new Date().toISOString(),
    };
    // Campos pesados (foto/firma/manifiesto): SOLO se incluyen en el guardado si
    // vienen de datos reales (ya cargados desde la BD, o con contenido efectivo
    // capturado en este momento por el chofer). Si vienen vacíos por defecto
    // (_fotosCargadas=false y sin ningún valor real), se omiten del payload para
    // no pisar con null lo que ya existe guardado — esto evita que editar una
    // solicitud antes de que sus fotos terminen de cargar borre foto/firma reales.
    const hayDatosPesadosReales = s._fotosCargadas ||
      !!s.fotoEntrega || !!s.firmaReceptor ||
      (s.fotosEntrega&&s.fotosEntrega.length>0) || (s.fotosManifiesto&&s.fotosManifiesto.length>0);
    if(hayDatosPesadosReales){
      row.foto_entrega = s.fotoEntrega||null;
      row.fotos_entrega = s.fotosEntrega||[];
      row.firma_receptor = s.firmaReceptor||null;
      row.fotos_manifiesto = s.fotosManifiesto||[];
    }
    // UPSERT - insert o update si ya existe
    const doUpsert = async (payload) => fetch(`${SUPABASE_URL}/rest/v1/solicitudes?on_conflict=id`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "apikey": SUPABASE_KEY,
        "Authorization": `Bearer ${SUPABASE_KEY}`,
        "Prefer": "resolution=merge-duplicates,return=minimal",
      },
      body: JSON.stringify(payload),
    });
    let res = await doUpsert(row);
    if(!res.ok) {
      const e = await res.text();
      // Reintento sin columnas opcionales recientes (por si falta la migración en Supabase)
      if(/column|schema|PGRST|fotos_manifiesto|fotos_entrega|observacion_chofer|observacion_autor|observacion_fecha|observacion_cobro|facturar_en_periodo|sin_cobro|devolucion_urgente/i.test(e)) {
        console.warn("saveSolicitud: reintentando sin columnas nuevas. Falta correr la migración SQL en Supabase.", e);
        const fallback = {...row};
        delete fallback.fotos_manifiesto; delete fallback.fotos_entrega; delete fallback.observacion_chofer;
        delete fallback.observacion_autor; delete fallback.observacion_fecha; delete fallback.observacion_cobro; delete fallback.facturar_en_periodo; delete fallback.sin_cobro; delete fallback.devolucion_urgente;
        res = await doUpsert(fallback);
      }
      if(!res.ok) { const e2 = await res.text(); console.error("saveSolicitud error:", e2);
        const otConflict = /duplicate key value violates unique constraint/i.test(e2) && /\bot\b/i.test(e2);
        return { ok:false, error:e2, otConflict };
      }
    }
    return { ok:true };
  } catch(e) { console.error(e); return { ok:false, error:String(e) }; }
}
