function GraficoCobros({ solicitudes }) {
  const P_SPOT=50000, P_OH=85000, M1=2840000, M2=2840000;
  const cobros=calcularCobros(solicitudes);
  const tSpot=cobros.spotCount;
  const tOH=cobros.ohCount;
  // SPOT Regional — recargo por destinos fuera de la RM (misma tabla del Excel)
  let mSpotReg=0, nSpotReg=0;
  solicitudes.forEach(s=>{
    if(s.sinCobro) return;
    const reg=detectarRegion(s.direccion||s.destino||"");
    const v=reg?(reg.valor||0):0;
    if(v>0){mSpotReg+=v;nSpotReg++;}
  });
  const tNP=solicitudes.filter(s=>s.noPresentacion).length*Math.round(2840000/30);
  const mFijo=M1+M2,mSpot=tSpot*P_SPOT,mOH=tOH*P_OH;
  const total=mFijo+mSpot+mOH+mSpotReg-tNP;
  if(total<=0) return null;

  const segmentos=[
    {label:"OC Mensual",valor:mFijo,color:"#1B3FA0"},
    {label:"SPOT Extra",valor:mSpot,color:"#F59E0B"},
    {label:"Overnight",valor:mOH,color:"#38BDF8"},
    ...(mSpotReg>0?[{label:`SPOT Regional (${nSpotReg})`,valor:mSpotReg,color:"#A78BFA"}]:[]),
    ...(tNP>0?[{label:"Descuento NP",valor:tNP,color:"#EF4444",negativo:true}]:[]),
  ];
  const positivos=segmentos.filter(s=>!s.negativo&&s.valor>0);
  const totalPos=positivos.reduce((a,s)=>a+s.valor,0);

  // Generar arcos SVG
  const cx=100,cy=100,R=75,Ri=45;
  let ang=-Math.PI/2;
  const slices=positivos.map(s=>{
    const pct=s.valor/totalPos;
    const end=ang+pct*2*Math.PI;
    const x1=cx+R*Math.cos(ang),y1=cy+R*Math.sin(ang);
    const x2=cx+R*Math.cos(end),y2=cy+R*Math.sin(end);
    const xi1=cx+Ri*Math.cos(end),yi1=cy+Ri*Math.sin(end);
    const xi2=cx+Ri*Math.cos(ang),yi2=cy+Ri*Math.sin(ang);
    const lg=pct>0.5?1:0;
    const d="M"+x1+","+y1+" A"+R+","+R+" 0 "+lg+",1 "+x2+","+y2+" L"+xi1+","+yi1+" A"+Ri+","+Ri+" 0 "+lg+",0 "+xi2+","+yi2+" Z";
    ang=end;
    return {...s,d};
  });

  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.5,textTransform:"uppercase"}}>Composición Total Pre Cierre</div>
      <div style={{display:"flex",alignItems:"center",gap:24,flexWrap:"wrap"}}>
        <svg viewBox="0 0 200 200" style={{width:160,height:160,flexShrink:0}}>
          {slices.map((s,i)=><path key={i} d={s.d} fill={s.color} opacity={0.9}/>)}
          <text x="100" y="96" textAnchor="middle" style={{fontSize:10,fill:C.textSecondary}}>Total</text>
          <text x="100" y="112" textAnchor="middle" style={{fontSize:9,fill:C.textPrimary,fontWeight:"bold"}}>{"$"+Math.round(total/1000)+"K"}</text>
        </svg>
        <div style={{display:"flex",flexDirection:"column",gap:8,flex:1}}>
          {segmentos.map((s,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:8}}>
              <div style={{width:10,height:10,borderRadius:2,background:s.color,flexShrink:0}}/>
              <div style={{flex:1,fontSize:12,color:C.textSecondary}}>{s.label}</div>
              <div style={{fontSize:13,fontWeight:700,color:s.negativo?C.danger:C.textPrimary}}>
                {s.negativo?"-":""}{"$"+s.valor.toLocaleString("es-CL")}
              </div>
            </div>
          ))}
          <div style={{borderTop:"1px solid "+C.border,paddingTop:8,display:"flex",justifyContent:"space-between"}}>
            <span style={{fontSize:12,fontWeight:700,color:C.textPrimary}}>Total Pre Cierre</span>
            <span style={{fontSize:13,fontWeight:900,color:C.cyan}}>{"$"+total.toLocaleString("es-CL")}</span>
          </div>
        </div>
      </div>
    </div>
  );
}


// Tarjeta de cobro con detalle emergente (hover en escritorio / toque en móvil).
// items: [{fecha, hora, tipo, motivo?}]
function TarjetaCobro({label,color,count,monto,items}){
  const [open,setOpen]=useState(false);
  const lista=items||[];
  return(
    <div
      onMouseEnter={()=>setOpen(true)} onMouseLeave={()=>setOpen(false)}
      onClick={()=>setOpen(o=>!o)}
      style={{position:"relative",flex:1,minWidth:140,background:C.navy,borderRadius:10,padding:"12px 14px",border:`1px solid ${color}44`,cursor:lista.length?"pointer":"default"}}>
      <div style={{fontSize:11,color:color,fontWeight:700,marginBottom:4,display:"flex",alignItems:"center",gap:6}}>
        {label}
        {lista.length>0&&<span style={{fontSize:10,color:C.muted,fontWeight:600}}>ⓘ ver detalle</span>}
      </div>
      <div style={{fontSize:11,color:C.muted}}>{count} solicitudes</div>
      <div style={{fontSize:18,fontWeight:900,color:color,marginTop:4}}>${monto.toLocaleString("es-CL")}</div>
      {open&&lista.length>0&&(
        <div style={{position:"absolute",top:"100%",left:0,marginTop:6,zIndex:50,minWidth:260,maxWidth:340,maxHeight:260,overflowY:"auto",background:C.navySurface,border:`1px solid ${color}`,borderRadius:10,padding:"10px 12px",boxShadow:"0 10px 30px rgba(0,0,0,.45)"}}>
          <div style={{fontSize:10,fontWeight:700,color:color,letterSpacing:.5,textTransform:"uppercase",marginBottom:8}}>{label} · {lista.length} solicitud(es)</div>
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {lista.map((it,i)=>(
              <div key={it.id||i} style={{borderTop:i?`1px solid ${C.border}`:"none",paddingTop:i?6:0,display:"flex",flexDirection:"column",gap:1}}>
                <div style={{fontSize:12,color:C.textPrimary,fontWeight:600}}>
                  {it.fecha||"sin fecha"}{it.hora?" · "+it.hora:""}
                </div>
                <div style={{fontSize:11,color:C.textSecondary}}>
                  {(TYPE_META[it.tipo]?.label)||it.tipo||"—"}{it.motivo?" · "+it.motivo:""}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function ResumenMes({solicitudes}){
  const P_SPOT=50000,P_OH=85000,M1=2840000,M2=2840000;
  const cobros=calcularCobros(solicitudes);
  const tSpot=cobros.spotCount;
  const tOH=cobros.ohCount;
  const _ordItems=arr=>arr.sort((a,b)=>(a.fecha||"").localeCompare(b.fecha||"")||(a.hora||"").localeCompare(b.hora||""));
  const itemsSpot=_ordItems(solicitudes.filter(s=>cobros.perId[s.id]?.esSpot)
    .map(s=>({id:s.id,fecha:s.fecha,hora:s.hora,tipo:s.tipo})));
  const itemsOH=_ordItems(solicitudes.filter(s=>{const r=cobros.perId[s.id];return r&&(r.ohEarly||r.ohLate);})
    .map(s=>{const r=cobros.perId[s.id];const motivo=r.ohEarly&&r.ohLate?"Temprano + Tarde":(r.ohEarly?"Temprano (<08:30)":"Tarde (≥17:00)");
      return {id:s.id,fecha:s.fecha,hora:s.hora,tipo:s.tipo,motivo};}));
  const mSpot=tSpot*P_SPOT,mOH=tOH*P_OH,tMov=M1+M2;
  const tNP=solicitudes.filter(s=>s.noPresentacion).length*Math.round(2840000/30);
  const gran=mSpot+mOH+tMov-tNP;
  return(
    <div style={{background:C.navySurface,border:`1px solid ${C.cyan}44`,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.5,textTransform:"uppercase"}}>Resumen de cobros · OC-4000255637</div>
      <div style={{background:C.navy,borderRadius:10,padding:"12px 14px",border:`1px solid ${C.blue}44`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div><div style={{fontSize:11,color:C.textSecondary,fontWeight:700,marginBottom:2}}>OC-4000255637</div>
          <div style={{fontSize:11,color:C.muted}}>Quantrex M1 + M2 · Mensual fijo</div></div>
        <div style={{fontSize:22,fontWeight:900,color:C.textPrimary}}>${tMov.toLocaleString("es-CL")}</div>
      </div>
      {(tSpot>0||tOH>0)&&(
        <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
          {tSpot>0&&<TarjetaCobro label="SPOT Extra" color={C.warning} count={tSpot} monto={mSpot} items={itemsSpot}/>}
          {tOH>0&&<TarjetaCobro label="Overnight" color={C.info} count={tOH} monto={mOH} items={itemsOH}/>}
        </div>
      )}
      {tNP>0&&<div style={{background:C.navy,borderRadius:10,padding:"12px 14px",border:`1px solid ${C.danger}44`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div><div style={{fontSize:11,color:C.danger,fontWeight:700,marginBottom:2}}>No presentación de vehículo</div>
          <div style={{fontSize:11,color:C.muted}}>{solicitudes.filter(s=>s.noPresentacion).length} día(s) · descuento aplicado</div></div>
        <div style={{fontSize:18,fontWeight:900,color:C.danger}}>-${tNP.toLocaleString("es-CL")}</div>
      </div>}
      <div style={{borderTop:`1px solid ${C.border}`,paddingTop:10,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div style={{fontSize:13,fontWeight:700,color:C.textPrimary}}>Gran total a cobrar</div>
        <div style={{fontSize:22,fontWeight:900,color:C.cyan}}>${gran.toLocaleString("es-CL")}</div>
      </div>
    </div>
  );
}

// ── Componentes ejecutivos del dashboard ───────────────────────────────────
function sparkPoints(vals,w,h){
  if(!vals||vals.length<2) return "";
  const min=Math.min(...vals), max=Math.max(...vals); const rng=(max-min)||1;
  return vals.map((v,i)=>{ const x=(i/(vals.length-1))*w; const y=h-((v-min)/rng)*(h-3)-1.5; return `${x.toFixed(1)},${y.toFixed(1)}`; }).join(" ");
}
function KpiEjecutivo({label,valor,delta,deltaColor,sub,subColor,spark,color,onClick}){
  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px",display:"flex",flexDirection:"column",gap:8,cursor:onClick?"pointer":"default"}} onClick={onClick}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:6}}>
        <div style={{fontSize:12,color:C.textSecondary,fontWeight:600}}>{label}</div>
        {onClick&&<span style={{fontSize:10,color:C.muted}}>desglose →</span>}
      </div>
      <div style={{display:"flex",alignItems:"baseline",gap:8,flexWrap:"wrap"}}>
        <span style={{fontSize:23,fontWeight:900,color:C.textPrimary,letterSpacing:-.5}}>{valor}</span>
        {delta!=null&&<span style={{fontSize:12,fontWeight:700,color:deltaColor||(delta>=0?C.success:C.danger)}}>{delta>=0?"▲":"▼"} {Math.abs(Math.round(delta))}%</span>}
      </div>
      {spark&&spark.length>=2&&(
        <svg viewBox="0 0 100 26" preserveAspectRatio="none" style={{width:"100%",height:24}} aria-hidden="true">
          <polyline points={sparkPoints(spark,100,26)} fill="none" stroke={color||C.cyan} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"/>
        </svg>
      )}
      {sub&&<div style={{fontSize:11.5,color:subColor||C.muted,fontWeight:600}}>{sub}</div>}
    </div>
  );
}
function BulletMeta({label,actual,meta,lessIsBetter,record}){
  const pct = meta>0 ? (actual/meta*100) : null;
  let color=C.muted, pctTxt="—";
  if(pct!=null){
    pctTxt=Math.round(pct)+"%";
    if(lessIsBetter){ color = actual<=meta ? C.success : (actual<=meta*1.1? C.warning : C.danger); }
    else { color = pct>=100 ? C.success : (pct>=90? C.cyan : (pct>=75? C.warning : C.danger)); }
  }
  const scaleMax = lessIsBetter ? (Math.max(actual,meta)*1.1||1) : (Math.max(meta*1.2, actual)||1);
  const fillW = Math.min(100,(actual/scaleMax)*100);
  const metaLeft = Math.min(100,(meta/scaleMax)*100);
  return(
    <div style={{display:"grid",gridTemplateColumns:"minmax(120px,150px) 1fr minmax(96px,120px)",gap:10,alignItems:"center"}}>
      <div style={{fontSize:12.5,color:C.textSecondary}}>{label}{record?<span style={{color:C.muted}}> · récord</span>:null}</div>
      <div style={{position:"relative",height:14,background:C.navy,border:"1px solid "+C.border,borderRadius:7}}>
        <div style={{position:"absolute",left:0,top:0,bottom:0,width:fillW+"%",background:color,borderRadius:7}}/>
        {meta>0&&<div style={{position:"absolute",left:metaLeft+"%",top:-3,bottom:-3,width:2,background:C.textPrimary}}/>}
      </div>
      <div style={{textAlign:"right"}}>
        <div style={{fontSize:13,fontWeight:900,color}}>{pctTxt}</div>
        <div style={{fontSize:10,color:C.muted}}>{fmtCLP(actual)} / {fmtCLP(meta)}</div>
      </div>
    </div>
  );
}
function TendenciaPeriodos({serie,metasMap,recordExtras}){
  const [modo,setModo]=useState("facturacion");
  const data=serie.map(p=>({
    nombre:p.nombre,
    valor: modo==="facturacion"?p.facturacion:p.extras,
    meta: modo==="facturacion" ? (metasMap[p.nombre]?.facturacion||0) : recordExtras,
  }));
  const max=Math.max(1,...data.map(d=>Math.max(d.valor,d.meta||0)));
  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:10,flexWrap:"wrap"}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.4,textTransform:"uppercase"}}>Tendencia mes a mes</div>
        <div style={{display:"flex",gap:6}}>
          {[["facturacion","Facturación"],["extras","Extras"]].map(([id,l])=>(
            <button key={id} style={{...S.statusBtn,fontSize:11,padding:"5px 12px",background:modo===id?C.cyan+"33":"transparent",border:"1px solid "+(modo===id?C.cyan:C.border),color:modo===id?C.cyan:C.muted,fontWeight:700}}
              onClick={()=>setModo(id)}>{l}</button>
          ))}
        </div>
      </div>
      {data.length===0?(
        <div style={{fontSize:12.5,color:C.muted}}>Aún no hay períodos para graficar. Cierra un mes y aparecerá la tendencia.</div>
      ):(<>
        <div style={{display:"flex",alignItems:"flex-end",gap:8,height:150}}>
          {data.map((d,i)=>{
            const h=(d.valor/max)*125;
            const metaH=(d.meta||0)/max*125;
            const ok = d.meta>0 ? d.valor>=d.meta : true;
            return(
              <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:4,minWidth:0}}>
                <div style={{fontSize:9.5,color:C.textSecondary,whiteSpace:"nowrap"}}>${Math.round(d.valor/1000000*10)/10}M</div>
                <div style={{position:"relative",width:"100%",height:125,display:"flex",alignItems:"flex-end"}} title={`${d.nombre}: ${fmtCLP(d.valor)}${d.meta>0?" · meta "+fmtCLP(d.meta):""}`}>
                  {d.meta>0&&<div style={{position:"absolute",left:0,right:0,bottom:metaH,borderTop:"2px dashed "+C.muted}}/>}
                  <div style={{width:"100%",height:Math.max(2,h),background:ok?C.cyan:C.danger,borderRadius:"4px 4px 0 0"}}/>
                </div>
                <div style={{fontSize:9.5,color:C.muted,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:"100%"}}>{d.nombre.split(" ")[0].slice(0,3)}</div>
              </div>
            );
          })}
        </div>
        <div style={{display:"flex",gap:16,flexWrap:"wrap",fontSize:11,color:C.textSecondary}}>
          <span style={{display:"inline-flex",alignItems:"center",gap:4}}><span style={{width:10,height:10,borderRadius:2,background:C.cyan}}/>Sobre/igual meta</span>
          <span style={{display:"inline-flex",alignItems:"center",gap:4}}><span style={{width:10,height:10,borderRadius:2,background:C.danger}}/>Bajo meta</span>
          <span style={{display:"inline-flex",alignItems:"center",gap:4}}><span style={{width:14,borderTop:"2px dashed "+C.muted}}/>{modo==="extras"?"Récord":"Meta"}</span>
        </div>
      </>)}
    </div>
  );
}
function MetasEditor({periodo,metasMap,onSaveMeta,recordExtras,recordPeriodo,esRecordActual}){
  const cur=metasMap[periodo]||{};
  const [open,setOpen]=useState(false);
  const [fact,setFact]=useState(cur.facturacion?String(cur.facturacion):"");
  const [tope,setTope]=useState(cur.costos?String(cur.costos):"");
  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"12px 16px",display:"flex",flexDirection:"column",gap:10}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,flexWrap:"wrap"}}>
        <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:1.2,textTransform:"uppercase"}}>🎯 Metas de {periodo}</div>
        <button style={{...S.exportBtn,fontSize:11,padding:"5px 12px"}} onClick={()=>setOpen(o=>!o)}>{open?"Cerrar":"Definir metas"}</button>
      </div>
      <div style={{fontSize:11.5,color:C.textSecondary}}>Meta de extras = tu récord histórico: <b style={{color:C.cyan}}>{fmtCLP(recordExtras)}</b>{recordPeriodo?` (${recordPeriodo})`:""}{esRecordActual?" · este período va liderando":""}</div>
      {open&&(
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))",gap:10,alignItems:"end"}}>
          <div style={S.fGroup}><label style={S.label}>Meta facturación (CLP)</label>
            <input style={S.input} inputMode="numeric" placeholder="Ej: 6500000" value={fact} onChange={e=>setFact(e.target.value.replace(/\D/g,""))}/></div>
          <div style={S.fGroup}><label style={S.label}>Tope costos flota (CLP)</label>
            <input style={S.input} inputMode="numeric" placeholder="Ej: 1200000" value={tope} onChange={e=>setTope(e.target.value.replace(/\D/g,""))}/></div>
          <button style={S.btnPri} onClick={async()=>{
            if(fact!=="")await onSaveMeta(periodo,"facturacion",Number(fact));
            if(tope!=="")await onSaveMeta(periodo,"costos",Number(tope));
            setOpen(false);
          }}>Guardar metas</button>
        </div>
      )}
    </div>
  );
}

// ── Popup de desglose de costos de flota ───────────────────────────────────
function ModalCostosDesglose({gastos,di,df,onClose}){
  const enRango=(gastos||[]).filter(g=>{const f=g.fecha||"";return f>=di&&f<=df;});
  const porCat={};
  enRango.forEach(g=>{ const cat=g.categoria||"otro"; porCat[cat]=(porCat[cat]||0)+(Number(g.monto)||0); });
  const total=Object.values(porCat).reduce((a,b)=>a+b,0);
  const filas=Object.entries(porCat).sort((a,b)=>b[1]-a[1]);
  return(
    <div style={{position:"fixed",inset:0,background:"#000000AA",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={onClose}>
      <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:18,width:"100%",maxWidth:420,boxShadow:"0 12px 40px #000000AA",maxHeight:"80vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
          <div style={{fontWeight:800,color:C.warning,fontSize:14}}>🚚 Desglose de costos de flota</div>
          <button style={{background:"transparent",border:"none",color:C.muted,fontSize:20,cursor:"pointer",lineHeight:1}} onClick={onClose}>✕</button>
        </div>
        {filas.length===0?(
          <div style={{fontSize:12,color:C.muted}}>Sin gastos registrados en este período.</div>
        ):(
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {filas.map(([cat,monto])=>{
              const m=metaCategoria(cat);
              const pct=total>0?Math.round(monto/total*100):0;
              return(
                <div key={cat} style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{fontSize:16,width:22,textAlign:"center"}}>{m.icon}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:12.5,color:C.textPrimary,fontWeight:600}}>{m.label}</div>
                    <div style={{height:5,background:C.navy,borderRadius:3,marginTop:3,overflow:"hidden"}}>
                      <div style={{width:pct+"%",height:"100%",background:m.color}}/>
                    </div>
                  </div>
                  <div style={{textAlign:"right",flexShrink:0}}>
                    <div style={{fontSize:12.5,fontWeight:800,color:C.textPrimary}}>{fmtCLP(monto)}</div>
                    <div style={{fontSize:10,color:C.muted}}>{pct}%</div>
                  </div>
                </div>
              );
            })}
            <div style={{borderTop:"1px solid "+C.border,marginTop:6,paddingTop:8,display:"flex",justifyContent:"space-between",fontSize:13,fontWeight:800}}>
              <span style={{color:C.textSecondary}}>Total</span><span style={{color:C.warning}}>{fmtCLP(total)}</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Evolución de facturación del año (barras = base, línea = extras) ──────
function EvolucionAnual({solicitudes=[]}){
  const anioActual=new Date().getFullYear();
  const mesActual=new Date().getMonth();
  const MESES=["Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic"];
  const data=[];
  for(let m=0;m<=mesActual;m++){
    // Mismo criterio de período de facturación que el resto del dashboard
    // (26 del mes anterior al 25 del mes en curso — ver getPeriodoActual /
    // inicioPeriodo/finPeriodo) y respeta facturarEnPeriodo como override,
    // igual que solicitudesPeriodo. Antes este gráfico usaba mes calendario
    // puro (1→fin de mes) e ignoraba facturarEnPeriodo, lo que producía
    // montos distintos a los de la tarjeta "Extras · Overnight + SPOT".
    const inicioP=new Date(anioActual,m-1,26,12,0,0);
    const finP=new Date(anioActual,m,25,12,0,0);
    const solsMes=solicitudes.filter(s=>fechaEnPeriodo(s.facturarEnPeriodo||s.fecha,inicioP,finP)&&s.status!=="cancelada");
    const mp=metricasPeriodo(solsMes);
    data.push({mes:MESES[m], base:Math.max(0,mp.facturacion-mp.extras), extras:mp.extras, total:mp.facturacion, n:solsMes.length});
  }
  const n=data.length;
  const maxBase=Math.max(1,...data.map(d=>d.base));
  const maxExtras=Math.max(1,...data.map(d=>d.extras));
  const totalAnio=data.reduce((s,d)=>s+d.total,0);
  const HBAR=150;
  const pts=data.map((d,i)=>({ x:((i+0.5)/n)*100, y:HBAR-8-((d.extras/maxExtras)*(HBAR-40)), v:d.extras }));
  const poly=pts.map(p=>`${p.x},${p.y}`).join(" ");
  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:8}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.4,textTransform:"uppercase"}}>Evolución de facturación · {anioActual}</div>
        <div style={{fontSize:10,color:C.muted}}>Acumulado: {fmtCLP(totalAnio)}</div>
      </div>
      <div style={{position:"relative",height:HBAR}}>
        <div style={{position:"absolute",inset:0,display:"flex",alignItems:"flex-end",gap:8}}>
          {data.map((d,i)=>{
            const h=(d.base/maxBase)*(HBAR-24);
            return(
              <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-end",gap:4,minWidth:0,height:"100%"}}>
                <div style={{fontSize:9,color:C.textSecondary,whiteSpace:"nowrap"}}>{d.base>0?`$${Math.round(d.base/1000000*10)/10}M`:""}</div>
                <div style={{width:"100%",height:Math.max(2,h),background:C.blue,borderRadius:"4px 4px 0 0"}} title={`${d.mes}: base ${fmtCLP(d.base)} + extras ${fmtCLP(d.extras)} = ${fmtCLP(d.total)} · ${d.n} solicitudes`}/>
              </div>
            );
          })}
        </div>
        <svg viewBox={`0 0 100 ${HBAR}`} preserveAspectRatio="none" style={{position:"absolute",inset:0,width:"100%",height:"100%",overflow:"visible",pointerEvents:"none"}}>
          <polyline points={poly} fill="none" stroke={C.cyan} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" vectorEffect="non-scaling-stroke"/>
          {pts.map((p,i)=>(
            <circle key={i} cx={p.x} cy={p.y} r="2.6" fill={C.navySurface} stroke={C.cyan} strokeWidth="1.8" vectorEffect="non-scaling-stroke"/>
          ))}
        </svg>
        <div style={{position:"absolute",inset:0,display:"flex",pointerEvents:"none"}}>
          {data.map((d,i)=>{
            const yPx=HBAR-8-((d.extras/maxExtras)*(HBAR-40));
            return (
              <div key={i} style={{flex:1,position:"relative"}}>
                {d.extras>0&&<div style={{position:"absolute",left:"50%",transform:"translateX(-50%)",top:Math.max(0,yPx-16),fontSize:9,fontWeight:700,color:C.cyan,whiteSpace:"nowrap"}}>{fmtCLP(d.extras)}</div>}
              </div>
            );
          })}
        </div>
      </div>
      <div style={{display:"flex",gap:8}}>
        {data.map((d,i)=><div key={i} style={{flex:1,textAlign:"center",fontSize:9.5,color:C.muted}}>{d.mes}</div>)}
      </div>
      <div style={{display:"flex",gap:16,flexWrap:"wrap",fontSize:11,color:C.textSecondary,marginTop:4}}>
        <span style={{display:"inline-flex",alignItems:"center",gap:4}}><span style={{width:10,height:10,borderRadius:2,background:C.blue}}/>Facturación base</span>
        <span style={{display:"inline-flex",alignItems:"center",gap:4}}><span style={{width:10,height:2,background:C.cyan,borderRadius:2}}/>Extras (SPOT + Overnight + Regional)</span>
      </div>
    </div>
  );
}

// ── Cumplimiento del día (gauge circular animado + desglose interactivo) ──
function CumplimientoDelDia({pct,totalHoy,gestionadasHoy,col,desglose=[],hoyStr,setView,setFilterStatus,setFilterFecha}){
  const [animPct,setAnimPct]=useState(0);
  const R=52, STROKE=12, CIRC=2*Math.PI*R;

  useEffect(()=>{
    if(pct===null) return;
    setAnimPct(0);
    const t=setTimeout(()=>setAnimPct(pct),80); // deja pintar el círculo en 0 antes de animar
    return ()=>clearTimeout(t);
  },[pct]);

  const offset=CIRC-(animPct/100)*CIRC;

  // Navega a "Solicitudes" mostrando las filas reales de hoy (opcionalmente
  // acotado a un estado puntual). "en_gestion" = cualquier estado distinto
  // de "pendiente" (mismo criterio que el % de cumplimiento).
  function verSolicitudesHoy(status){
    setFilterFecha?.(hoyStr);
    setFilterStatus?.(status||"en_gestion");
    setView?.("lista");
  }

  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:10}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.2,textTransform:"uppercase"}}>Cumplimiento del día</div>
        {pct!==null&&totalHoy>0&&(
          <button onClick={()=>verSolicitudesHoy()} style={{background:"none",border:"none",color:C.muted,fontSize:11,cursor:"pointer",display:"flex",alignItems:"center",gap:4,padding:0}}>
            Detalle <span style={{display:"inline-block"}}>→</span>
          </button>
        )}
      </div>

      {pct===null?(
        <div style={{fontSize:12,color:C.muted}}>Aún no se registran solicitudes ingresadas hoy.</div>
      ):(
        <div style={{display:"flex",alignItems:"center",gap:18,flexWrap:"wrap"}}>
          <div
            style={{position:"relative",width:120,height:120,cursor:totalHoy>0?"pointer":"default"}}
            onClick={()=>totalHoy>0&&verSolicitudesHoy()}
            title={`${gestionadasHoy} de ${totalHoy} solicitudes gestionadas hoy — toca para verlas`}
          >
            <svg width={120} height={120} viewBox="0 0 120 120" style={{transform:"rotate(-90deg)"}}>
              <circle cx={60} cy={60} r={R} fill="none" stroke={C.navy} strokeWidth={STROKE}/>
              <circle cx={60} cy={60} r={R} fill="none" stroke={col} strokeWidth={STROKE} strokeLinecap="round"
                strokeDasharray={CIRC} strokeDashoffset={offset}
                style={{transition:"stroke-dashoffset 1s cubic-bezier(.4,0,.2,1), stroke .3s"}}/>
            </svg>
            <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
              <div style={{fontSize:26,fontWeight:900,color:col,lineHeight:1}}>{pct}%</div>
              <div style={{fontSize:9,color:C.muted,marginTop:2}}>gestionado</div>
            </div>
          </div>
          <div style={{flex:1,minWidth:140,display:"flex",flexDirection:"column",gap:4}}>
            <div style={{fontSize:12,color:C.textSecondary}}>{totalHoy} solicitud{totalHoy===1?"":"es"} ingresada{totalHoy===1?"":"s"} hoy</div>
          </div>
        </div>
      )}

      {desglose.length>0&&(
        <div style={{display:"flex",flexDirection:"column",gap:4,marginTop:4,borderTop:"1px solid "+C.border,paddingTop:8}}>
          {desglose.map(d=>(
            <div key={d.k} onClick={()=>verSolicitudesHoy(d.k)}
              style={{display:"flex",alignItems:"center",gap:8,fontSize:12,cursor:"pointer",padding:"6px 8px",borderRadius:8,background:"transparent",transition:"background .15s"}}
              onMouseEnter={e=>e.currentTarget.style.background=C.navy}
              onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
              <span style={{width:9,height:9,borderRadius:"50%",background:d.color,flexShrink:0}}/>
              <span style={{flex:1,color:C.textSecondary}}>{d.label}</span>
              <span style={{fontWeight:700,color:d.color}}>{d.n}</span>
              <span style={{color:C.muted,fontSize:11}}>→</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Mapa de trazabilidad del día (GPS real, hoy) ──────────────────────────
// Se muestra bajo "Cumplimiento del día" en el perfil cliente. Mapa
// interactivo (Leaflet + OpenStreetMap): permite zoom, pan y ver detalle de
// cada punto/parada al hacer click. Requiere `npm install leaflet`.
function MapaTrazabilidadHoy(){
  const mapDivRef=useRef(null);
  const mapInstanceRef=useRef(null);
  const [estado,setEstado]=useState("cargando"); // cargando | ok | vacio | error
  const [datosMapa,setDatosMapa]=useState(null); // {grupos, paradas}
  const [kmHoy,setKmHoy]=useState("0.0");
  const [nVehiculos,setNVehiculos]=useState(0);

  function fmtHora(iso){
    if(!iso) return "";
    return new Date(iso).toLocaleTimeString("es-CL",{hour:"2-digit",minute:"2-digit",hour12:false});
  }

  // 1) Carga los puntos GPS de hoy
  useEffect(()=>{
    let cancelado=false;
    (async()=>{
      setEstado("cargando");
      try{
        const hoy=new Date().toISOString().slice(0,10);
        const q=`?order=vehiculo_id.asc,timestamp_captura.asc&timestamp_captura=gte.${hoy}T00:00:00&timestamp_captura=lte.${hoy}T23:59:59`;
        const data=await sbFetch("GET","tracking_puntos","",q);
        if(cancelado) return;
        const puntos=data||[];
        if(!puntos.length){ setEstado("vacio"); return; }
        const map=new Map();
        for(const p of puntos){
          const key=p.vehiculo_id||"_sin_vehiculo";
          if(!map.has(key)) map.set(key,[]);
          map.get(key).push(p);
        }
        const grupos=[...map.values()];
        const paradas=grupos.flatMap(g=>calcularParadas(g));
        let d=0;
        for(const g of grupos){ for(let i=1;i<g.length;i++){ d+=distanciaMetros(g[i-1].lat,g[i-1].lng,g[i].lat,g[i].lng); } }
        setKmHoy((d/1000).toFixed(1));
        setNVehiculos(grupos.length);
        setDatosMapa({grupos,paradas});
        setEstado("ok");
      }catch(e){ if(!cancelado) setEstado("error"); }
    })();
    return ()=>{ cancelado=true; };
  },[]);

  // 2) Cuando hay datos y el <div> del mapa ya está montado, inicializa Leaflet
  useEffect(()=>{
    if(estado!=="ok"||!datosMapa||!mapDivRef.current) return;
    if(mapInstanceRef.current){ mapInstanceRef.current.remove(); mapInstanceRef.current=null; }
    const map=L.map(mapDivRef.current,{zoomControl:true,attributionControl:true,scrollWheelZoom:true});
    mapInstanceRef.current=map;
    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{maxZoom:19,attribution:"© OpenStreetMap"}).addTo(map);

    let cancelado=false;
    const paleta=["#00AEEF","#FF7A00","#22C55E","#E11D48","#A855F7"];
    const bounds=[];
    datosMapa.grupos.forEach((grupo,gi)=>{
      if(grupo.length<2) return;
      const latlngsCrudos=grupo.map(p=>[p.lat,p.lng]);
      bounds.push(...latlngsCrudos);
      const color=paleta[gi%paleta.length];
      let linea=L.polyline(latlngsCrudos,{color,weight:4,opacity:0.85}).addTo(map);
      snapToRoads(grupo).then(snapped=>{
        if(cancelado) return;
        if(snapped&&snapped.length>=2) linea.setLatLngs(snapped);
      });
      const inicio=grupo[0], fin=grupo[grupo.length-1];
      L.circleMarker([inicio.lat,inicio.lng],{radius:7,color:"#fff",weight:2,fillColor:"#22C55E",fillOpacity:1})
        .bindPopup(`<b>Inicio</b><br/>${inicio.vehiculo_id||"Vehículo"}<br/>${fmtHora(inicio.timestamp_captura)}`)
        .addTo(map);
      L.circleMarker([fin.lat,fin.lng],{radius:7,color:"#fff",weight:2,fillColor:"#E11D48",fillOpacity:1})
        .bindPopup(`<b>Última posición</b><br/>${fin.vehiculo_id||"Vehículo"}<br/>${fmtHora(fin.timestamp_captura)}`)
        .addTo(map);
    });
    datosMapa.paradas.slice(0,15).forEach((pa,i)=>{
      L.circleMarker([pa.lat,pa.lng],{radius:6,color:"#fff",weight:2,fillColor:"#F59E0B",fillOpacity:1})
        .bindPopup(`<b>Parada ${i+1}</b><br/>${pa.duracionMin} min detenido<br/>${fmtHora(pa.inicio)} – ${fmtHora(pa.fin)}`)
        .addTo(map);
      bounds.push([pa.lat,pa.lng]);
    });
    if(bounds.length) map.fitBounds(bounds,{padding:[24,24]});
    else map.setView([-33.45,-70.67],11);

    return ()=>{ cancelado=true; if(mapInstanceRef.current){ mapInstanceRef.current.remove(); mapInstanceRef.current=null; } };
  },[estado,datosMapa]);

  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:10}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.2,textTransform:"uppercase"}}>Trazabilidad de hoy</div>
        {estado==="ok"&&<div style={{fontSize:10,color:C.muted}}>{kmHoy} km · {nVehiculos} vehículo{nVehiculos===1?"":"s"} · toca un punto para ver el detalle</div>}
      </div>
      {estado==="cargando"&&<div style={{fontSize:12,color:C.muted}}>Cargando recorrido del día...</div>}
      {estado==="vacio"&&<div style={{fontSize:12,color:C.muted}}>Aún no hay puntos GPS registrados hoy.</div>}
      {estado==="error"&&<div style={{fontSize:12,color:C.danger}}>No se pudo cargar la trazabilidad de hoy.</div>}
      {estado==="ok"&&<div ref={mapDivRef} style={{width:"100%",height:340,borderRadius:10,overflow:"hidden",border:"1px solid "+C.border}}/>}
    </div>
  );
}
// año de puntos GPS es demasiado dato para traer automáticamente en cada carga
// del Dashboard. Se pagina la consulta y se limita a un máximo de puntos para
// que la página no se cuelgue con historiales muy grandes.
async function fetchTrackingAnio(anio){
  const desde=`${anio}-01-01T00:00:00`;
  const hasta=new Date().toISOString();
  let all=[]; let offset=0; const PAGE=1000; const MAX_PAGES=40;
  for(let page=0; page<MAX_PAGES; page++){
    const url=`${SUPABASE_URL}/rest/v1/tracking_puntos?select=lat,lng,timestamp_captura,vehiculo_id&timestamp_captura=gte.${desde}&timestamp_captura=lte.${hasta}&order=vehiculo_id.asc,timestamp_captura.asc&limit=${PAGE}&offset=${offset}`;
    let res;
    try{
      res=await fetch(url,{ headers:{ apikey:SUPABASE_KEY, Authorization:`Bearer ${SUPABASE_KEY}` } });
    }catch{ break; }
    if(!res.ok) break;
    const data=await res.json();
    all=all.concat(data);
    if(!data.length || data.length<PAGE) break;
    offset+=PAGE;
  }
  return {puntos:all, truncado: all.length>=PAGE*MAX_PAGES};
}
function ResumenKmAnual(){
  const anioActual=new Date().getFullYear();
  const MESES=["Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic"];
  const FACTOR_CO2=0.25; // kg CO2/km, furgón diésel liviano (estimado)
  const [data,setData]=useState(null); // {porMes, record, totalKm, truncado}
  const [calculando,setCalculando]=useState(false);

  async function calcular(){
    setCalculando(true);
    const {puntos,truncado}=await fetchTrackingAnio(anioActual);
    const porDia={};
    let prev=null;
    for(const p of puntos){
      if(prev && prev.vehiculo_id===p.vehiculo_id && p.lat!=null && p.lng!=null && prev.lat!=null){
        const dia=(p.timestamp_captura||"").slice(0,10);
        const d=distanciaMetros(prev.lat,prev.lng,p.lat,p.lng)/1000;
        if(d<50) porDia[dia]=(porDia[dia]||0)+d; // ignora saltos GPS absurdos entre puntos
      }
      prev=p;
    }
    const diasArr=Object.entries(porDia);
    const porMes=Array(12).fill(0);
    diasArr.forEach(([fecha,km])=>{ const mIdx=parseInt(fecha.slice(5,7),10)-1; if(mIdx>=0&&mIdx<12) porMes[mIdx]+=km; });
    let record=null;
    diasArr.forEach(([fecha,km])=>{ if(!record||km>record.km) record={fecha,km}; });
    const totalKm=diasArr.reduce((s,[,km])=>s+km,0);
    setData({porMes, record, totalKm, truncado, nPuntos:puntos.length});
    setCalculando(false);
  }

  if(!data){
    return(
      <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:10}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.4,textTransform:"uppercase"}}>Kilómetros recorridos · {anioActual}</div>
        <div style={{fontSize:12,color:C.muted}}>Calcula el recorrido del año a partir del GPS de la flota (trazabilidad). Puede tardar unos segundos.</div>
        <button style={{...S.exportBtn,alignSelf:"flex-start"}} disabled={calculando} onClick={calcular}>{calculando?"Calculando...":"📊 Calcular año"}</button>
      </div>
    );
  }

  const mesActual=new Date().getMonth();
  const serie=data.porMes.slice(0,mesActual+1).map((km,i)=>({mes:MESES[i],km}));
  const max=Math.max(1,...serie.map(d=>d.km));

  if(data.totalKm===0){
    return(
      <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.4,textTransform:"uppercase"}}>Kilómetros recorridos · {anioActual}</div>
        <div style={{fontSize:12,color:C.muted}}>No se encontraron puntos GPS con recorrido este año ({data.nPuntos} punto(s) revisado(s)). Verifica que la app esté capturando trazabilidad en los vehículos.</div>
        <button style={{...S.linkBtn}} onClick={()=>setData(null)}>← Recalcular</button>
      </div>
    );
  }

  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.4,textTransform:"uppercase"}}>Kilómetros recorridos · {anioActual}</div>
        <div style={{fontSize:10,color:C.muted}}>{Math.round(data.totalKm)} km · {(data.totalKm*FACTOR_CO2).toFixed(0)} kg CO₂ est.</div>
      </div>
      {data.record&&(
        <div style={{background:C.cyan+"18",border:"1px solid "+C.cyan+"44",borderRadius:10,padding:"8px 12px",fontSize:12,color:C.cyan,fontWeight:700}}>
          🏆 Récord del día: {data.record.km.toFixed(1)} km el {new Date(data.record.fecha+"T00:00:00").toLocaleDateString("es-CL",{day:"numeric",month:"long"})} · {(data.record.km*FACTOR_CO2).toFixed(1)} kg CO₂
        </div>
      )}
      <div style={{display:"flex",alignItems:"flex-end",gap:8,height:120}}>
        {serie.map((d,i)=>{
          const h=(d.km/max)*95;
          return(
            <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:4,minWidth:0}}>
              <div style={{fontSize:9,color:C.textSecondary}}>{d.km>0?Math.round(d.km):""}</div>
              <div style={{width:"100%",height:Math.max(2,h),background:C.warning,borderRadius:"4px 4px 0 0"}} title={`${d.mes}: ${d.km.toFixed(1)} km · ${(d.km*FACTOR_CO2).toFixed(0)} kg CO₂`}/>
              <div style={{fontSize:9.5,color:C.muted}}>{d.mes}</div>
            </div>
          );
        })}
      </div>
      <div style={{fontSize:10.5,color:C.muted,fontStyle:"italic"}}>
        Basado en {data.nPuntos.toLocaleString("es-CL")} puntos GPS reales{data.truncado?" (muestra parcial — historial muy extenso, se limitó la consulta)":""} · CO₂ ≈ km × 0,25 kg/km (estimado)
      </div>
      <button style={{...S.linkBtn,alignSelf:"flex-start"}} onClick={()=>setData(null)}>← Recalcular</button>
    </div>
  );
}

// ── Dashboard ──────────────────────────────────────────────────────────────
// ── Buscador de documentos (DT + Drive) ─────────────────────────────────────
// Descubre recursivamente todas las subcarpetas dentro de una carpeta de Drive
// (BFS). Se limita a un máximo de carpetas para no disparar demasiadas
// llamadas si la estructura es muy profunda o muy ancha. Si una carpeta puntual
// da error (ej. permisos rotos), se salta y se sigue con el resto — no aborta
// todo el descubrimiento.
async function obtenerSubcarpetasDrive(folderIdRaiz, apiKey, maxCarpetas=60){
  const todas=[folderIdRaiz];
  const porRevisar=[folderIdRaiz];
  while(porRevisar.length>0 && todas.length<maxCarpetas){
    const actual=porRevisar.shift();
    const query=`'${actual}' in parents and mimeType='application/vnd.google-apps.folder' and trashed=false`;
    const url=`https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(query)}&fields=${encodeURIComponent("files(id,name)")}&pageSize=100&key=${apiKey}`;
    try{
      const res=await fetch(url);
      const data=await res.json();
      if(data.error) continue; // esta carpeta no se pudo listar (permisos) — se salta, no se aborta todo
      for(const f of (data.files||[])){
        if(f?.id && !todas.includes(f.id)){
          todas.push(f.id);
          porRevisar.push(f.id);
          if(todas.length>=maxCarpetas) break;
        }
      }
    }catch{ /* red: se salta esta carpeta y se sigue con las demás */ }
  }
  return todas;
}

// Busca el término en cada carpeta POR SEPARADO (en paralelo) en vez de una
// sola consulta combinada — así, si alguna carpeta tiene permisos rotos, esa
// consulta individual falla pero el resto de las carpetas igual entregan
// resultado, en vez de tirar abajo toda la búsqueda.
async function buscarEnCarpetasDrive(carpetas, apiKey, terms){
  const vistos=new Set();
  const resultados=[];
  let carpetasConError=0;
  const nameClause = terms.map(t=>`name contains '${t}'`).join(" or ");
  await Promise.all(carpetas.map(async folderId=>{
    const query=`'${folderId}' in parents and (${nameClause}) and trashed = false`;
    const url=`https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(query)}&fields=${encodeURIComponent("files(id,name,webViewLink)")}&pageSize=50&key=${apiKey}`;
    try{
      const res=await fetch(url);
      const data=await res.json();
      if(data.error){ carpetasConError++; return; }
      for(const f of (data.files||[])){
        if(!vistos.has(f.id)){ vistos.add(f.id); resultados.push(f); }
      }
    }catch{ carpetasConError++; }
  }));
  return {resultados, carpetasConError};
}

function BuscadorDocumento(){
  const MAX_DOCS=5;
  const [q,setQ]=useState("");
  const [buscado,setBuscado]=useState(false);
  const [drive,setDrive]=useState(null); // {loading}|{archivos}|{error}
  const [numerosBuscados,setNumerosBuscados]=useState([]);
  const [limiteExcedido,setLimiteExcedido]=useState(false);
  const [ultimoCopiado,setUltimoCopiado]=useState("");
  const [showDT,setShowDT]=useState(false);
  const carpetasCache=useRef(null); // cache de IDs de subcarpetas ya descubiertas en esta sesión

  const dtConfigurado = DT_WIDGET_URL && !DT_WIDGET_URL.startsWith("TU_");
  const driveConfigurado = GOOGLE_DRIVE_API_KEY && !GOOGLE_DRIVE_API_KEY.startsWith("TU_") && GOOGLE_DRIVE_FOLDER_ID && !GOOGLE_DRIVE_FOLDER_ID.startsWith("TU_");

  const buscarDrive=async(terminos)=>{
    if(!driveConfigurado){ setDrive({error:"config"}); return; }
    setDrive({loading:true});
    try{
      if(!carpetasCache.current){
        carpetasCache.current = await obtenerSubcarpetasDrive(GOOGLE_DRIVE_FOLDER_ID, GOOGLE_DRIVE_API_KEY);
      }
      const carpetas=carpetasCache.current;
      const {resultados,carpetasConError} = await buscarEnCarpetasDrive(carpetas, GOOGLE_DRIVE_API_KEY, terminos);
      setDrive({archivos:resultados, carpetasConError});
    }catch{
      setDrive({error:"red"});
    }
  };

  const buscar=()=>{
    const numeros=Array.from(new Set(q.split(/[,;\n]+/).map(s=>s.trim()).filter(Boolean)));
    if(numeros.length===0) return;
    if(numeros.length>MAX_DOCS){ setLimiteExcedido(true); return; }
    setLimiteExcedido(false);
    setNumerosBuscados(numeros);
    setBuscado(true);
    setDrive(null);
    buscarDrive(numeros.map(n=>n.replace(/'/g,"\\'")));
  };

  const copiarNumero=async(n)=>{
    try{ await navigator.clipboard.writeText(n); setUltimoCopiado(n); setTimeout(()=>setUltimoCopiado(""),2500); }catch{}
  };

  const resultCard = (contenido)=>(
    <div style={{...S.detailBlock,display:"flex",flexDirection:"column",gap:8,flex:1,minWidth:180}}>{contenido}</div>
  );

  return (
    <div style={{...S.detailBlock,display:"flex",flexDirection:"column",gap:10}}>
      <div>
        <div style={{fontWeight:800,color:C.cyan,fontSize:14}}>🔍 Buscar documento</div>
        <div style={{fontSize:12,color:C.textSecondary,marginTop:2}}>Ingresa N° de despacho o documento para ubicarlo en DispatchTrack o el PDF escaneado. Puedes buscar hasta {MAX_DOCS} a la vez, separados por coma.</div>
      </div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
        <input style={{...S.input,flex:1,minWidth:180}} placeholder="Ej: 432263, 424948, 1037054..." value={q}
          onChange={e=>setQ(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")buscar();}}/>
        <button style={S.btnPri} onClick={buscar}>Buscar</button>
      </div>
      {limiteExcedido&&<div style={{fontSize:12,color:C.warning}}>⚠ Máximo {MAX_DOCS} documentos por búsqueda — quita algunos e inténtalo de nuevo.</div>}
      {buscado&&(
        <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
          {resultCard(<>
            <div style={{fontWeight:700,color:C.textPrimary,fontSize:13}}>🚚 DispatchTrack</div>
            {dtConfigurado?(<>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                {numerosBuscados.map(n=>(
                  <button key={n} style={{...S.exportBtn,textAlign:"left",display:"flex",justifyContent:"space-between",gap:8}}
                    onClick={async()=>{await copiarNumero(n);setShowDT(true);}}>
                    <span>{n}</span><span>{ultimoCopiado===n?"✓ copiado":"Copiar →"}</span>
                  </button>
                ))}
              </div>
              <div style={{fontSize:11,color:C.muted}}>Copia cada número y pégalo (Ctrl+V) en el campo "Ingrese su número de despacho" del widget.</div>
            </>):(
              <div style={{fontSize:12,color:C.warning}}>Falta configurar DT_WIDGET_URL con la URL del widget de tu cuenta DispatchTrack.</div>
            )}
          </>)}
          {resultCard(<>
            <div style={{fontWeight:700,color:C.textPrimary,fontSize:13}}>📄 Documento escaneado</div>
            {!driveConfigurado?(
              <div style={{fontSize:12,color:C.warning}}>Falta configurar GOOGLE_DRIVE_FOLDER_ID / GOOGLE_DRIVE_API_KEY.</div>
            ):drive?.loading?(
              <div style={{fontSize:12,color:C.muted}}>Buscando en Drive...</div>
            ):drive?.error==="api"?(
              <div style={{fontSize:12,color:C.danger}}>Error de la API de Drive{drive?.detalle?`: ${drive.detalle}`:" (revisa la clave o los permisos de la carpeta)."}</div>
            ):drive?.error==="red"?(
              <div style={{fontSize:12,color:C.danger}}>Error de conexión con Drive.</div>
            ):drive?.archivos?(<>
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {numerosBuscados.map(n=>{
                  const matches=drive.archivos.filter(f=>f.name.includes(n));
                  return (
                    <div key={n}>
                      <div style={{fontSize:11,color:C.muted,fontWeight:700}}>{n}</div>
                      {matches.length===0
                        ?<div style={{fontSize:12,color:C.muted,paddingLeft:6}}>— no encontrado</div>
                        :matches.map(f=>(
                          <a key={f.id} href={f.webViewLink} target="_blank" rel="noreferrer" style={{display:"block",fontSize:12,color:C.cyan,textDecoration:"none",fontWeight:600,paddingLeft:6}}>📄 {f.name} →</a>
                        ))}
                    </div>
                  );
                })}
              </div>
              {drive.carpetasConError>0&&<div style={{fontSize:11,color:C.warning,marginTop:2}}>⚠ {drive.carpetasConError} carpeta(s) no se pudieron revisar por permisos — si algún documento no aparece, puede estar ahí. Revisa que estén compartidas como "Cualquiera con el enlace".</div>}
            </>):null}
          </>)}
        </div>
      )}
      {showDT&&(
        <div style={{position:"fixed",inset:0,background:"#000000AA",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={()=>setShowDT(false)}>
          <div style={{background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:14,padding:16,width:"100%",maxWidth:460,boxShadow:"0 12px 40px #000000AA"}} onClick={e=>e.stopPropagation()}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
              <div style={{fontWeight:800,color:C.cyan,fontSize:13}}>🚚 Seguimiento DispatchTrack</div>
              <button style={{background:"transparent",border:"none",color:C.muted,fontSize:20,cursor:"pointer",lineHeight:1}} onClick={()=>setShowDT(false)}>✕</button>
            </div>
            <div style={{fontSize:12,color:C.textSecondary,marginBottom:8}}>{ultimoCopiado?<>N° copiado al portapapeles: <b style={{color:C.textPrimary}}>{ultimoCopiado}</b> — pégalo (Ctrl+V) en el campo de abajo.</>:"Copia un número de la lista y pégalo en el campo de abajo."}</div>
            <iframe
              name="beetrack-widget"
              id="beetrack-widget"
              frameBorder="0"
              width="100%"
              height="310px"
              src={DT_WIDGET_URL}
              title="Widget DispatchTrack"
            />
          </div>
        </div>
      )}
    </div>
  );
}

function Dashboard({stats,solicitudes,solicitudesPeriodo,nombrePeriodo,inicio,fin,yaCerrado,setView,setSelectedId,setFilterStatus,setFilterFecha,confirmCierre,setConfirmCierre,onCerrarMes,abrirPeriodo,setAbrirPeriodo,nuevaFechaInicio,setNuevaFechaInicio,onAbrirPeriodo,sesion,rutas=[],onExport,gastos=[],vehiculos=[],recordatorios=[],onSaveRecordatorio,onDeleteRecordatorio,cierres=[],metas=[],onSaveMeta}){
  const esAdmin=sesion?.perfil==="admin";
  const esCliente=sesion?.perfil==="cliente";
  const fmt=d=>d.toLocaleDateString("es-CL",{day:"numeric",month:"long"});
  const [showCostosDesglose,setShowCostosDesglose]=useState(false);
  const [showMetasTendencia,setShowMetasTendencia]=useState(false);

  // ── Cálculo ejecutivo: serie de períodos (cierres + período actual) ──
  const metasMap={};
  (metas||[]).forEach(m=>{ (metasMap[m.periodo]=metasMap[m.periodo]||{})[m.kpi]=m.valor; });
  const diAct=inicio?inicio.toISOString().slice(0,10):null;
  const dfAct=fin?fin.toISOString().slice(0,10):null;
  const mpActual=metricasPeriodo(solicitudesPeriodo);
  const costosActual=costosEnRango(gastos,diAct,dfAct);
  const serie=[];
  (cierres||[]).forEach(c=>{
    if(c.nombre===nombrePeriodo) return; // evita duplicar el período activo
    const mp=metricasPeriodo(c.solicitudes||[]);
    serie.push({nombre:c.nombre, facturacion:mp.facturacion, extras:mp.extras,
      costos:costosEnRango(gastos,c.fechaInicio,c.fechaFin), _orden:c.fechaFin||c.fechaInicio||"", actual:false});
  });
  serie.push({nombre:nombrePeriodo, facturacion:mpActual.facturacion, extras:mpActual.extras, costos:costosActual, _orden:dfAct||"zzzz", actual:true});
  serie.sort((a,b)=>(a._orden||"").localeCompare(b._orden||""));
  const serieView=serie.slice(-8);
  const idxCur=serie.length-1;
  const prevP=serie[idxCur-1];
  const mom=(field)=>{ if(!prevP||!prevP[field]) return null; return ((serie[idxCur][field]-prevP[field])/Math.abs(prevP[field]))*100; };
  const pasados=serie.filter(p=>!p.actual);
  const recExtrasObj = pasados.length ? pasados.reduce((a,b)=>b.extras>a.extras?b:a) : null;
  const recordExtras = recExtrasObj ? recExtrasObj.extras : mpActual.extras;
  const recordPeriodo = recExtrasObj ? recExtrasObj.nombre : nombrePeriodo;
  const esRecordActual = mpActual.extras>=recordExtras;
  const metaFact = metasMap[nombrePeriodo]?.facturacion||0;
  const topeCostos = metasMap[nombrePeriodo]?.costos||0;

  return(
    <div style={S.section}>
      <div style={{position:"relative",border:"1.5px solid "+(yaCerrado?C.border:"#C9A227"),borderRadius:14,overflow:"hidden",background:C.navySurface,boxShadow:yaCerrado?"none":"0 0 18px -6px #C9A22755"}}>
        <div style={{display:"flex",alignItems:"stretch"}}>
          {!yaCerrado&&(
            <div style={{position:"relative",width:76,flexShrink:0,background:"linear-gradient(160deg,#F1D488 0%,#D9B44A 45%,#A97F1E 100%)",clipPath:"polygon(0 0,100% 0,68% 100%,0 100%)",display:"flex",alignItems:"center",justifyContent:"center"}}>
              <span style={{fontSize:24,color:"#1B1E4A",transform:"translateX(-6px)"}}>⚠</span>
            </div>
          )}
          <div style={{flex:1,padding:"14px 20px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:16,flexWrap:"wrap"}}>
            <div style={{flex:1}}>
              <div style={{fontSize:11,fontWeight:800,color:yaCerrado?C.muted:"#D9B44A",letterSpacing:1.8,textTransform:"uppercase",marginBottom:4}}>{yaCerrado?"✓ Período cerrado":"Período activo"}</div>
              <div style={{fontWeight:800,fontSize:17,color:C.textPrimary}}>{nombrePeriodo}</div>
              <div style={{fontSize:12,color:C.textSecondary,marginTop:2}}>{fmt(inicio)} → {fmt(fin)} · {solicitudesPeriodo.length} solicitudes</div>
            </div>
            {esAdmin&&(yaCerrado
              ?<div style={{...S.badge,background:C.success+"22",color:C.success}}>Cerrado</div>
              :!confirmCierre
                ?<button style={S.btnCierre} onClick={()=>setConfirmCierre(true)}>Cerrar Mes</button>
                :<div style={{display:"flex",flexDirection:"column",gap:8,alignItems:"flex-end"}}>
                  <div style={{fontSize:12,color:C.warning,fontWeight:600}}>¿Exportar y cerrar {nombrePeriodo}?</div>
                  <div style={{display:"flex",gap:8}}>
                    <button style={{...S.statusBtn,border:`1px solid ${C.muted}`,color:C.muted,fontSize:12}} onClick={()=>setConfirmCierre(false)}>Cancelar</button>
                    <button style={{...S.statusBtn,background:C.cyan,color:"#fff",border:"none",fontSize:12}} onClick={onCerrarMes}>Confirmar</button>
                  </div>
                </div>
            )}
          </div>
        </div>
      </div>

      {esCliente&&<div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"14px 18px",display:"flex",gap:16,flexWrap:"wrap",alignItems:"center"}}>
        <div style={{fontSize:12,color:C.textSecondary}}>📦 <strong style={{color:C.textPrimary}}>{solicitudesPeriodo.length}</strong> solicitudes en el período actual</div>
        <div style={{width:1,height:18,background:C.border}}/>
        {Object.entries(STATUS_META).map(([k,meta])=>{
          const n=solicitudesPeriodo.filter(s=>s.status===k).length;
          if(n===0)return null;
          return <div key={k} style={{fontSize:12,color:C.textSecondary}}><strong style={{color:meta.color}}>{n}</strong> {meta.label}</div>;
        })}
      </div>}

      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={S.pageTitle}>Dashboard</div>
        {solicitudes.length>0&&!esCliente&&<button title="Exporta solo las solicitudes del período activo" style={{...S.exportBtn,display:"flex",alignItems:"center",gap:6}} onClick={onExport}><span>📥</span><span>Reporte del período</span></button>}
      </div>
      <BuscadorDocumento/>
      {abrirPeriodo && (
        <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:12}}>
          <div style={{fontSize:13,fontWeight:800,color:C.cyan}}>Abrir nuevo período de facturación</div>
          <div style={{fontSize:12,color:C.textSecondary}}>Define la fecha de inicio del nuevo período. El fin se calculará automáticamente en 30 días.</div>
          <div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
            <div style={{display:"flex",flexDirection:"column",gap:4,flex:1}}>
              <label style={S.label}>Fecha de inicio</label>
              <input style={S.input} type="date" value={nuevaFechaInicio} onChange={e=>setNuevaFechaInicio(e.target.value)}/>
            </div>
            <div style={{display:"flex",gap:8,alignSelf:"flex-end"}}>
              <button style={{...S.btnSec,fontSize:13}} onClick={()=>setAbrirPeriodo(false)}>Cancelar</button>
              <button style={S.btnCierre} onClick={onAbrirPeriodo}>Abrir período</button>
            </div>
          </div>
        </div>
      )}

      {esAdmin&&showCostosDesglose&&<ModalCostosDesglose gastos={gastos} di={diAct} df={dfAct} onClose={()=>setShowCostosDesglose(false)}/>}

      <div style={S.sectionTitle}>Operación · {nombrePeriodo}</div>
      {(()=>{
        // Cumplimiento del día: promedio ponderado del avance por etapa de
        // cada solicitud ingresada hoy (pendiente=25%, en tránsito=50%,
        // cualquier estado final=100%). Se muestra para todos los perfiles.
        const hoyStr=new Date().toISOString().slice(0,10);
        const solHoy=(solicitudes||[]).filter(s=>s.fecha===hoyStr);
        const totalHoy=solHoy.length;
        const gestionadasHoy=solHoy.filter(s=>s.status!=="pendiente").length;
        const pct=totalHoy>0?Math.round(solHoy.reduce((a,s)=>a+(AVANCE_STATUS[s.status]??0),0)/totalHoy*100):null;
        const col=pct===null?C.muted:pct>=100?C.success:pct>=50?C.warning:C.danger;
        const desglose=[
          {k:"pendiente",label:"Pendientes",color:C.warning},
          {k:"en_proceso",label:"En tránsito",color:C.info},
          {k:"completada",label:"Completadas",color:C.success},
          {k:"devolucion",label:"Devoluciones",color:C.success},
          {k:"no_entregado",label:"No entregado",color:"#F97316"},
          {k:"cancelada",label:"Canceladas",color:C.danger},
        ].map(x=>({...x,n:solHoy.filter(s=>s.status===x.k).length})).filter(x=>x.n>0);
        return <CumplimientoDelDia pct={pct} totalHoy={totalHoy} gestionadasHoy={gestionadasHoy} col={col} desglose={desglose} hoyStr={hoyStr} setView={setView} setFilterStatus={setFilterStatus} setFilterFecha={setFilterFecha}/>;
      })()}
      {!esCliente&&(
      <div style={S.statsGrid}>
        {[["Total",stats.total,C.cyan],["Pendientes",stats.pendiente,C.warning],["En Tránsito",stats.en_proceso,C.info],["Completadas",stats.completada+stats.devolucion,C.success],
          ...(stats.no_entregado>0?[["No Entregado",stats.no_entregado,"#F97316"]]:[]),
          ...(stats.cancelada>0?[["Canceladas",stats.cancelada,C.danger]]:[])].map(([l,v,col])=>(
          <div key={l} style={{...S.statCard,borderTop:`3px solid ${col}`}}>
            <div style={{...S.statNum,color:col}}>{v}</div>
            <div style={S.statLabel}>{l}</div>
          </div>
        ))}
      </div>
      )}
      {esCliente&&<MapaTrazabilidadHoy/>}
      {(()=>{
        const sinObs=solicitudesPeriodo.filter(s=>s.status==="no_entregado"&&!(s.observacionChofer||"").trim()).length;
        if(sinObs<1) return null;
        return(
        <div style={{background:"#F9731611",border:"1px solid #F97316",borderRadius:12,padding:"14px 18px",display:"flex",flexDirection:"column",gap:10}}>
          <div style={{fontSize:11,fontWeight:700,color:"#F97316",letterSpacing:1.5,textTransform:"uppercase"}}>⚠ No Entregados — Requieren atención</div>
          <div style={{display:"flex",alignItems:"center",gap:16}}>
            <div style={{fontSize:36,fontWeight:900,color:"#F97316"}}>{sinObs}</div>
            <div style={{fontSize:13,color:C.textSecondary}}>solicitud(es) marcadas como No Entregado sin observación registrada en el período activo</div>
          </div>
          <div style={{fontSize:12.5,color:"#F97316",fontWeight:600}}>📝 Abre la solicitud y agrega el motivo de la no entrega (queda registrado quién y cuándo).</div>
          <button style={{...S.exportBtn,fontSize:12,borderColor:"#F97316",color:"#F97316",alignSelf:"flex-start"}}
            onClick={()=>setView("lista")}>
            Ver solicitudes →
          </button>
        </div>
        );
      })()}

      {esAdmin&&(<>
        <div style={S.sectionTitle}>Resumen ejecutivo · {nombrePeriodo}</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(190px,1fr))",gap:12}}>
          <KpiEjecutivo label="Facturación del período" valor={fmtCLP(mpActual.facturacion)}
            delta={mom("facturacion")} spark={serieView.map(p=>p.facturacion)} color={C.cyan}
            sub={metaFact>0?`${Math.round(mpActual.facturacion/metaFact*100)}% de la meta`:"sin meta definida"}
            subColor={metaFact>0?(mpActual.facturacion>=metaFact?C.success:C.warning):C.muted}/>
          <KpiEjecutivo label="Costos de flota" valor={fmtCLP(costosActual)} onClick={()=>setShowCostosDesglose(true)}
            delta={mom("costos")} deltaColor={mom("costos")==null?undefined:(mom("costos")>0?C.danger:C.success)}
            spark={serieView.map(p=>p.costos)} color={C.warning}
            sub={topeCostos>0?`${costosActual<=topeCostos?"bajo el tope":"sobre el tope"} (${Math.round(costosActual/topeCostos*100)}%)`:"sin tope definido"}
            subColor={topeCostos>0?(costosActual<=topeCostos?C.success:C.danger):C.muted}/>
          <KpiEjecutivo label="Extras · Overnight + SPOT" valor={fmtCLP(mpActual.extras)}
            delta={mom("extras")} spark={serieView.map(p=>p.extras)} color={C.info}
            sub={esRecordActual?"🏆 nuevo récord":`récord: ${fmtCLP(recordExtras)} · ${Math.round((recordExtras?mpActual.extras/recordExtras:1)*100)}%`}
            subColor={esRecordActual?C.success:C.muted}/>
        </div>

        <EvolucionAnual solicitudes={solicitudes}/>

        <div style={S.sectionTitle}>Costos y flota</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(190px,1fr))",gap:12}}>
          <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"14px 16px",display:"flex",flexDirection:"column",gap:6,cursor:"pointer"}} onClick={()=>setShowCostosDesglose(true)}>
            <div style={{fontSize:11,fontWeight:700,color:C.warning,letterSpacing:1.2,textTransform:"uppercase"}}>Costos de flota <span style={{color:C.muted,fontWeight:600}}>· ver desglose</span></div>
            <div style={{fontSize:22,fontWeight:900,color:C.warning}}>{fmtCLP(costosActual)}</div>
            <div style={{fontSize:10,color:C.muted}}>{nombrePeriodo}</div>
          </div>
          <ResumenKmDia solicitudes={solicitudes} rutas={rutas} compact/>
          <ResumenCO2 solicitudes={solicitudesPeriodo} rutas={rutas} compact/>
        </div>
        <ResumenKmAnual/>

        <button style={{...S.linkBtn,alignSelf:"flex-start"}} onClick={()=>setShowMetasTendencia(v=>!v)}>
          {showMetasTendencia?"Ocultar metas y tendencia histórica ▲":"Ver metas y tendencia histórica ▼"}
        </button>
        {showMetasTendencia&&(<>
          <MetasEditor periodo={nombrePeriodo} metasMap={metasMap} onSaveMeta={onSaveMeta}
            recordExtras={recordExtras} recordPeriodo={recordPeriodo} esRecordActual={esRecordActual}/>

          <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:12}}>
            <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.4,textTransform:"uppercase"}}>Cumplimiento de metas</div>
            {metaFact>0
              ? <BulletMeta label="Facturación" actual={mpActual.facturacion} meta={metaFact}/>
              : <div style={{fontSize:12,color:C.muted}}>Define la meta de facturación para ver su cumplimiento.</div>}
            <BulletMeta label="Extras (O/N + SPOT)" actual={mpActual.extras} meta={recordExtras} record/>
            {topeCostos>0
              ? <BulletMeta label="Costos de flota" actual={costosActual} meta={topeCostos} lessIsBetter/>
              : <div style={{fontSize:12,color:C.muted}}>Define el tope de costos para ver su cumplimiento.</div>}
          </div>

          <TendenciaPeriodos serie={serieView} metasMap={metasMap} recordExtras={recordExtras}/>
        </>)}
      </>)}

      {esCliente&&<ResumenCO2 solicitudes={solicitudesPeriodo} rutas={rutas}/>}
      {!esCliente&&<>
      <div style={S.sectionTitle}>Solicitudes recientes</div>
      {solicitudes.length===0?<EmptyState msg="Sin solicitudes aún." action={()=>setView("nueva")}/>
        :[...solicitudes].sort((a,b)=>{
            const f=(b.fecha||"").localeCompare(a.fecha||"");
            return f!==0?f:(b.createdAt||"").localeCompare(a.createdAt||"");
          }).slice(0,3).map(s=><SolicitudRow key={s.id} sol={s} onSelect={id=>{setSelectedId(id);setView("detalle");}}/>)}
      {solicitudes.length>3&&<button style={S.linkBtn} onClick={()=>setView("lista")}>Ver todas →</button>}
      </>}
    </div>
  );
}

// ── Cierres ────────────────────────────────────────────────────────────────
function Cierres({cierres,onDetalle,onExport}){
  return(
    <div style={S.section}>
      <div style={S.pageTitle}>Historial de Cierres</div>
      {cierres.length===0?<EmptyState msg="No hay períodos cerrados aún."/>
        :cierres.map(c=>(
          <div key={c.id} style={{...S.row,cursor:"default"}}>
            <div style={{...S.rowIcon,background:C.cyan+"22",color:C.cyan,fontSize:14}}>✓</div>
            <div style={S.rowBody}>
              <div style={S.rowTitle}>{c.nombre}</div>
              <div style={S.rowMeta}><span style={{color:C.textSecondary}}>{c.fechaInicio} → {c.fechaFin}</span><span style={{color:C.muted}}> · {c.total} solicitudes</span></div>
            </div>
            <div style={{display:"flex",gap:8}}>
              <button style={{...S.exportBtn,fontSize:11}} onClick={()=>onExport(c)}>⬇ Excel</button>
              <button style={{...S.exportBtn,fontSize:11,borderColor:C.blue,color:C.cyan}} onClick={()=>onDetalle(c)}>Ver →</button>
            </div>
          </div>
        ))}
    </div>
  );
}

function CierreDetalle({cierre,setView,onExport}){
  return(
    <div style={S.section}>
      <button style={S.backBtn} onClick={()=>setView("cierres")}>← Volver</button>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div><div style={S.pageTitle}>{cierre.nombre}</div>
          <div style={{color:C.textSecondary,fontSize:13}}>{cierre.fechaInicio} → {cierre.fechaFin} · {cierre.total} solicitudes</div></div>
        <button style={S.exportBtn} onClick={onExport}>⬇ Excel</button>
      </div>
      {cierre.solicitudes.map(s=><SolicitudRow key={s.id} sol={s} onSelect={()=>{}}/>)}
    </div>
  );
}

// ── Lista ──────────────────────────────────────────────────────────────────
function Lista({solicitudes,filterTipo,setFilterTipo,filterStatus,setFilterStatus,filterFecha,setFilterFecha,filterQ,setFilterQ,onSelect,onExport,total,sesion}){
  const esCliente=sesion?.perfil==="cliente";
  return(
    <div style={S.section}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={S.pageTitle}>Solicitudes Abbott</div>
        {total>0&&sesion?.perfil!=="cliente"&&<button title="Exporta TODAS las solicitudes de la historia, no solo el período actual" style={{...S.exportBtn,display:"flex",alignItems:"center",gap:6}} onClick={onExport}><span>📥</span><span>Exportar historial completo ({total})</span></button>}
      </div>
      {filterFecha&&(
        <div style={{display:"flex",alignItems:"center",gap:8,background:C.cyan+"18",border:"1px solid "+C.cyan+"44",borderRadius:8,padding:"6px 12px",fontSize:12,color:C.cyan,width:"fit-content"}}>
          <span>Filtrando por {new Date(filterFecha+"T12:00:00").toLocaleDateString("es-CL")}{filterStatus==="en_gestion"?" · en gestión":filterStatus!=="todos"?" · "+(STATUS_META[filterStatus]?.label||filterStatus):""}</span>
          <button onClick={()=>{setFilterFecha("");setFilterStatus("todos");}} style={{background:"none",border:"none",color:C.cyan,cursor:"pointer",fontWeight:700,padding:0}}>✕</button>
        </div>
      )}
      <div style={S.filters}>
        <input style={S.searchInput} placeholder="Buscar por cliente o guía..." value={filterQ} onChange={e=>setFilterQ(e.target.value)}/>
        <select style={S.select} value={filterTipo} onChange={e=>setFilterTipo(e.target.value)}>
          <option value="todos">Todos los tipos</option>
          {Object.entries(TYPE_META).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
        </select>
        <select style={S.select} value={filterStatus} onChange={e=>setFilterStatus(e.target.value)}>
          <option value="todos">Todos los estados</option>
          {filterStatus==="en_gestion"&&<option value="en_gestion">En gestión (no pendientes)</option>}
          {Object.entries(STATUS_META).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
        </select>
      </div>
      {solicitudes.length===0?<EmptyState msg="No hay solicitudes que coincidan."/>
        :solicitudes.map(s=><SolicitudRow key={s.id} sol={s} onSelect={onSelect}/>)}
    </div>
  );
}

function SolicitudRow({sol,onSelect}){
  const tm=TYPE_META[sol.tipo]||{label:sol.tipo,icon:"·",color:"#6B8CAE"};
  const sm=STATUS_META[sol.status]||{label:sol.status,color:"#6B8CAE"};
  return(
    <div style={{...S.row,cursor:onSelect?"pointer":"default"}} onClick={()=>onSelect&&onSelect(sol.id)}>
      <div style={{...S.rowIcon,background:tm.color+"22",color:tm.color}}>{tm.icon}</div>
      <div style={S.rowBody}>
        <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
          {sol.ot&&<span style={{fontSize:11,fontWeight:800,color:C.cyan,background:C.cyan+"18",padding:"2px 7px",borderRadius:6}}>{sol.ot}</span>}
          <span style={S.rowTitle}>{sol.titulo}</span>
        </div>
        <div style={S.rowMeta}>
          <span style={{color:C.textSecondary}}>{tm.label}</span>
          <span style={{color:C.muted}}> · {sol.fecha}</span>
          {sol.noPresentacion&&<span style={{color:C.danger}}> · NP</span>}
        </div>
      </div>
      <div style={{...S.badge,background:sm.color+"22",color:sm.color}}>{sm.label}</div>
    </div>
  );
}

// ── Detalle ────────────────────────────────────────────────────────────────
function Detalle({sol,onStatusChange,onDelete,onEdit,onEditLog,onRefrescar,setView,clientes=CLIENTES_DEFAULT,sesion,solicitudes=[],choferes=CHOFERES,vehiculos=[]}){
  const opcionesPPU=(vehiculos||[]).filter(v=>v&&v.ppu).map(v=>{
    const ch=(choferes||[]).find(c=>c.ppu===v.ppu);
    const desc=ch?.nombre||[v.marca,v.modelo].filter(Boolean).join(" ");
    return {value:v.ppu, label:desc?`${v.ppu} · ${desc}`:v.ppu};
  });
  const esAdmin=sesion?.perfil==="admin";
  const tm=TYPE_META[sol.tipo]||{label:sol.tipo,icon:"·",color:"#6B8CAE"};
  const sm=STATUS_META[sol.status]||{label:sol.status,color:"#6B8CAE"};
  const [confirmDel,setConfirmDel]=useState(false);
  const [cancelando,setCancelando]=useState(false);
  const [canceladoPor,setCanceladoPor]=useState("");
  const [editMode,setEditMode]=useState(false);
  const [editForm,setEditForm]=useState({...sol});
  const [refrescando,setRefrescando]=useState(false);
  async function abrirEdicion(){
    // Antes de editar, se confirma contra la base el estado más reciente (status,
    // log, gestión del chofer) por si cambió mientras se estaba viendo el detalle.
    if(onRefrescar){
      setRefrescando(true);
      const fresco = await onRefrescar(sol.id);
      setRefrescando(false);
      setEditForm({...(fresco||sol)});
    } else {
      setEditForm({...sol});
    }
    setEditMode(true);
  }
  const fe=k=>e=>{
    const upd={...editForm,[k]:e.target.value};
    if(k==="tipo"){
      upd.prioridad=PRIORIDAD_DEFAULT[e.target.value]||editForm.prioridad;
      if(e.target.value==="li_devol"){
        const dhl=clientes.find(c=>(c.id?c.id+" - "+c.nombre:c.nombre)==="000-2 - Dhl Atlantis");
        upd.destino="000-2 - Dhl Atlantis";
        upd.direccion=dhl?.direccion||editForm.direccion;
        if(!editForm.hora)upd.hora="16:30";
      } else if(e.target.value==="carga_ol"){
        upd.devolucionUrgente=false;
        if(!CARGA_OL_CLIENTES.includes(upd.titulo)) upd.titulo="";
        upd.destino="";
      } else {
        upd.devolucionUrgente=false;
      }
    }
    if(k==="titulo"){const sel=resolverDestino(e.target.value,clientes);if(sel){upd.direccion=sel.direccion;upd.notas=sel.notas;upd.contacto=sel.contacto||upd.contacto;}}
    setEditForm(upd);
  };

  if(editMode) return(
    <div style={S.section}>
      <button style={S.backBtn} onClick={()=>setEditMode(false)}>← Cancelar edición</button>
      <div style={S.pageTitle}>Editar Solicitud</div>
      <div style={S.formGrid}>
        <div style={S.fGroup}><label style={S.label}>Tipo *</label>
          <select style={S.input} value={editForm.tipo} onChange={fe("tipo")}>
            {Object.entries(TYPE_META).map(([k,v])=><option key={k} value={k}>{v.icon} {v.label}</option>)}
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Prioridad</label>
          <select style={S.input} value={editForm.prioridad} onChange={fe("prioridad")}>
            <option value="urgente">🔴 Urgente</option><option value="normal">🟡 Normal</option>
          </select></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}>
          <label style={S.label}>Cliente *</label>
          <select style={S.input} value={editForm.titulo} onChange={fe("titulo")}>
            <option value="">-- Seleccionar cliente --</option>
            {(editForm.tipo==="carga_ol"?clientes.filter(c=>CARGA_OL_CLIENTES.includes(c.id?c.id+" - "+c.nombre:c.nombre)):clientes).flatMap((c,i)=>{
              const label=c.id?c.id+" - "+c.nombre:c.nombre;
              const base=[<option key={"c"+i} value={label}>{label}</option>];
              const subs=(c.sucursales||[]).map((s,si)=>{
                const sl=label+" — "+s.nombre;
                return <option key={"s"+i+"-"+si} value={sl}>{"  ↳ "+s.nombre}</option>;
              });
              return [...base,...subs];
            })}
          </select></div>
        {editForm.tipo==="carga_ol"&&<div style={{...S.fGroup,gridColumn:"1/-1"}}>
          <label style={S.label}>Destino</label>
          <select style={S.input} value={editForm.destino||""} onChange={e=>setEditForm(p=>({...p,destino:e.target.value}))}>
            <option value="">-- Seleccionar destino --</option>
            {DESTINOS_CARGA_OL.map(d=><option key={d} value={d}>{d}</option>)}
          </select></div>}
        {editForm.tipo!=="carga_ol"&&(editForm.titulo==="000-2 - Dhl Atlantis"||editForm.tipo==="li_devol")&&<div style={{...S.fGroup,gridColumn:"1/-1"}}>
          <label style={S.label}>Destino</label>
          <select style={{...S.input,...(editForm.tipo==="li_devol"?{opacity:0.7,cursor:"not-allowed"}:{})}} value={editForm.destino||""} disabled={editForm.tipo==="li_devol"} onChange={e=>{
            const sel=resolverDestino(e.target.value,clientes);
            setEditForm(p=>({...p,destino:e.target.value,
              direccion:sel?.direccion||p.direccion,
              descripcion:sel?.nombre?`Despacho a ${sel.nombre}`:"",
              notas:sel?.notas||p.notas}));
          }}>
            <option value="">-- Seleccionar destino --</option>
            {clientes.flatMap((c,i)=>{
              const label=c.id?c.id+" - "+c.nombre:c.nombre;
              const base=[<option key={"c"+i} value={label}>{label}</option>];
              const subs=(c.sucursales||[]).map((s,si)=>{
                const sl=label+" — "+s.nombre;
                return <option key={"s"+i+"-"+si} value={sl}>{"  ↳ "+s.nombre}</option>;
              });
              return [...base,...subs];
            })}
          </select>
          {editForm.tipo==="li_devol"&&<div style={{fontSize:11,color:C.muted,marginTop:4}}>Destino fijo: bodega DHL (devolución a operador logístico).</div>}
          </div>}
        <div style={S.fGroup}><label style={S.label}>Fecha *</label>
          <input style={S.input} type="date" value={editForm.fecha} onChange={fe("fecha")}/></div>
        <div style={S.fGroup}><label style={S.label}>Hora</label>
          <input style={S.input} type="time" value={editForm.hora} onChange={fe("hora")}/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Dirección</label>
          <input style={S.input} value={editForm.direccion} onChange={fe("direccion")}/></div>
        <div style={S.fGroup}><label style={S.label}>Contacto</label>
          <input style={S.input} value={editForm.contacto} onChange={fe("contacto")}/></div>
        <div style={S.fGroup}><label style={S.label}>Chofer Asignado</label>
          <select style={S.input} value={editForm.choferAsignado||""} onChange={fe("choferAsignado")}>
            <option value="">-- Seleccionar --</option>
            {choferes.map(c=><option key={c.nombre} value={c.nombre}>{c.nombre}</option>)}
          </select></div>
        <div style={S.fGroup}><label style={S.label}>OT Quantrex</label>
          <input style={{...S.input,background:C.navy,color:C.cyan,fontWeight:700}} value={editForm.ot||""} readOnly/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>N° Guías / Documentos Cliente (separar con coma)</label>
          <input style={S.input} placeholder="Ej: Factura 001, Guía 123, OC 456" value={editForm.documentos||""} onChange={fe("documentos")}/></div>
        <div style={S.fGroup}><label style={S.label}>Solicitante *</label>
          <select style={S.input} value={editForm.solicitante} onChange={fe("solicitante")}>
            <option value="">-- Seleccionar --</option>
            <option value="Jorge Monsalve">Jorge Monsalve</option>
            <option value="Yeneidi Rodriguez">Yeneidi Rodriguez</option>
            <option value="Andres Barrios">Andres Barrios</option>
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Canal de Solicitud</label>
          <select style={S.input} value={editForm.canalSolicitud} onChange={fe("canalSolicitud")}>
            <option value="">-- Seleccionar --</option>
            <option value="WhatsApp">WhatsApp</option>
            <option value="Email">Email</option>
            <option value="Llamada Telefónica">Llamada Telefónica</option>
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Usuario DispatchTrack</label>
          <select style={S.input} value={editForm.usuarioDT} onChange={fe("usuarioDT")}>
            <option value="">-- Seleccionar --</option>
            <option value="Quantrex M1">Quantrex M1</option>
            <option value="Quantrex M2">Quantrex M2</option>
          </select></div>
        <div style={S.fGroup}><label style={S.label}>PPU Asignada</label>
          <select style={S.input} value={editForm.ppuAsignada} onChange={fe("ppuAsignada")}>
            <option value="">-- Seleccionar --</option>
            {opcionesPPU.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}
            {editForm.ppuAsignada && !opcionesPPU.some(o=>o.value===editForm.ppuAsignada) && <option value={editForm.ppuAsignada}>{editForm.ppuAsignada} (no en mantenedor)</option>}
          </select></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Descripción</label>
          <textarea style={{...S.input,minHeight:60,resize:"vertical"}} value={editForm.descripcion} onChange={fe("descripcion")}/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Notas internas Quantrex</label>
          <textarea style={{...S.input,minHeight:50,resize:"vertical"}} value={editForm.notas} onChange={fe("notas")}/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}>
          <label style={S.label}>Observación {editForm.status==="no_entregado"&&<span style={{color:C.danger}}>(recomendada para No Entregado)</span>}</label>
          <textarea style={{...S.input,minHeight:50,resize:"vertical"}} value={editForm.observacionChofer||""} onChange={fe("observacionChofer")}
            placeholder="Motivo o situación de la entrega. Si la editas aquí, se registrará tu nombre y la fecha."/>
          {editForm.observacionAutor&&<div style={{fontSize:11,color:C.muted,marginTop:4}}>Última edición: {editForm.observacionAutor}{editForm.observacionFecha?" · "+new Date(editForm.observacionFecha).toLocaleString("es-CL"):""}</div>}
        </div>
        {esAdmin&&(
          <div style={{...S.fGroup,gridColumn:"1/-1"}}>
            <label style={{...S.label,color:C.warning}}>🧾 Observación Facturación / Pre-Cierre</label>
            <textarea style={{...S.input,minHeight:50,resize:"vertical"}} value={editForm.observacionCobro||""} onChange={fe("observacionCobro")}
              placeholder="Ej: Rechazos pre-cierre mes anterior con respaldos válidos"/>
            <div style={{marginTop:8}}>
              <label style={{...S.label,fontSize:11}}>Facturar en el período que incluya esta fecha (opcional)</label>
              <input style={{...S.input,maxWidth:200}} type="date" value={editForm.facturarEnPeriodo||""} onChange={fe("facturarEnPeriodo")} disabled={editForm.sinCobro}/>
              <div style={{fontSize:11,color:C.muted,marginTop:4}}>
                Si la dejas vacía, cuenta en el período de su fecha real ({sol.fecha}). Si pones una fecha de este mes, la solicitud se suma al cobro del período actual sin cambiar su fecha de servicio.
              </div>
            </div>
            <label style={{display:"flex",alignItems:"center",gap:8,fontSize:13,color:C.danger,cursor:"pointer",marginTop:10}}>
              <input type="checkbox" checked={!!editForm.sinCobro} onChange={e=>setEditForm(p=>({...p,sinCobro:e.target.checked,facturarEnPeriodo:e.target.checked?"":p.facturarEnPeriodo}))}/>
              Exenta de cobro permanente (no genera cargo en ningún período — queda solo como registro operativo)
            </label>
          </div>
        )}
        {editForm.tipo==="li_devol"&&<div style={{...S.fGroup,gridColumn:"1/-1",borderTop:`1px solid ${C.border}`,paddingTop:12}}>
          <label style={{...S.label,display:"flex",alignItems:"center",gap:8,cursor:"pointer"}}>
            <input type="checkbox" checked={editForm.devolucionUrgente||false} onChange={e=>setEditForm(p=>({...p,devolucionUrgente:e.target.checked}))}/>
            <span style={{color:C.warning}}>Devolución urgente exigida por Abbott — cuenta para cobro</span>
          </label>
          <div style={{fontSize:11,color:C.muted,marginTop:4}}>Las devoluciones normales no se cobran ni cuentan al límite diario. Marca esto solo si Abbott exigió un viaje extra por insumos urgentes.</div>
        </div>}
        <div style={{...S.fGroup,gridColumn:"1/-1",borderTop:`1px solid ${C.border}`,paddingTop:12}}>
          <label style={{...S.label,display:"flex",alignItems:"center",gap:8,cursor:"pointer"}}>
            <input type="checkbox" checked={editForm.noPresentacion||false} onChange={e=>setEditForm(p=>({...p,noPresentacion:e.target.checked,vehiculoNP:"",motivoNP:""}))}/>
            <span style={{color:C.danger}}>Registrar no presentación de vehículo (descuento)</span>
          </label></div>
        {editForm.noPresentacion&&<>
          <div style={S.fGroup}><label style={S.label}>Vehículo no presentado</label>
            <select style={S.input} value={editForm.vehiculoNP||""} onChange={fe("vehiculoNP")}>
              <option value="">-- Seleccionar --</option>
              <option value="Quantrex M1">Quantrex M1</option>
              <option value="Quantrex M2">Quantrex M2</option>
            </select></div>
          <div style={S.fGroup}><label style={S.label}>Motivo</label>
            <input style={S.input} value={editForm.motivoNP||""} onChange={fe("motivoNP")}/></div>
          <div style={{...S.fGroup,gridColumn:"1/-1"}}>
            <div style={{background:C.navy,border:`1px solid ${C.danger}44`,borderRadius:8,padding:"10px 14px",fontSize:12,color:C.danger,fontWeight:600}}>
              Descuento: ${Math.round(2840000/30).toLocaleString("es-CL")}
            </div></div>
        </>}
      </div>
      <div style={{display:"flex",gap:10,justifyContent:"flex-end",marginTop:8}}>
        <button style={S.btnSec} onClick={()=>setEditMode(false)}>Cancelar</button>
        <button style={S.btnPri} onClick={()=>{onEdit(editForm);setEditMode(false);}}>Guardar cambios</button>
      </div>
    </div>
  );

  return(
    <div style={S.section}>
      <button style={S.backBtn} onClick={()=>setView("lista")}>← Volver</button>
      <div style={S.detailHeader}>
        <div style={{...S.detailIcon,background:tm.color+"22",color:tm.color}}>{tm.icon}</div>
        <div style={{flex:1}}>
          <div style={S.pageTitle}>{sol.titulo}</div>
          <div style={{color:C.textSecondary,fontSize:13}}>{tm.label} · {sol.fecha}{sol.hora&&` · ${sol.hora}`}</div>
        </div>
        <div style={{...S.badge,background:sm.color+"22",color:sm.color}}>{sm.label}</div>
        {esAdmin||sesion?.perfil==="operador"?(
          sol._fotosCargadas
            ?<button style={{...S.exportBtn,fontSize:12,opacity:refrescando?.6:1}} disabled={refrescando} onClick={abrirEdicion}>{refrescando?"Verificando estado...":"✎ Editar"}</button>
            :<button style={{...S.exportBtn,fontSize:12,opacity:.5,cursor:"not-allowed"}} disabled title="Esperando a que carguen foto y firma antes de habilitar edición">⏳ Cargando datos...</button>
        ):null}
      </div>
      <div style={S.detailGrid}>
        {[["Dirección",sol.direccion],["Contacto",sol.contacto],["N° Guía",sol.guia],
          ["Prioridad",sol.prioridad==="urgente"?"🔴 Urgente":"🟡 Normal"],
          ["Solicitante",sol.solicitante],["Canal",sol.canalSolicitud],
          ["Usuario DT",sol.usuarioDT],["OT Quantrex",sol.ot],["PPU Asignada",sol.ppuAsignada],["Chofer",sol.choferAsignado]
        ].filter(([,v])=>v).map(([l,v])=>(
          <div key={l} style={S.detailField}><div style={S.fieldLabel}>{l}</div><div style={S.fieldValue}>{v}</div></div>
        ))}
      </div>
      {sol.titulo==="000-2 - Dhl Atlantis"&&sol.destino&&<div style={S.detailBlock}><div style={S.fieldLabel}>Destino</div><div style={S.fieldValue}>{sol.destino}</div></div>}
      {sol.noPresentacion&&<div style={{...S.detailBlock,border:`1px solid ${C.danger}44`}}>
        <div style={{...S.fieldLabel,color:C.danger}}>No presentación · {sol.vehiculoNP}</div>
        <div style={S.fieldValue}>{sol.motivoNP} <span style={{color:C.danger,fontWeight:700}}>· Descuento: ${Math.round(2840000/30).toLocaleString("es-CL")}</span></div>
      </div>}
      {sol.documentos&&<div style={S.detailBlock}><div style={S.fieldLabel}>N° Guías / Documentos Cliente</div><div style={S.fieldValue}>{sol.documentos}</div></div>}
      {sol.descripcion&&<div style={S.detailBlock}><div style={S.fieldLabel}>Descripción</div><div style={S.fieldValue}>{sol.descripcion}</div></div>}
      {sol.notas&&<div style={S.detailBlock}><div style={S.fieldLabel}>Notas internas</div><div style={S.fieldValue}>{sol.notas}</div></div>}
      {sol.observacionCobro&&<div style={{...S.detailBlock,border:`1px solid ${C.warning}`,background:C.warning+"11"}}><div style={{...S.fieldLabel,color:C.warning}}>🧾 Observación Facturación / Pre-Cierre</div><div style={S.fieldValue}>{sol.observacionCobro}</div>
        {sol.sinCobro&&<div style={{fontSize:11.5,color:C.danger,marginTop:6,fontWeight:700}}>🚫 EXENTA DE COBRO — no genera cargo en ningún período</div>}
        {!sol.sinCobro&&sol.facturarEnPeriodo&&<div style={{fontSize:11.5,color:C.warning,marginTop:6,fontWeight:600}}>↻ Facturada en el período de {sol.facturarEnPeriodo} · fecha real de servicio: {sol.fecha}</div>}
      </div>}
      {sol.canceladoPor&&<div style={{...S.detailBlock,border:`1px solid ${C.danger}44`}}><div style={{...S.fieldLabel,color:C.danger}}>Cancelada por</div><div style={S.fieldValue}>{sol.canceladoPor}</div></div>}
      {sol.observacionChofer&&<div style={S.detailBlock}><div style={S.fieldLabel}>Observación</div><div style={S.fieldValue}>📝 {sol.observacionChofer}</div>{sol.observacionAutor&&<div style={{fontSize:11,color:C.muted,marginTop:4}}>Por {sol.observacionAutor}{sol.observacionFecha?" · "+new Date(sol.observacionFecha).toLocaleString("es-CL"):""}</div>}</div>}
      {(sol.firmaReceptor||sol.rechazoFirma)&&(
        <div style={S.detailBlock}>
          <div style={S.fieldLabel}>{sol.rechazoFirma?"Firma digital no necesaria":(sol.tipo==="carga_ol"?"Firma del despachador":"Firma del receptor")}</div>
          {sol.nombreReceptor&&<div style={{fontSize:13,color:C.textPrimary,marginBottom:6}}>👤 {sol.nombreReceptor}</div>}
          {sol.rechazoFirma
            ?<div style={{background:C.info+"18",border:"1px solid "+C.info+"44",borderRadius:8,padding:"8px 12px",fontSize:13,color:C.info,fontWeight:600}}>🖊 Firma y timbre en papel · firma digital no fue necesaria</div>
            :<img src={sol.firmaReceptor} alt="Firma receptor" style={{maxWidth:280,borderRadius:8,border:"1px solid "+C.border,background:"#f9f9f9"}}/>
          }
        </div>
      )}
      {sol.horaEntrega&&(
        <div style={S.detailBlock}>
          <div style={S.fieldLabel}>Registro de entrega</div>
          {sol.horaLlegada&&<div style={{fontSize:12,color:C.muted,marginBottom:4}}>📍 Llegada al punto: {sol.horaLlegada}</div>}
          <div style={S.fieldValue}>🕐 Entrega registrada: {sol.horaEntrega}</div>
          {sol.tiempoEnPunto&&<div style={{marginTop:6,background:C.cyan+"18",border:"1px solid "+C.cyan+"44",borderRadius:8,padding:"6px 12px",display:"inline-flex",alignItems:"center",gap:6}}><span style={{fontSize:12,color:C.cyan,fontWeight:700}}>⏱ Tiempo en punto:</span><span style={{fontSize:14,fontWeight:900,color:C.cyan}}>{sol.tiempoEnPunto}</span></div>}
          {sol.geoEntrega&&sol.geoEntrega!=="Sin geolocalización"?(
            <>
              <div style={{fontSize:12,color:C.muted,marginTop:4}}>📍 {sol.geoEntrega}</div>
              <a href={"https://www.google.com/maps?q="+sol.geoEntrega} target="_blank" rel="noreferrer"
                style={{display:"inline-flex",alignItems:"center",gap:6,marginTop:8,background:C.cyan+"22",border:"1px solid "+C.cyan,color:C.cyan,borderRadius:8,padding:"7px 14px",fontSize:12,fontWeight:700,textDecoration:"none"}}>
                📍 Ver en Google Maps
              </a>
            </>
          ):<div style={{fontSize:12,color:C.muted,marginTop:4}}>Sin geolocalización disponible</div>}
          {((sol.fotosEntrega&&sol.fotosEntrega.length>0)||sol.fotoEntrega)&&(()=>{
            const docs=(sol.fotosEntrega&&sol.fotosEntrega.length>0)?sol.fotosEntrega:(sol.fotoEntrega?[sol.fotoEntrega]:[]);
            return(
            <div style={{marginTop:12}}>
              <div style={{fontSize:10,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase",marginBottom:6}}>Foto del documento ({docs.length})</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                {docs.map((b,i)=>(
                  <a key={i} href={b} download={"foto_documento_"+(i+1)+".jpg"} target="_blank" rel="noreferrer">
                    <img src={b} alt={"Documento "+(i+1)} style={{width:96,height:96,borderRadius:10,objectFit:"cover",border:"1px solid "+C.border}}/>
                  </a>
                ))}
              </div>
            </div>
            );
          })()}
          {(sol.fotosManifiesto||[]).length>0&&(
            <div style={{marginTop:12}}>
              <div style={{fontSize:10,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase",marginBottom:6}}>Registro Fotográfico Manifiesto DHL ({sol.fotosManifiesto.length})</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                {sol.fotosManifiesto.map((b,i)=>(
                  <a key={i} href={b} download={"manifiesto_"+(i+1)+".jpg"} target="_blank" rel="noreferrer">
                    <img src={b} alt={"Manifiesto "+(i+1)} style={{width:96,height:96,borderRadius:10,objectFit:"cover",border:"1px solid "+C.border}}/>
                  </a>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
      {esAdmin&&(<>
      <div style={S.fieldLabel}>Cambiar estado</div>
      <div style={S.statusBtns}>
        {Object.entries(STATUS_META).map(([k,v])=>
          k==="cancelada"
            ?<button key={k} onClick={()=>setCancelando(true)} style={{...S.statusBtn,background:sol.status===k?v.color:"transparent",color:sol.status===k?"#fff":v.color,border:`1px solid ${v.color}`}}>{v.label}</button>
            :<button key={k} onClick={()=>onStatusChange(sol.id,k)} style={{...S.statusBtn,background:sol.status===k?v.color:"transparent",color:sol.status===k?"#fff":v.color,border:`1px solid ${v.color}`}}>{v.label}</button>
        )}
      </div>
      {cancelando&&(
        <div style={{background:C.navySurface,border:`1px solid ${C.danger}`,borderRadius:10,padding:"14px 16px",display:"flex",flexDirection:"column",gap:10}}>
          <div style={{fontSize:13,fontWeight:700,color:C.danger}}>¿Quién cancela esta solicitud?</div>
          <select style={S.input} value={canceladoPor} onChange={e=>setCanceladoPor(e.target.value)}>
            <option value="">-- Seleccionar --</option>
            <option value="Jorge Monsalve">Jorge Monsalve</option>
            <option value="Yeneidi Rodriguez">Yeneidi Rodriguez</option>
            <option value="Andres Barrios">Andres Barrios</option>
          </select>
          <div style={{display:"flex",gap:8}}>
            <button style={{...S.statusBtn,border:`1px solid ${C.muted}`,color:C.muted}} onClick={()=>{setCancelando(false);setCanceladoPor("");}}>Cancelar</button>
            <button style={{...S.statusBtn,background:C.danger,color:"#fff",border:"none"}} disabled={!canceladoPor}
              onClick={()=>{onStatusChange(sol.id,"cancelada",canceladoPor);setCancelando(false);setCanceladoPor("");}}>Confirmar</button>
          </div>
        </div>
      )}
      </>)}
      {!esAdmin&&<div style={{...S.detailBlock,fontSize:12,color:C.muted}}>Estado actual: <b style={{color:sm.color}}>{sm.label}</b></div>}
      <LogEstados log={sol.statusLog||[]} solId={sol.id} onEditLog={onEditLog} esAdmin={esAdmin} usuarioActual={sesion?.nombre||sesion?.email||"Administrador"}/>
      {esAdmin&&<div style={{marginTop:16}}>
        {!confirmDel
          ?<button style={S.deleteBtn} onClick={()=>setConfirmDel(true)}>Eliminar solicitud</button>
          :<div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
            <span style={{color:C.danger,fontSize:13}}>¿Confirmar eliminación?</span>
            <button style={{...S.statusBtn,border:`1px solid ${C.danger}`,color:C.danger}} onClick={()=>onDelete(sol.id)}>Sí, eliminar</button>
            <button style={{...S.statusBtn,border:`1px solid ${C.muted}`,color:C.muted}} onClick={()=>setConfirmDel(false)}>Cancelar</button>
          </div>
        }
      </div>}
    </div>
  );
}

// ── LogEstados ─────────────────────────────────────────────────────────────
function LogEstados({log,solId,onEditLog,esAdmin=true,usuarioActual="Administrador"}){
  const [editMode,setEditMode]=useState(false);
  const [editLog,setEditLog]=useState(log);
  const upd=(id,f,v)=>setEditLog(p=>p.map(e=>e.id===id?{...e,[f]:v}:e));
  const del=id=>setEditLog(p=>p.filter(e=>e.id!==id));
  const add=()=>{const n=new Date();setEditLog(p=>[...p,{id:Date.now().toString(),de:"Pendiente",a:"En Tránsito",
    fechaHora:n.toLocaleDateString("es-CL")+" "+n.toLocaleTimeString("es-CL",{hour:"2-digit",minute:"2-digit",hour12:false}),canceladoPor:null,usuario:usuarioActual+" (manual)"}]);};
  return(
    <div style={{background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:10,padding:"12px 14px",display:"flex",flexDirection:"column",gap:8}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div style={S.fieldLabel}>Log de estados</div>
        {esAdmin&&<button style={{...S.exportBtn,fontSize:11,padding:"4px 10px"}} onClick={()=>{setEditMode(!editMode);setEditLog(log);}}>
          {editMode?"Cancelar":"✎ Editar log"}
        </button>}
      </div>
      {log.length===0&&!editMode&&<div style={{fontSize:12,color:C.muted}}>Sin cambios registrados.</div>}
      {!editMode?log.map((e,i)=>(
        <div key={i} style={{fontSize:12,color:C.textSecondary,display:"flex",gap:6,alignItems:"center"}}>
          <span style={{color:C.cyan}}>→</span>
          <span style={{color:C.textPrimary,fontWeight:600}}>{e.de} → {e.a}</span>
          <span style={{color:C.muted}}>· {(e.fechaHora||"").split(" ")[1]||e.fechaHora}</span>
          {e.canceladoPor&&<span style={{color:C.danger}}>· {e.canceladoPor}</span>}
          {esAdmin&&e.usuario&&<span style={{color:C.muted,fontStyle:"italic"}}>· por {e.usuario}</span>}
        </div>
      )):(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {editLog.map(e=>(
            <div key={e.id} style={{background:C.navy,borderRadius:8,padding:"10px 12px",display:"flex",flexDirection:"column",gap:6}}>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                <select style={{...S.input,flex:1,fontSize:12,padding:"5px 8px"}} value={e.de} onChange={ev=>upd(e.id,"de",ev.target.value)}>
                  {Object.values(STATUS_META).map(v=><option key={v.label} value={v.label}>{v.label}</option>)}
                </select>
                <span style={{color:C.muted,alignSelf:"center"}}>→</span>
                <select style={{...S.input,flex:1,fontSize:12,padding:"5px 8px"}} value={e.a} onChange={ev=>upd(e.id,"a",ev.target.value)}>
                  {Object.values(STATUS_META).map(v=><option key={v.label} value={v.label}>{v.label}</option>)}
                </select>
              </div>
              <input style={{...S.input,fontSize:12,padding:"5px 8px"}} value={e.fechaHora}
                placeholder="DD/MM/YYYY HH:MM (24hrs)" onChange={ev=>upd(e.id,"fechaHora",ev.target.value)}/>
              <div style={{display:"flex",justifyContent:"flex-end"}}>
                <button style={{...S.statusBtn,border:`1px solid ${C.danger}`,color:C.danger,fontSize:11,padding:"3px 10px"}} onClick={()=>del(e.id)}>Eliminar</button>
              </div>
            </div>
          ))}
          <div style={{display:"flex",gap:8,justifyContent:"space-between"}}>
            <button style={{...S.exportBtn,fontSize:11}} onClick={add}>+ Agregar entrada</button>
            <button style={{...S.btnPri,fontSize:12,padding:"7px 16px"}} onClick={()=>{onEditLog(solId,editLog);setEditMode(false);}}>Guardar log</button>
          </div>
        </div>
      )}
    </div>
  );
}

// ── FormNueva ──────────────────────────────────────────────────────────────
function FormNueva({form,setForm,onSave,saving,error,setView,clientes=CLIENTES_DEFAULT,solicitudes=[],rutas=[],choferes=CHOFERES,vehiculos=[]}){
  const opcionesPPU=(vehiculos||[]).filter(v=>v&&v.ppu).map(v=>{
    const ch=(choferes||[]).find(c=>c.ppu===v.ppu);
    const desc=ch?.nombre||[v.marca,v.modelo].filter(Boolean).join(" ");
    return {value:v.ppu, label:desc?`${v.ppu} · ${desc}`:v.ppu};
  });
  const [clienteQ,setClienteQ]=useState("");
  const [clienteOpen,setClienteOpen]=useState(false);
  // Opciones de cliente aplanadas (cliente + sucursales) para el buscador
  const opcionesCliente=clientes.flatMap(c=>{
    const label=c.id?c.id+" - "+c.nombre:c.nombre;
    const arr=[{value:label,texto:label}];
    (c.sucursales||[]).forEach(su=>arr.push({value:label+" — "+su.nombre,texto:label+" — "+su.nombre}));
    return arr;
  });
  const clienteFiltrado=clienteQ.trim()
    ? opcionesCliente.filter(o=>o.texto.toLowerCase().includes(clienteQ.trim().toLowerCase())).slice(0,40)
    : opcionesCliente.slice(0,40);
  const f=k=>e=>setForm(p=>{
    const u={...p,[k]:e.target.value};
    if(k==="tipo"){
      u.prioridad=PRIORIDAD_DEFAULT[e.target.value]||"normal";
      if(e.target.value==="li_devol"){
        const dhl=clientes.find(c=>(c.id?c.id+" - "+c.nombre:c.nombre)==="000-2 - Dhl Atlantis");
        u.destino="000-2 - Dhl Atlantis";
        u.direccion=dhl?.direccion||p.direccion;
        u.notas=dhl?.notas||p.notas;
        u.hora="16:30";
      } else if(e.target.value==="carga_ol"){
        u.devolucionUrgente=false;
        if(!CARGA_OL_CLIENTES.includes(u.titulo)) u.titulo="";
        u.destino="";
      } else {
        u.devolucionUrgente=false;
      }
    }
    if(k==="titulo"){const sel=resolverDestino(e.target.value,clientes);if(sel){u.direccion=sel.direccion;u.notas=sel.notas;u.contacto=sel.contacto||u.contacto;if(u.tipo!=="carga_ol")u.destino="";}}
    return u;
  });
  return(
    <div style={S.section}>
      <div style={S.pageTitle}>Nueva Solicitud</div>
      <div style={S.formGrid}>
        <div style={S.fGroup}><label style={S.label}>Tipo *</label>
          <select style={S.input} value={form.tipo} onChange={f("tipo")}>
            {Object.entries(TYPE_META).map(([k,v])=><option key={k} value={k}>{v.icon} {v.label}</option>)}
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Prioridad</label>
          <select style={S.input} value={form.prioridad} onChange={f("prioridad")}>
            <option value="urgente">🔴 Urgente</option><option value="normal">🟡 Normal</option>
          </select></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}>
          <label style={S.label}>Cliente *</label>
          {form.tipo==="carga_ol"?(
            <select style={S.input} value={form.titulo} onChange={f("titulo")}>
              <option value="">-- Seleccionar cliente --</option>
              {clientes.filter(c=>CARGA_OL_CLIENTES.includes(c.id?c.id+" - "+c.nombre:c.nombre)).map((c,i)=>{
                const label=c.id?c.id+" - "+c.nombre:c.nombre;
                return <option key={"c"+i} value={label}>{label}</option>;
              })}
            </select>
          ):(
            <div style={{position:"relative"}}>
              <input style={S.input} placeholder="Buscar cliente por nombre o RUT…"
                value={clienteOpen?clienteQ:(form.titulo||"")}
                onFocus={()=>{setClienteOpen(true);setClienteQ("");}}
                onChange={e=>{setClienteQ(e.target.value);setClienteOpen(true);}}
                onBlur={()=>setTimeout(()=>setClienteOpen(false),150)}/>
              {clienteOpen&&<div style={{position:"absolute",top:"100%",left:0,right:0,zIndex:50,marginTop:4,maxHeight:260,overflowY:"auto",background:C.navy,border:"1px solid "+C.border,borderRadius:10,boxShadow:"0 8px 24px #00000055"}}>
                {clienteFiltrado.length===0
                  ?<div style={{padding:"10px 14px",fontSize:13,color:C.muted}}>Sin coincidencias</div>
                  :clienteFiltrado.map((o,i)=>(
                    <div key={i} onMouseDown={()=>{f("titulo")({target:{value:o.value}});setClienteOpen(false);setClienteQ("");}}
                      style={{padding:"9px 14px",fontSize:13,color:C.text,cursor:"pointer",borderBottom:"1px solid "+C.border+"55",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}
                      onMouseEnter={e=>e.currentTarget.style.background=C.cyan+"22"}
                      onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                      {o.texto.includes(" — ")?"↳ "+o.texto:o.texto}
                    </div>
                  ))}
              </div>}
            </div>
          )}</div>
        {/* Alerta cliente con solicitudes activas hoy */}
        {form.titulo&&(()=>{
          const hoy=new Date().toISOString().split("T")[0];
          const activas=solicitudes.filter(s=>s.titulo===form.titulo&&s.fecha===hoy&&s.status!=="cancelada"&&s.status!=="completada");
          return activas.length>0?(<div style={{...S.fGroup,gridColumn:"1/-1"}}>
            <div style={{background:C.warning+"22",border:"1px solid "+C.warning,borderRadius:8,padding:"10px 14px",fontSize:13,color:C.warning,fontWeight:600}}>
              ⚠ Este cliente ya tiene {activas.length} solicitud(es) activa(s) hoy. Se generará una nueva OT.
            </div>
          </div>):null;
        })()}
        {form.tipo==="carga_ol"&&<div style={{...S.fGroup,gridColumn:"1/-1"}}>
          <label style={S.label}>Destino</label>
          <select style={S.input} value={form.destino} onChange={e=>setForm(p=>({...p,destino:e.target.value}))}>
            <option value="">-- Seleccionar destino --</option>
            {DESTINOS_CARGA_OL.map(d=><option key={d} value={d}>{d}</option>)}
          </select></div>}
        {form.tipo!=="carga_ol"&&(form.titulo==="000-2 - Dhl Atlantis"||form.tipo==="li_devol")&&<div style={{...S.fGroup,gridColumn:"1/-1"}}>
          <label style={S.label}>Destino</label>
          <select style={{...S.input,...(form.tipo==="li_devol"?{opacity:0.7,cursor:"not-allowed"}:{})}} value={form.destino} disabled={form.tipo==="li_devol"} onChange={e=>{
            const sel=resolverDestino(e.target.value,clientes);
            setForm(p=>({...p,destino:e.target.value,
              direccion:sel?.direccion||p.direccion,
              descripcion:sel?.nombre?`Despacho a ${sel.nombre}`:"",
              notas:sel?.notas||p.notas}));
          }}>
            <option value="">-- Seleccionar destino --</option>
            {clientes.flatMap((c,i)=>{
              const label=c.id?c.id+" - "+c.nombre:c.nombre;
              const base=[<option key={"c"+i} value={label}>{label}</option>];
              const subs=(c.sucursales||[]).map((s,si)=>{
                const sl=label+" — "+s.nombre;
                return <option key={"s"+i+"-"+si} value={sl}>{"  ↳ "+s.nombre}</option>;
              });
              return [...base,...subs];
            })}
          </select>
          {form.tipo==="li_devol"&&<div style={{fontSize:11,color:C.muted,marginTop:4}}>Destino fijo: bodega DHL (devolución a operador logístico).</div>}
          </div>}
        <div style={S.fGroup}><label style={S.label}>Fecha *</label>
          <input style={S.input} type="date" value={form.fecha} onChange={f("fecha")}/></div>
        <div style={S.fGroup}><label style={S.label}>Hora</label>
          <input style={S.input} type="time" value={form.hora} onChange={f("hora")}/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Dirección</label>
          <input style={S.input} placeholder="Dirección de entrega" value={form.direccion} onChange={f("direccion")}/></div>
        <div style={S.fGroup}><label style={S.label}>Contacto</label>
          <input style={S.input} placeholder="Nombre / teléfono" value={form.contacto} onChange={f("contacto")}/></div>
        <div style={S.fGroup}><label style={S.label}>Solicitante *</label>
          <select style={S.input} value={form.solicitante} onChange={f("solicitante")}>
            <option value="">-- Seleccionar --</option>
            <option value="Jorge Monsalve">Jorge Monsalve</option>
            <option value="Yeneidi Rodriguez">Yeneidi Rodriguez</option>
            <option value="Andres Barrios">Andres Barrios</option>
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Canal de Solicitud *</label>
          <select style={S.input} value={form.canalSolicitud} onChange={f("canalSolicitud")}>
            <option value="">-- Seleccionar --</option>
            <option value="WhatsApp">WhatsApp</option>
            <option value="Email">Email</option>
            <option value="Llamada Telefónica">Llamada Telefónica</option>
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Usuario DispatchTrack</label>
          <select style={S.input} value={form.usuarioDT} onChange={f("usuarioDT")}>
            <option value="">-- Seleccionar --</option>
            <option value="Quantrex M1">Quantrex M1</option>
            <option value="Quantrex M2">Quantrex M2</option>
          </select></div>
        <div style={S.fGroup}><label style={S.label}>PPU Asignada</label>
          <select style={S.input} value={form.ppuAsignada} onChange={f("ppuAsignada")}>
            <option value="">-- Seleccionar --</option>
            {opcionesPPU.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}
            {form.ppuAsignada && !opcionesPPU.some(o=>o.value===form.ppuAsignada) && <option value={form.ppuAsignada}>{form.ppuAsignada} (no en mantenedor)</option>}
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Chofer Asignado</label>
          <select style={S.input} value={form.choferAsignado} onChange={f("choferAsignado")}>
            <option value="">-- Seleccionar --</option>
            {choferes.map(c=><option key={c.nombre} value={c.nombre}>{c.nombre}</option>)}
          </select></div>
        <div style={S.fGroup}><label style={S.label}>Asignar a Ruta</label>
          <select style={S.input} value={form.rutaId} onChange={f("rutaId")}>
            <option value="">-- Sin ruta --</option>
            {rutas.map(r=><option key={r.id} value={r.id}>{r.id} · {r.fecha} · {r.vehiculo}</option>)}
          </select></div>
        <div style={S.fGroup}><label style={S.label}>OT Quantrex</label>
          <input style={{...S.input,background:C.navy,color:C.cyan,fontWeight:700}} value={form.ot||"Se genera automáticamente"} readOnly/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>N° Guías / Documentos Cliente (separar con coma)</label>
          <input style={S.input} placeholder="Ej: Factura 001, Guía 123, OC 456" value={form.documentos} onChange={f("documentos")}/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Descripción</label>
          <textarea style={{...S.input,minHeight:60,resize:"vertical"}} placeholder="Detalle de la carga..." value={form.descripcion} onChange={f("descripcion")}/></div>
        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Notas internas Quantrex</label>
          <textarea style={{...S.input,minHeight:50,resize:"vertical"}} placeholder="Instrucciones al equipo..." value={form.notas} onChange={f("notas")}/></div>
        {form.tipo==="li_devol"&&<div style={{...S.fGroup,gridColumn:"1/-1",borderTop:`1px solid ${C.border}`,paddingTop:12,marginTop:4}}>
          <label style={{...S.label,display:"flex",alignItems:"center",gap:8,cursor:"pointer"}}>
            <input type="checkbox" checked={form.devolucionUrgente||false} onChange={e=>setForm(p=>({...p,devolucionUrgente:e.target.checked}))}/>
            <span style={{color:C.warning}}>Devolución urgente exigida por Abbott — cuenta para cobro</span>
          </label>
          <div style={{fontSize:11,color:C.muted,marginTop:4}}>Las devoluciones normales (fin de jornada a bodega) no se cobran ni cuentan al límite diario. Marca esto solo si Abbott exigió un viaje extra por insumos urgentes.</div>
        </div>}
        <div style={{...S.fGroup,gridColumn:"1/-1",borderTop:`1px solid ${C.border}`,paddingTop:12,marginTop:4}}>
          <label style={{...S.label,display:"flex",alignItems:"center",gap:8,cursor:"pointer"}}>
            <input type="checkbox" checked={form.noPresentacion} onChange={e=>setForm(p=>({...p,noPresentacion:e.target.checked,vehiculoNP:"",motivoNP:""}))}/>
            <span style={{color:C.danger}}>Registrar no presentación de vehículo (descuento)</span>
          </label></div>
        {form.noPresentacion&&<>
          <div style={S.fGroup}><label style={S.label}>Vehículo no presentado</label>
            <select style={S.input} value={form.vehiculoNP} onChange={f("vehiculoNP")}>
              <option value="">-- Seleccionar --</option>
              <option value="Quantrex M1">Quantrex M1</option>
              <option value="Quantrex M2">Quantrex M2</option>
            </select></div>
          <div style={S.fGroup}><label style={S.label}>Motivo</label>
            <input style={S.input} placeholder="Describe el motivo..." value={form.motivoNP} onChange={f("motivoNP")}/></div>
          <div style={{...S.fGroup,gridColumn:"1/-1"}}>
            <div style={{background:C.navy,border:`1px solid ${C.danger}44`,borderRadius:8,padding:"10px 14px",fontSize:12,color:C.danger,fontWeight:600}}>
              Descuento a aplicar: ${Math.round(2840000/30).toLocaleString("es-CL")} · ($2.840.000 / 30 días)
            </div></div>
        </>}
      </div>
      {error&&<div style={{color:C.danger,fontSize:13,fontWeight:600}}>{error}</div>}
      <div style={{display:"flex",gap:10,justifyContent:"flex-end",marginTop:8}}>
        <button style={S.btnSec} onClick={()=>setView("lista")}>Cancelar</button>
        <button style={S.btnPri} onClick={onSave} disabled={saving}>{saving?"Guardando…":"Crear solicitud"}</button>
      </div>
    </div>
  );
}



// ── Pantalla Login ─────────────────────────────────────────────────────────
function PantallaLogin({onLogin,usuarios=USUARIOS,choferes=CHOFERES}){
  const [email,setEmail]=useState("");
  const [password,setPassword]=useState("");
  const [error,setError]=useState("");
  const [modo,setModo]=useState("login");
  const [cambioRequerido,setCambioRequerido]=useState(null);
  const [nuevaPassword,setNuevaPassword]=useState("");
  const [pinChofer,setPinChofer]=useState("");

  function handleLogin(){
    const u=usuarios.find(u=>u.email===email&&u.password===password);
    if(u){
      if(u.bloqueado){
        setError(`Cuenta bloqueada por inactividad (${DIAS_INACTIVIDAD_BLOQUEO}+ días sin acceder). Contacta a Quantrex para reactivarla.`);
        return;
      }
      if(debeCambiarPassword(u)){
        setCambioRequerido(u);
      } else {
        onLogin(u);
      }
    }
    else{setError("Email o contraseña incorrectos.");}
  }

  return(
    <div style={{minHeight:"100vh",background:C.navy,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:16,padding:"32px 28px",width:"100%",maxWidth:380,display:"flex",flexDirection:"column",gap:20}}>
        <div style={{textAlign:"center"}}>
          <img src={LOGO_QUANTREX} alt="Quantrex Abbott" style={{width:150,height:150,borderRadius:"50%",display:"block",margin:"0 auto",boxShadow:"0 0 0 4px rgba(0,174,239,.12), 0 18px 50px rgba(0,0,0,.55), 0 0 60px rgba(0,174,239,.18)"}}/>
        </div>

        {cambioRequerido?(
          <>
            <div style={{textAlign:"center",marginBottom:8}}>
              <div style={{fontSize:14,fontWeight:700,color:C.warning}}>⚠ Cambio de contraseña requerido</div>
              <div style={{fontSize:12,color:C.muted,marginTop:4}}>Es el primer día del mes. Por seguridad debes actualizar tu contraseña.</div>
            </div>
            <div style={S.fGroup}>
              <label style={S.label}>Nueva contraseña</label>
              <input style={S.input} type="password" placeholder="Nueva contraseña" value={nuevaPassword} onChange={e=>setNuevaPassword(e.target.value)}/>
            </div>
            <button style={{...S.btnPri,width:"100%",padding:"13px",fontSize:15,opacity:nuevaPassword.length>=6?1:0.5}}
              disabled={nuevaPassword.length<6}
              onClick={()=>{
                const u={...cambioRequerido,password:nuevaPassword};
                marcarPasswordCambiado(u.email);
                onLogin(u);
              }}>
              Actualizar y continuar
            </button>
            <div style={{fontSize:11,color:C.muted,textAlign:"center"}}>Mínimo 6 caracteres</div>
          </>
        ):modo==="login"?(
          <>
            <div style={S.fGroup}>
              <label style={S.label}>Email</label>
              <input style={S.input} type="email" placeholder="usuario@quantrex.cl"
                value={email} onChange={e=>setEmail(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&handleLogin()}/>
            </div>
            <div style={S.fGroup}>
              <label style={S.label}>Contraseña</label>
              <input style={S.input} type="password" placeholder="••••••••"
                value={password} onChange={e=>setPassword(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&handleLogin()}/>
            </div>
            {error&&<div style={{color:C.danger,fontSize:13,fontWeight:600,textAlign:"center"}}>{error}</div>}
            <button style={{...S.btnPri,width:"100%",padding:"13px",fontSize:15}} onClick={handleLogin}>
              Ingresar
            </button>
            <button style={{background:"transparent",border:"none",color:C.cyan,cursor:"pointer",fontSize:13,fontWeight:600,textAlign:"center"}}
              onClick={()=>setModo("chofer")}>
              🚗 Soy chofer — acceder aquí
            </button>
          </>
        ):(
          <>
            <div style={{textAlign:"center",fontSize:13,color:C.textSecondary}}>Selecciona tu nombre e ingresa tu PIN para ver tus entregas del día</div>
            <div style={S.fGroup}>
              <label style={S.label}>Chofer</label>
              <select style={{...S.input,fontSize:15,padding:"12px"}} value={email} onChange={e=>{setEmail(e.target.value);setError("");}}>
                <option value="">-- Selecciona tu nombre --</option>
                {choferes.map(c=><option key={c.nombre} value={c.nombre}>{c.nombre} · {c.ppu}</option>)}
              </select>
            </div>
            <div style={S.fGroup}>
              <label style={S.label}>PIN (4 dígitos)</label>
              <input style={{...S.input,fontSize:22,padding:"12px",letterSpacing:8,textAlign:"center"}} type="password" inputMode="numeric"
                maxLength={4} placeholder="••••" value={pinChofer}
                onChange={e=>{setPinChofer(e.target.value.replace(/\D/g,"").slice(0,4));setError("");}}
                onKeyDown={e=>{if(e.key==="Enter"){const c=choferes.find(ch=>ch.nombre===email);if(c&&(c.pin||"")===pinChofer)onLogin({...c,perfil:"chofer",nombre:c.nombre});else setError("Chofer o PIN incorrecto.");}}}/>
            </div>
            {error&&<div style={{color:C.danger,fontSize:13,fontWeight:600,textAlign:"center"}}>{error}</div>}
            <button style={{...S.btnPri,width:"100%",padding:"13px",fontSize:15,opacity:(email&&pinChofer.length===4)?1:0.5}}
              disabled={!email||pinChofer.length!==4}
              onClick={()=>{const c=choferes.find(ch=>ch.nombre===email);if(c&&(c.pin||"")===pinChofer)onLogin({...c,perfil:"chofer",nombre:c.nombre});else setError("Chofer o PIN incorrecto.");}}>
              Ingresar como Chofer
            </button>
            <button style={{background:"transparent",border:"none",color:C.muted,cursor:"pointer",fontSize:13,textAlign:"center"}}
              onClick={()=>{setModo("login");setEmail("");setPinChofer("");setError("");}}>
              ← Volver al login
            </button>
          </>
        )}
      </div>
    </div>
  );
}



// ── Gestión de Rutas ───────────────────────────────────────────────────────
const VEHICULOS = [
  {id:"M1", label:"M1 · Felipe Hernandez", ppu:"KRYX27"},
  {id:"M2", label:"M2 · Italo Loiza", ppu:"PBGJ33"},
  {id:"M3", label:"M3 · Cristian Donoso", ppu:"PZGH22"},
];

function GestionRutas({rutas,setRutas,solicitudes,setSolicitudes,onSaveRuta,onDeleteRuta,onSaveSolicitud,setView,sesion,vehiculos=[],choferes=[]}){
  const hoy=new Date().toISOString().split("T")[0];
  // ── Vehículos alineados con el mantenedor (Gestión de Usuarios) ───────────
  // Opciones derivadas del estado sincronizado con Supabase. La identidad es la
  // PPU; se enriquece con el chofer asignado (match por PPU en `choferes`).
  const opcionesVehiculo=(vehiculos||[]).filter(v=>v&&v.ppu).map(v=>{
    const ch=(choferes||[]).find(c=>c.ppu===v.ppu);
    const desc=ch?.nombre||[v.marca,v.modelo].filter(Boolean).join(" ");
    return {value:v.ppu, label:desc?`${v.ppu} · ${desc}`:v.ppu};
  });
  // Compatibilidad con rutas antiguas que guardaron códigos M1/M2/M3.
  function resolverVehiculo(code){
    if(!code) return {value:"",label:"—"};
    const legacy=VEHICULOS.find(v=>v.id===code);
    const ppu=legacy?legacy.ppu:code;
    const opt=opcionesVehiculo.find(o=>o.value===ppu);
    if(opt) return opt;
    if(legacy) return {value:ppu,label:legacy.label};
    return {value:ppu,label:ppu};
  }
  const vehiculoDefault=opcionesVehiculo[0]?.value||"";
  const [nuevaRuta,setNuevaRuta]=useState(false);
  const [formRuta,setFormRuta]=useState({nombre:"",fecha:hoy,vehiculo:""});
  const [rutaDetalle,setRutaDetalle]=useState(null);
  const [agregandoParada,setAgregandoParada]=useState(false);
  const [kmCalculando,setKmCalculando]=useState(false);

  function generarIdRuta(){
    return "RUTA-"+(rutas.length+1).toString().padStart(3,"0");
  }

  async function crearRuta(){
    if(!formRuta.vehiculo){window.alert("Selecciona un vehículo. Si no aparece ninguno, agrégalo en Gestión de Usuarios → Vehículos.");return;}
    const idRuta=generarIdRuta();
    const r={id:idRuta,nombre:idRuta,fecha:formRuta.fecha,
      vehiculo:formRuta.vehiculo,paradas:[],kmTotal:null,estado:"abierta",cerradaPor:null,reaperturas:[],createdAt:new Date().toISOString()};
    const upd=[r,...rutas];
    setRutas(upd); await onSaveRuta(r);
    setNuevaRuta(false); setFormRuta({nombre:"",fecha:hoy,vehiculo:vehiculoDefault});
    setRutaDetalle(r.id);
  }

  async function eliminarRuta(id){
    if(!window.confirm("¿Eliminar esta ruta?"))return;
    setRutas(rutas.filter(r=>r.id!==id));
    await onDeleteRuta(id);
    if(rutaDetalle===id)setRutaDetalle(null);
  }

  async function agregarParada(rutaId, solId, orden){
    const upd=rutas.map(r=>{
      if(r.id!==rutaId)return r;
      const paradas=[...r.paradas.filter(p=>p.solId!==solId),{solId,orden:r.paradas.length+1}]
        .sort((a,b)=>a.orden-b.orden);
      return {...r,paradas};
    });
    setRutas(upd);
    const ruta=upd.find(r=>r.id===rutaId);
    if(ruta) await onSaveRuta(ruta);
    // Actualizar solicitud con ID de ruta
    const sol=solicitudes.find(s=>s.id===solId);
    if(sol){
      const solUpd={...sol,rutaId};
      setSolicitudes(solicitudes.map(s=>s.id===solId?solUpd:s));
      await onSaveSolicitud(solUpd);
    }
  }

  async function quitarParada(rutaId, solId){
    const upd=rutas.map(r=>{
      if(r.id!==rutaId)return r;
      return {...r,paradas:r.paradas.filter(p=>p.solId!==solId)};
    });
    setRutas(upd);
    const ruta=upd.find(r=>r.id===rutaId);
    if(ruta) await onSaveRuta(ruta);
    const sol=solicitudes.find(s=>s.id===solId);
    if(sol){
      const solUpd={...sol,rutaId:null};
      setSolicitudes(solicitudes.map(s=>s.id===solId?solUpd:s));
      await onSaveSolicitud(solUpd);
    }
  }

  async function moverParada(rutaId, solId, dir){
    const ruta=rutas.find(r=>r.id===rutaId);
    if(!ruta)return;
    const idx=ruta.paradas.findIndex(p=>p.solId===solId);
    if((dir===-1&&idx===0)||(dir===1&&idx===ruta.paradas.length-1))return;
    const paradas=[...ruta.paradas];
    [paradas[idx],paradas[idx+dir]]=[paradas[idx+dir],paradas[idx]];
    paradas.forEach((p,i)=>p.orden=i+1);
    const upd=rutas.map(r=>r.id===rutaId?{...r,paradas}:r);
    setRutas(upd);
    await onSaveRuta(upd.find(r=>r.id===rutaId));
  }

  async function cambiarVehiculo(rutaId, vehiculo){
    const upd=rutas.map(r=>r.id===rutaId?{...r,vehiculo}:r);
    setRutas(upd);
    await onSaveRuta(upd.find(r=>r.id===rutaId));
  }

  async function calcularKmRuta(rutaId){
    const ruta=rutas.find(r=>r.id===rutaId);
    if(!ruta||ruta.paradas.length===0)return;
    setKmCalculando(rutaId);
    const paradaSols=ruta.paradas.map(p=>solicitudes.find(s=>s.id===p.solId)).filter(Boolean);
    
    let total=0;
    let origen=ORIGEN_PUDAHUEL;
    let primera=true;

    for(const s of paradaSols){
      if(!s.direccion)continue;
      
      if(primera){
        primera=false;
        if(s.tipo==="carga_ol"){
          // Carga OL: siempre es punto de salida desde Pudahuel, nunca destino
          origen=ORIGEN_PUDAHUEL;
          continue;
        } else if(s.tipo==="li_retiro"){
          // LI Retiro como primera parada: es el origen de la ruta
          origen=s.direccion+", Chile";
          continue;
        }
        // LI Devolución, Entrega/Despacho: siempre cuentan como destino
      }
      
      // Calcular distancia desde el origen actual hasta este destino
      const destCoords=await coordsSolicitud(s);
      let origenCoords;
      if(origen===ORIGEN_PUDAHUEL){
        origenCoords=PUDAHUEL_COORDS;
      } else {
        origenCoords=await geocodificar(origen.replace(", Chile",""));
      }
      if(destCoords&&origenCoords){
        const km=haversineKm(origenCoords.lat,origenCoords.lon,destCoords.lat,destCoords.lon);
        total+=parseFloat(km);
      }
      origen=s.direccion+", Chile";
    }
    
    const upd=rutas.map(r=>r.id===rutaId?{...r,kmTotal:total.toFixed(1)}:r);
    setRutas(upd);
    await onSaveRuta(upd.find(r=>r.id===rutaId));
    setKmCalculando(null);
  }

  const perfil=sesion?.perfil;
  const puedeReabrir=perfil==="admin";

  async function cerrarRutaManual(rutaId){
    const ruta=rutas.find(r=>r.id===rutaId);
    if(!ruta)return;
    if((ruta.paradas||[]).length===0){window.alert("La ruta no tiene paradas, no se puede cerrar.");return;}
    const pendientes=ruta.paradas.map(p=>solicitudes.find(s=>s.id===p.solId)).filter(Boolean)
      .filter(s=>!ESTADOS_TERMINALES.includes(s.status));
    if(pendientes.length>0 && !window.confirm(`Hay ${pendientes.length} parada(s) sin finalizar. ¿Cerrar la ruta de todas formas?`))return;
    const nr={...ruta,estado:"cerrada",cerradaAt:new Date().toISOString(),cerradaPor:sesion?.nombre||perfil||"Manual"};
    setRutas(rutas.map(r=>r.id===rutaId?nr:r));
    await onSaveRuta(nr);
  }

  async function reabrirRuta(rutaId){
    if(perfil!=="admin"){window.alert("Solo un administrador puede reabrir una ruta.");return;}
    const ruta=rutas.find(r=>r.id===rutaId);
    if(!ruta)return;
    const motivo=(window.prompt("Motivo de la reapertura (queda registrado):")||"").trim();
    if(!motivo){window.alert("Debes indicar un motivo para reabrir la ruta.");return;}
    const now=new Date();
    const sello=now.toLocaleDateString("es-CL")+" "+now.toLocaleTimeString("es-CL",{hour:"2-digit",minute:"2-digit",hour12:false});
    const reaperturas=[...(ruta.reaperturas||[]),{fecha:sello,usuario:sesion?.nombre||"Admin",motivo}];
    const nr={...ruta,estado:"abierta",cerradaAt:null,cerradaPor:null,reaperturas};
    setRutas(rutas.map(r=>r.id===rutaId?nr:r));
    await onSaveRuta(nr);
  }

  const rutaActiva=rutaDetalle?rutas.find(r=>r.id===rutaDetalle):null;
  const solsDisponibles=solicitudes.filter(s=>(!s.rutaId||s.rutaId===rutaDetalle) && solRutable(s));

  return(
    <div style={S.section}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={S.pageTitle}>Gestión de Rutas</div>
        <button style={S.btnPri} onClick={()=>{setFormRuta(p=>({...p,fecha:hoy,vehiculo:vehiculoDefault}));setNuevaRuta(true);}}>+ Nueva Ruta</button>
      </div>

      {nuevaRuta&&(
        <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px"}}>
          <div style={{fontWeight:700,color:C.cyan,marginBottom:12}}>Nueva Ruta — {generarIdRuta()}</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div style={S.fGroup}><label style={S.label}>Fecha</label>
              <input style={S.input} type="date" value={formRuta.fecha} onChange={e=>setFormRuta(p=>({...p,fecha:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Vehículo</label>
              <select style={S.input} value={formRuta.vehiculo} onChange={e=>setFormRuta(p=>({...p,vehiculo:e.target.value}))}>
                {opcionesVehiculo.length===0
                  ? <option value="">Sin vehículos — agrégalos en Gestión de Usuarios</option>
                  : opcionesVehiculo.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}
              </select></div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
            <button style={S.btnSec} onClick={()=>setNuevaRuta(false)}>Cancelar</button>
            <button style={S.btnPri} onClick={crearRuta}>Crear Ruta</button>
          </div>
        </div>
      )}

      {/* Lista de rutas */}
      {rutas.length===0&&!nuevaRuta&&<EmptyState msg="No hay rutas creadas aún."/>}
      {rutas.map(r=>{
        const veh=resolverVehiculo(r.vehiculo);
        const isOpen=rutaDetalle===r.id;
        const paradaSols=r.paradas.map(p=>solicitudes.find(s=>s.id===p.solId)).filter(Boolean);
        const listaParaCerrar=paradaSols.length>0&&paradaSols.every(s=>ESTADOS_TERMINALES.includes(s.status));
        const estaCerrada=(r.estado||"abierta")==="cerrada";
        return(
          <div key={r.id} style={{background:C.navySurface,border:"1px solid "+(isOpen?C.cyan:C.border),borderRadius:12,overflow:"hidden"}}>
            {/* Header ruta */}
            <div style={{padding:"14px 16px",display:"flex",alignItems:"center",gap:12,cursor:"pointer"}} onClick={()=>setRutaDetalle(isOpen?null:r.id)}>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                  <span style={{fontWeight:800,fontSize:14}}>{r.id}</span>
                  <span style={{fontSize:13,color:C.textSecondary}}>{r.nombre}</span>
                  <span style={{fontSize:11,background:C.cyan+"22",color:C.cyan,padding:"2px 8px",borderRadius:6,fontWeight:700}}>{veh.label||r.vehiculo}</span>
                  <span style={{fontSize:11,background:(estaCerrada?"#22C55E":"#F59E0B")+"22",color:estaCerrada?"#22C55E":"#F59E0B",padding:"2px 8px",borderRadius:6,fontWeight:700}}>{estaCerrada?"✓ Cerrada":"Abierta"}</span>
                  {!estaCerrada&&listaParaCerrar&&<span style={{fontSize:11,background:"#22C55E22",color:"#22C55E",padding:"2px 8px",borderRadius:6,fontWeight:700}}>Lista para cerrar</span>}
                </div>
                <div style={{fontSize:12,color:C.muted,marginTop:2}}>{r.fecha} · {r.paradas.length} parada(s){r.kmTotal?` · ${r.kmTotal} km`:""}</div>
              </div>
              <div style={{display:"flex",gap:6}}>
                {!estaCerrada&&<button style={{...S.exportBtn,fontSize:11}} onClick={e=>{e.stopPropagation();eliminarRuta(r.id);}}>✕</button>}
                <span style={{color:C.muted,fontSize:16}}>{isOpen?"▲":"▼"}</span>
              </div>
            </div>

            {/* Detalle ruta */}
            {isOpen&&(
              <div style={{borderTop:"1px solid "+C.border,padding:"14px 16px",display:"flex",flexDirection:"column",gap:12}}>
                {/* Acciones de cierre / reapertura */}
                <div style={{display:"flex",alignItems:"center",gap:10,flexWrap:"wrap"}}>
                  {!estaCerrada
                    ? <button style={{...S.btnPri,fontSize:13}} onClick={()=>cerrarRutaManual(r.id)}>🔒 Cerrar ruta</button>
                    : (<>
                        <button style={{...S.btnSec,fontSize:13,opacity:puedeReabrir?1:.5,cursor:puedeReabrir?"pointer":"not-allowed"}} disabled={!puedeReabrir} onClick={()=>reabrirRuta(r.id)}>🔓 Reabrir ruta</button>
                        {!puedeReabrir&&<span style={{fontSize:11,color:C.muted}}>Solo un administrador puede reabrir.</span>}
                      </>)
                  }
                </div>
                {estaCerrada&&(
                  <div style={{background:C.navy,borderRadius:8,padding:"10px 12px",fontSize:12,color:C.textSecondary}}>
                    Ruta cerrada{r.cerradaPor?` por ${r.cerradaPor}`:""}{r.cerradaAt?` · ${new Date(r.cerradaAt).toLocaleString("es-CL")}`:""}. Edición bloqueada.
                    {(r.reaperturas||[]).length>0&&(
                      <div style={{marginTop:8}}>
                        <div style={{fontSize:11,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>Reaperturas registradas</div>
                        {(r.reaperturas||[]).map((re,i)=>(
                          <div key={i} style={{fontSize:11,color:C.muted,marginBottom:2}}>• {re.fecha} — {re.usuario}: {re.motivo}</div>
                        ))}
                      </div>
                    )}
                  </div>
                )}
                {!estaCerrada&&(
                <div style={{display:"flex",alignItems:"center",gap:10,flexWrap:"wrap"}}>
                  <label style={{...S.label,marginBottom:0}}>Vehículo:</label>
                  {opcionesVehiculo.length===0
                    ? <span style={{fontSize:12,color:C.muted}}>Sin vehículos registrados (Gestión de Usuarios → Vehículos)</span>
                    : opcionesVehiculo.map(o=>(
                    <button key={o.value} style={{...S.statusBtn,background:resolverVehiculo(r.vehiculo).value===o.value?C.cyan+"33":"transparent",border:"1px solid "+(resolverVehiculo(r.vehiculo).value===o.value?C.cyan:C.border),color:resolverVehiculo(r.vehiculo).value===o.value?C.cyan:C.muted,fontSize:12}}
                      onClick={()=>cambiarVehiculo(r.id,o.value)}>{o.label}</button>
                  ))}
                </div>
                )}

                {/* Paradas */}
                <div>
                  <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase",marginBottom:8}}>Paradas en orden</div>
                  {paradaSols.length===0&&<div style={{fontSize:12,color:C.muted}}>Sin paradas. Agrega solicitudes abajo.</div>}
                  {paradaSols.map((s,i)=>{
                    const tm=TYPE_META[s.tipo]||{label:s.tipo,icon:"·",color:"#6B8CAE"};
                    return(
                      <div key={s.id} style={{background:C.navy,borderRadius:8,padding:"10px 12px",marginBottom:6,display:"flex",alignItems:"center",gap:10}}>
                        <span style={{fontSize:18,fontWeight:900,color:C.cyan,minWidth:24}}>{i+1}</span>
                        <div style={{...S.rowIcon,background:tm.color+"22",color:tm.color,width:28,height:28,fontSize:14,flexShrink:0}}>{tm.icon}</div>
                        <div style={{flex:1,minWidth:0}}>
                          <div style={{fontSize:12,fontWeight:700,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{s.titulo}</div>
                          <div style={{fontSize:11,color:C.muted}}>{s.direccion||"Sin dirección"}</div>
                          <div style={{fontSize:10,fontWeight:700,color:STATUS_META[s.status]?.color||C.muted,marginTop:2}}>{STATUS_META[s.status]?.label||s.status}</div>
                        </div>
                        {!estaCerrada&&(
                        <div style={{display:"flex",gap:4,flexShrink:0}}>
                          <button style={{...S.statusBtn,fontSize:12,padding:"4px 8px"}} onClick={()=>moverParada(r.id,s.id,-1)} disabled={i===0}>↑</button>
                          <button style={{...S.statusBtn,fontSize:12,padding:"4px 8px"}} onClick={()=>moverParada(r.id,s.id,1)} disabled={i===paradaSols.length-1}>↓</button>
                          <button style={{...S.statusBtn,fontSize:11,padding:"4px 8px",border:"1px solid "+C.danger,color:C.danger}} onClick={()=>quitarParada(r.id,s.id)}>✕</button>
                        </div>
                        )}
                      </div>
                    );
                  })}
                </div>

                {!estaCerrada&&(<>
                {/* Agregar parada */}
                <div>
                  <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase",marginBottom:8}}>Agregar solicitud a la ruta</div>
                  <select style={S.input} value="" onChange={e=>{if(e.target.value)agregarParada(r.id,e.target.value);}}>
                    <option value="">-- Seleccionar solicitud --</option>
                    {solicitudes.filter(s=>(!s.rutaId||s.rutaId===r.id)&&!r.paradas.find(p=>p.solId===s.id)&&solRutable(s)).map(s=>(
                      <option key={s.id} value={s.id}>{s.ot||s.id} · {s.titulo} · {s.fecha}</option>
                    ))}
                  </select>
                </div>

                {/* Calcular km */}
                {paradaSols.length>0&&(
                  <div style={{display:"flex",alignItems:"center",gap:12}}>
                    <button style={{...S.exportBtn,fontSize:12}} disabled={kmCalculando===r.id} onClick={()=>calcularKmRuta(r.id)}>
                      {kmCalculando===r.id?"Calculando...":"🗺 Calcular km de la ruta"}
                    </button>
                    {r.kmTotal&&<span style={{fontSize:16,fontWeight:900,color:C.cyan}}>{r.kmTotal} km totales</span>}
                  </div>
                )}
                </>)}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}


// ── Admin Usuarios ─────────────────────────────────────────────────────────
function AdminUsuarios({usuarios,choferes,vehiculos=[],onSave,onDesbloquearUsuario,setView}){
  const [listaU,setListaU]=useState(usuarios.filter(u=>u.perfil!=="admin"));
  const [listaC,setListaC]=useState(choferes);
  const [tab,setTab]=useState("operadores");
  const [editU,setEditU]=useState(null);
  const [editC,setEditC]=useState(null);
  const [formU,setFormU]=useState({email:"",password:"",nombre:"",perfil:"operador"});
  const [formC,setFormC]=useState({nombre:"",ppu:"",usuarioDT:"Quantrex M1"});
  const [nuevoU,setNuevoU]=useState(false);
  const [nuevoC,setNuevoC]=useState(false);
  const [listaV,setListaV]=useState(vehiculos);
  const [editV,setEditV]=useState(null);
  const [nuevoV,setNuevoV]=useState(false);
  const [formV,setFormV]=useState({ppu:"",marca:"",modelo:"",anio:"",capacidadM3:"",capacidadKg:""});
  const [autollenado,setAutollenado]=useState(false);

  function guardarOperador(){
    if(!formU.email||!formU.password||!formU.nombre)return;
    const upd=editU!==null
      ?listaU.map((u,i)=>i===editU?{...formU}:u)
      :[...listaU,{...formU}];
    setListaU(upd);
    const todosUsuarios=[usuarios.find(u=>u.perfil==="admin"),...upd,{email:"info@transportesbs.cl",password:"libre2026",perfil:"cliente",nombre:"Abbott Chile"}];
    onSave(todosUsuarios);
    setEditU(null);setNuevoU(false);setFormU({email:"",password:"",nombre:"",perfil:"operador"});
  }

  function eliminarOperador(i){
    if(!window.confirm("¿Eliminar este usuario?"))return;
    const upd=listaU.filter((_,j)=>j!==i);
    setListaU(upd);
    const todosUsuarios=[usuarios.find(u=>u.perfil==="admin"),...upd,{email:"info@transportesbs.cl",password:"libre2026",perfil:"cliente",nombre:"Abbott Chile"}];
    onSave(todosUsuarios);
  }

  return(
    <div style={S.section}>
      <div style={S.pageTitle}>Gestión de Usuarios</div>
      <div style={{display:"flex",gap:8,marginBottom:4,flexWrap:"wrap"}}>
        {[["operadores","👤 Operadores"],["clientes_acc","🏢 Clientes"],["choferes","🚗 Choferes"],["vehiculos","🚚 Vehículos"]].map(([id,label])=>(
          <button key={id} style={{...S.statusBtn,background:tab===id?C.cyan+"33":"transparent",border:"1px solid "+(tab===id?C.cyan:C.border),color:tab===id?C.cyan:C.muted,fontWeight:700,fontSize:13}}
            onClick={()=>setTab(id)}>{label}</button>
        ))}
      </div>

      {tab==="operadores"&&(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"flex",justifyContent:"flex-end"}}>
            <button style={S.btnPri} onClick={()=>{setNuevoU(true);setEditU(null);setFormU({email:"",password:"",nombre:"",perfil:"operador"});}}>+ Nuevo operador</button>
          </div>
          {(nuevoU||editU!==null)&&(
            <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px"}}>
              <div style={{fontWeight:700,color:C.cyan,marginBottom:12}}>{editU!==null?"Editar operador":"Nuevo operador"}</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div style={S.fGroup}><label style={S.label}>Nombre</label>
                  <input style={S.input} value={formU.nombre} onChange={e=>setFormU(p=>({...p,nombre:e.target.value}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Email</label>
                  <input style={S.input} type="email" value={formU.email} onChange={e=>setFormU(p=>({...p,email:e.target.value}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Contraseña</label>
                  <input style={S.input} type="text" value={formU.password} onChange={e=>setFormU(p=>({...p,password:e.target.value}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Perfil</label>
                  <select style={S.input} value={formU.perfil} onChange={e=>setFormU(p=>({...p,perfil:e.target.value}))}>
                    <option value="operador">Operador</option>
                    <option value="cliente">Cliente (solo lectura)</option>
                  </select></div>
              </div>
              <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
                <button style={S.btnSec} onClick={()=>{setNuevoU(false);setEditU(null);}}>Cancelar</button>
                <button style={S.btnPri} onClick={guardarOperador}>Guardar</button>
              </div>
            </div>
          )}
          {listaU.map((u,i)=>(
            <div key={i} style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:10,padding:"12px 16px",display:"flex",alignItems:"center",gap:12}}>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:13}}>{u.nombre}</div>
                <div style={{fontSize:12,color:C.muted}}>{u.email} · <span style={{color:C.cyan}}>{u.perfil}</span></div>
              </div>
              <div style={{display:"flex",gap:6}}>
                <button style={{...S.exportBtn,fontSize:11}} onClick={()=>{setEditU(i);setNuevoU(false);setFormU({...u});}}>✎ Editar</button>
                <button style={{...S.exportBtn,fontSize:11,borderColor:C.danger,color:C.danger}} onClick={()=>eliminarOperador(i)}>✕</button>
              </div>
            </div>
          ))}
          {listaU.length===0&&!nuevoU&&<EmptyState msg="No hay operadores registrados."/>}
        </div>
      )}

      {tab==="clientes_acc"&&(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"flex",justifyContent:"flex-end"}}>
            <button style={S.btnPri} onClick={()=>{setNuevoU(true);setEditU(null);setFormU({email:"",password:"",nombre:"",perfil:"cliente"});}}>+ Nuevo cliente</button>
          </div>
          {(nuevoU&&formU.perfil==="cliente"||editU!==null&&listaU[editU]?.perfil==="cliente")&&(
            <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px"}}>
              <div style={{fontWeight:700,color:C.cyan,marginBottom:12}}>{editU!==null?"Editar cliente":"Nuevo cliente"}</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div style={S.fGroup}><label style={S.label}>Nombre / Empresa</label>
                  <input style={S.input} value={formU.nombre} onChange={e=>setFormU(p=>({...p,nombre:e.target.value}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Email</label>
                  <input style={S.input} type="email" value={formU.email} onChange={e=>setFormU(p=>({...p,email:e.target.value}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Contraseña</label>
                  <input style={S.input} type="text" value={formU.password} onChange={e=>setFormU(p=>({...p,password:e.target.value}))}/></div>
              </div>
              <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
                <button style={S.btnSec} onClick={()=>{setNuevoU(false);setEditU(null);}}>Cancelar</button>
                <button style={S.btnPri} onClick={()=>{setFormU(p=>({...p,perfil:"cliente"}));guardarOperador();}}>Guardar</button>
              </div>
            </div>
          )}
          {usuarios.filter(u=>u.perfil==="cliente").map((u,i)=>{
            const dias=diasInactividadUsuario(u);
            const cambio=debeCambiarPassword(u);
            return(
              <div key={i} style={{background:C.navySurface,border:"1px solid "+(u.bloqueado?C.danger:cambio?C.warning:C.border),borderRadius:10,padding:"12px 16px",display:"flex",flexDirection:"column",gap:8}}>
                <div style={{display:"flex",alignItems:"center",gap:12}}>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:700,fontSize:13}}>{u.nombre}</div>
                    <div style={{fontSize:12,color:C.muted}}>{u.email}</div>
                  </div>
                  <div style={{display:"flex",gap:6}}>
                    {u.bloqueado&&<button style={{...S.exportBtn,fontSize:11,borderColor:C.success,color:C.success}} onClick={()=>onDesbloquearUsuario?.(u.email)}>🔓 Desbloquear</button>}
                    <button style={{...S.exportBtn,fontSize:11}} onClick={()=>{
                      const idx=listaU.findIndex(lu=>lu.email===u.email);
                      if(idx>=0){setEditU(idx);setNuevoU(false);setFormU({...u});}
                      else{setNuevoU(true);setEditU(null);setFormU({...u});}
                      setTab("clientes_acc");
                    }}>✎ Editar</button>
                  </div>
                </div>
                <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
                  {u.bloqueado&&<div style={{background:C.danger+"22",border:"1px solid "+C.danger,borderRadius:6,padding:"4px 10px",fontSize:11,color:C.danger,fontWeight:700}}>
                    🔒 Bloqueado por inactividad ({DIAS_INACTIVIDAD_BLOQUEO}+ días sin acceder)
                  </div>}
                  <div style={{background:dias===null?"#333":dias>7?C.danger+"22":C.success+"22",border:"1px solid "+(dias===null?"#555":dias>7?C.danger:C.success),borderRadius:6,padding:"4px 10px",fontSize:11,color:dias===null?C.muted:dias>7?C.danger:C.success,fontWeight:700}}>
                    {dias===null?"Sin accesos registrados":dias===0?"Accedió hoy":dias===1?"Hace 1 día":dias+" días sin acceder"}
                  </div>
                  {cambio&&<div style={{background:C.warning+"22",border:"1px solid "+C.warning,borderRadius:6,padding:"4px 10px",fontSize:11,color:C.warning,fontWeight:700}}>
                    ⚠ Debe cambiar contraseña este mes
                  </div>}
                </div>
              </div>
            );
          })}
          {usuarios.filter(u=>u.perfil==="cliente").length===0&&!nuevoU&&<EmptyState msg="No hay clientes registrados."/>}
        </div>
      )}

      {tab==="choferes"&&(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"flex",justifyContent:"flex-end"}}>
            <button style={S.btnPri} onClick={()=>{setNuevoC(true);setEditC(null);setFormC({nombre:"",ppu:"",usuarioDT:"Quantrex M1",pin:"1981"});}}>+ Nuevo chofer</button>
          </div>
          {(nuevoC||editC!==null)&&(
            <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px"}}>
              <div style={{fontWeight:700,color:C.cyan,marginBottom:12}}>{editC!==null?"Editar chofer":"Nuevo chofer"}</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>
                <div style={S.fGroup}><label style={S.label}>Nombre</label>
                  <input style={S.input} value={formC.nombre} onChange={e=>setFormC(p=>({...p,nombre:e.target.value}))}/></div>
                <div style={S.fGroup}><label style={S.label}>PPU</label>
                  <input style={S.input} placeholder="Ej: KRYX27" value={formC.ppu} onChange={e=>setFormC(p=>({...p,ppu:e.target.value.toUpperCase()}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Usuario DT</label>
                  <select style={S.input} value={formC.usuarioDT} onChange={e=>setFormC(p=>({...p,usuarioDT:e.target.value}))}>
                    <option>Quantrex M1</option>
                    <option>Quantrex M2</option>
                  </select></div>
                <div style={S.fGroup}><label style={S.label}>PIN (4 dígitos)</label>
                  <input style={S.input} inputMode="numeric" maxLength={4} placeholder="Ej: 1981" value={formC.pin||""}
                    onChange={e=>setFormC(p=>({...p,pin:e.target.value.replace(/\D/g,"").slice(0,4)}))}/></div>
              </div>
              <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
                <button style={S.btnSec} onClick={()=>{setNuevoC(false);setEditC(null);}}>Cancelar</button>
                <button style={S.btnPri} onClick={()=>{
                  if(!formC.nombre||!formC.ppu)return;
                  if(!formC.pin||formC.pin.length!==4){return;}
                  const upd=editC!==null?listaC.map((c,i)=>i===editC?{...formC}:c):[...listaC,{...formC}];
                  setListaC(upd);setNuevoC(false);setEditC(null);
                  onSave(null,upd);
                }}>Guardar</button>
              </div>
            </div>
          )}
          {listaC.map((c,i)=>(
            <div key={i} style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:10,padding:"12px 16px",display:"flex",alignItems:"center",gap:12}}>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:13}}>{c.nombre}</div>
                <div style={{fontSize:12,color:C.muted}}>PPU: {c.ppu} · {c.usuarioDT} · PIN: {c.pin||"—"}</div>
              </div>
              <div style={{display:"flex",gap:6}}>
                <button style={{...S.exportBtn,fontSize:11}} onClick={()=>{setEditC(i);setNuevoC(false);setFormC({...c});}}>✎ Editar</button>
                <button style={{...S.exportBtn,fontSize:11,borderColor:C.danger,color:C.danger}} onClick={()=>{const upd=listaC.filter((_,j)=>j!==i);setListaC(upd);onSave(null,upd);}}>✕</button>
              </div>
            </div>
          ))}
          {listaC.length===0&&!nuevoC&&<EmptyState msg="No hay choferes registrados."/>}
        </div>
      )}

      {tab==="vehiculos"&&(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"flex",justifyContent:"flex-end"}}>
            <button style={S.btnPri} onClick={()=>{setNuevoV(true);setEditV(null);setAutollenado(false);setFormV({ppu:"",marca:"",modelo:"",anio:"",capacidadM3:"",capacidadKg:""});}}>+ Nuevo vehículo</button>
          </div>
          {(nuevoV||editV!==null)&&(()=>{
            const sugerencia=buscarCapacidad(formV.marca,formV.modelo);
            const aplicarSugerencia=()=>{
              if(!sugerencia)return;
              setFormV(p=>({...p,capacidadM3:String(sugerencia.m3),capacidadKg:String(sugerencia.kg)}));
              setAutollenado(true);
            };
            return(
            <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px"}}>
              <div style={{fontWeight:700,color:C.cyan,marginBottom:12}}>{editV!==null?"Editar vehículo":"Nuevo vehículo"}</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>
                <div style={S.fGroup}><label style={S.label}>PPU (patente)</label>
                  <input style={S.input} placeholder="Ej: KRYX27" value={formV.ppu} onChange={e=>setFormV(p=>({...p,ppu:e.target.value.toUpperCase().replace(/\s/g,"")}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Marca</label>
                  <input style={S.input} placeholder="Ej: Hyundai" value={formV.marca}
                    onChange={e=>{setAutollenado(false);setFormV(p=>({...p,marca:e.target.value}));}}/></div>
                <div style={S.fGroup}><label style={S.label}>Modelo</label>
                  <input style={S.input} placeholder="Ej: Porter" value={formV.modelo}
                    onChange={e=>{setAutollenado(false);setFormV(p=>({...p,modelo:e.target.value}));}}/></div>
                <div style={S.fGroup}><label style={S.label}>Año</label>
                  <input style={S.input} inputMode="numeric" maxLength={4} placeholder="Ej: 2022" value={formV.anio}
                    onChange={e=>setFormV(p=>({...p,anio:e.target.value.replace(/\D/g,"").slice(0,4)}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Capacidad (m³)</label>
                  <input style={S.input} inputMode="decimal" placeholder="Ej: 3.5" value={formV.capacidadM3}
                    onChange={e=>setFormV(p=>({...p,capacidadM3:e.target.value.replace(/[^\d.]/g,"")}))}/></div>
                <div style={S.fGroup}><label style={S.label}>Carga útil (kg)</label>
                  <input style={S.input} inputMode="numeric" placeholder="Ej: 1000" value={formV.capacidadKg}
                    onChange={e=>setFormV(p=>({...p,capacidadKg:e.target.value.replace(/\D/g,"")}))}/></div>
              </div>
              {sugerencia&&(
                <div style={{marginTop:10,background:C.cyan+"15",border:"1px solid "+C.cyan+"55",borderRadius:8,padding:"8px 12px",display:"flex",alignItems:"center",gap:10,flexWrap:"wrap"}}>
                  <span style={{fontSize:12,color:C.textSecondary}}>Capacidad referencial encontrada: <b style={{color:C.cyan}}>{sugerencia.m3} m³ · {sugerencia.kg} kg</b></span>
                  <button style={{...S.exportBtn,fontSize:11}} onClick={aplicarSugerencia}>Autocompletar</button>
                  {autollenado&&<span style={{fontSize:11,color:C.success}}>✓ aplicado (puedes ajustarlo)</span>}
                </div>
              )}
              <div style={{fontSize:11,color:C.muted,marginTop:8}}>Las capacidades son referenciales por marca/modelo. Verifica con el padrón del vehículo y ajústalas si es necesario.</div>
              <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
                <button style={S.btnSec} onClick={()=>{setNuevoV(false);setEditV(null);}}>Cancelar</button>
                <button style={S.btnPri} onClick={()=>{
                  if(!formV.ppu){window.alert("La PPU es obligatoria.");return;}
                  const dup=listaV.findIndex(v=>v.ppu===formV.ppu);
                  if(editV===null&&dup>=0){window.alert("Ya existe un vehículo con esa PPU.");return;}
                  const upd=editV!==null?listaV.map((v,i)=>i===editV?{...formV}:v):[...listaV,{...formV}];
                  setListaV(upd);setNuevoV(false);setEditV(null);
                  onSave(null,null,upd);
                }}>Guardar</button>
              </div>
            </div>
            );
          })()}
          {listaV.map((v,i)=>(
            <div key={i} style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:10,padding:"12px 16px",display:"flex",alignItems:"center",gap:12}}>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:13}}>{v.ppu} {(v.marca||v.modelo)?<span style={{color:C.muted,fontWeight:500}}>· {[v.marca,v.modelo,v.anio].filter(Boolean).join(" ")}</span>:null}</div>
                <div style={{fontSize:12,color:C.muted}}>
                  {v.capacidadM3?`${v.capacidadM3} m³`:"m³ —"} · {v.capacidadKg?`${Number(v.capacidadKg).toLocaleString("es-CL")} kg`:"kg —"}
                </div>
              </div>
              <div style={{display:"flex",gap:6}}>
                <button style={{...S.exportBtn,fontSize:11}} onClick={()=>{setEditV(i);setNuevoV(false);setAutollenado(false);setFormV({ppu:v.ppu||"",marca:v.marca||"",modelo:v.modelo||"",anio:v.anio||"",capacidadM3:v.capacidadM3===""||v.capacidadM3==null?"":String(v.capacidadM3),capacidadKg:v.capacidadKg===""||v.capacidadKg==null?"":String(v.capacidadKg)});}}>✎ Editar</button>
                <button style={{...S.exportBtn,fontSize:11,borderColor:C.danger,color:C.danger}} onClick={()=>{if(!window.confirm("¿Eliminar este vehículo?"))return;const upd=listaV.filter((_,j)=>j!==i);setListaV(upd);onSave(null,null,upd);}}>✕</button>
              </div>
            </div>
          ))}
          {listaV.length===0&&!nuevoV&&<EmptyState msg="No hay vehículos registrados."/>}
        </div>
      )}
    </div>
  );
}

// ── Admin Clientes ─────────────────────────────────────────────────────────
function AdminClientes({clientes,onSave,setView}){
  const [lista,setLista]=useState(clientes.map(c=>({...c,sucursales:c.sucursales||[]})));
  const [editIdx,setEditIdx]=useState(null);
  const [editData,setEditData]=useState(null);
  const [hayambios,setHayCambios]=useState(false);
  const [buscar,setBuscar]=useState("");
  const [mostrarNuevo,setMostrarNuevo]=useState(false);
  const [nuevoCliente,setNuevoCliente]=useState({id:"",nombre:"",direccion:"",notas:"",sucursales:[]});

  const filtrados=lista.filter(c=>c.nombre.toLowerCase().includes(buscar.toLowerCase())||c.id.includes(buscar));

  function iniciarEdit(idx){
    setEditIdx(idx);
    setEditData({...lista[idx],sucursales:[...(lista[idx].sucursales||[])]});
  }

  function guardarEdit(){
    const nueva=[...lista];
    nueva[editIdx]=editData;
    setLista(nueva); setEditIdx(null); setEditData(null); setHayCambios(true);
  }

  function eliminarCliente(idx){
    if(!window.confirm("¿Eliminar este cliente?"))return;
    const nueva=lista.filter((_,i)=>i!==idx);
    setLista(nueva); setHayCambios(true);
  }

  function agregarSucursal(){
    setEditData(p=>({...p,sucursales:[...p.sucursales,{nombre:"",direccion:"",notas:""}]}));
  }

  function editarSucursal(i,k,v){
    setEditData(p=>{const s=[...p.sucursales];s[i]={...s[i],[k]:v};return{...p,sucursales:s};});
  }

  function eliminarSucursal(i){
    setEditData(p=>({...p,sucursales:p.sucursales.filter((_,j)=>j!==i)}));
  }

  function agregarNuevo(){
    if(!nuevoCliente.nombre.trim()){alert("El nombre es obligatorio.");return;}
    setLista(p=>[...p,{...nuevoCliente}]);
    setNuevoCliente({id:"",nombre:"",direccion:"",notas:"",sucursales:[]});
    setMostrarNuevo(false); setHayCambios(true);
  }

  async function handleGuardar(){
    await onSave(lista);
    setHayCambios(false);
    alert("✓ Clientes guardados correctamente.");
  }

  return(
    <div style={S.section}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={S.pageTitle}>Administrar Clientes</div>
        <div style={{display:"flex",gap:8}}>
          {hayambios&&<button style={{...S.btnPri,fontSize:13}} onClick={handleGuardar}>💾 Guardar cambios</button>}
          <button style={{...S.exportBtn,fontSize:13}} onClick={()=>setMostrarNuevo(true)}>+ Nuevo cliente</button>
        </div>
      </div>

      {hayambios&&<div style={{background:"#3A2000",border:"1px solid "+C.warning,borderRadius:8,padding:"10px 14px",fontSize:12,color:C.warning,fontWeight:600}}>
        ⚠ Tienes cambios sin guardar. Haz clic en "Guardar cambios" para aplicarlos.
      </div>}

      <input style={S.searchInput} placeholder="Buscar cliente por nombre o ID..." value={buscar} onChange={e=>setBuscar(e.target.value)}/>

      {mostrarNuevo&&(
        <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px"}}>
          <div style={{fontWeight:700,color:C.cyan,marginBottom:12,fontSize:13}}>Nuevo cliente</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div style={S.fGroup}><label style={S.label}>ID (RUT)</label>
              <input style={S.input} value={nuevoCliente.id} onChange={e=>setNuevoCliente(p=>({...p,id:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Nombre *</label>
              <input style={S.input} value={nuevoCliente.nombre} onChange={e=>setNuevoCliente(p=>({...p,nombre:e.target.value}))}/></div>
            <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Dirección</label>
              <input style={S.input} value={nuevoCliente.direccion} onChange={e=>setNuevoCliente(p=>({...p,direccion:e.target.value}))}/></div>
            <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Notas</label>
              <input style={S.input} value={nuevoCliente.notas} onChange={e=>setNuevoCliente(p=>({...p,notas:e.target.value}))}/></div>
          </div>
          <div style={{display:"flex",gap:8,marginTop:12,justifyContent:"flex-end"}}>
            <button style={S.btnSec} onClick={()=>setMostrarNuevo(false)}>Cancelar</button>
            <button style={S.btnPri} onClick={agregarNuevo}>Agregar</button>
          </div>
        </div>
      )}

      {filtrados.map((c,i)=>{
        const idxReal=lista.indexOf(c);
        const enEdicion=editIdx===idxReal;
        return(
          <div key={i} style={{background:C.navySurface,border:"1px solid "+(enEdicion?C.cyan:C.border),borderRadius:12,padding:"14px 16px",display:"flex",flexDirection:"column",gap:10}}>
            {!enEdicion?(
              <>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,flexWrap:"wrap"}}>
                  <div>
                    <div style={{fontWeight:700,fontSize:14}}>{c.id&&<span style={{color:C.muted,marginRight:6}}>{c.id}</span>}{c.nombre}</div>
                    {c.direccion&&<div style={{fontSize:12,color:C.textSecondary,marginTop:2}}>📍 {c.direccion}</div>}
                    {c.notas&&<div style={{fontSize:12,color:C.muted,marginTop:1}}>💬 {c.notas}</div>}
                    {c.sucursales?.length>0&&<div style={{fontSize:11,color:C.cyan,marginTop:2}}>🏢 {c.sucursales.length} sucursal(es)</div>}
                  </div>
                  <div style={{display:"flex",gap:6}}>
                    <button style={{...S.exportBtn,fontSize:11}} onClick={()=>iniciarEdit(idxReal)}>✎ Editar</button>
                    <button style={{...S.exportBtn,fontSize:11,borderColor:C.danger,color:C.danger}} onClick={()=>eliminarCliente(idxReal)}>✕</button>
                  </div>
                </div>
              </>
            ):(
              <>
                <div style={{fontWeight:700,color:C.cyan,fontSize:13}}>Editando: {c.nombre}</div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                  <div style={S.fGroup}><label style={S.label}>ID (RUT)</label>
                    <input style={S.input} value={editData.id} onChange={e=>setEditData(p=>({...p,id:e.target.value}))}/></div>
                  <div style={S.fGroup}><label style={S.label}>Nombre *</label>
                    <input style={S.input} value={editData.nombre} onChange={e=>setEditData(p=>({...p,nombre:e.target.value}))}/></div>
                  <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Dirección principal</label>
                    <input style={S.input} value={editData.direccion} onChange={e=>setEditData(p=>({...p,direccion:e.target.value}))}/></div>
                  <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Notas</label>
                    <input style={S.input} value={editData.notas} onChange={e=>setEditData(p=>({...p,notas:e.target.value}))}/></div>
                </div>
                <div style={{borderTop:"1px solid "+C.border,paddingTop:10}}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
                    <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase"}}>Sucursales</div>
                    <button style={{...S.exportBtn,fontSize:11}} onClick={agregarSucursal}>+ Agregar sucursal</button>
                  </div>
                  {editData.sucursales.map((s,si)=>(
                    <div key={si} style={{background:C.navy,borderRadius:8,padding:"10px",marginBottom:8,display:"flex",flexDirection:"column",gap:6}}>
                      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                        <div style={S.fGroup}><label style={S.label}>Nombre sucursal</label>
                          <input style={S.input} placeholder="Ej: Bodega Norte, Piso 7..." value={s.nombre} onChange={e=>editarSucursal(si,"nombre",e.target.value)}/></div>
                        <div style={S.fGroup}><label style={S.label}>Dirección</label>
                          <input style={S.input} value={s.direccion} onChange={e=>editarSucursal(si,"direccion",e.target.value)}/></div>
                        <div style={{...S.fGroup,gridColumn:"1/-1"}}><label style={S.label}>Notas</label>
                          <input style={S.input} value={s.notas} onChange={e=>editarSucursal(si,"notas",e.target.value)}/></div>
                      </div>
                      <div style={{display:"flex",justifyContent:"flex-end"}}>
                        <button style={{...S.statusBtn,border:"1px solid "+C.danger,color:C.danger,fontSize:11}} onClick={()=>eliminarSucursal(si)}>Eliminar sucursal</button>
                      </div>
                    </div>
                  ))}
                </div>
                <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
                  <button style={S.btnSec} onClick={()=>{setEditIdx(null);setEditData(null);}}>Cancelar</button>
                  <button style={S.btnPri} onClick={guardarEdit}>Guardar cliente</button>
                </div>
              </>
            )}
          </div>
        );
      })}
    </div>
  );
}


// ── Mapa tramo en detalle solicitud ───────────────────────────────────────
function MapaTramo({ sol, solicitudes }) {
  const [tramo, setTramo] = useState(null);
  const [calculando, setCalculando] = useState(false);

  // Determinar origen: Pudahuel o la solicitud anterior del mismo día y chofer
  function getOrigen() {
    if (!sol.fecha || !sol.direccion) return null;
    const mismaFecha = solicitudes
      .filter(s => s.fecha === sol.fecha && s.id !== sol.id && s.status === "completada")
      .sort((a, b) => new Date(a.updatedAt) - new Date(b.updatedAt));
    
    const idx = mismaFecha.findIndex(s => {
      // La solicitud anterior a la actual
      return new Date(s.updatedAt) < new Date(sol.updatedAt);
    });
    
    const anterior = mismaFecha.filter(s => new Date(s.updatedAt) < new Date(sol.updatedAt)).pop();
    if (anterior?.direccion) return anterior.direccion + ", Chile";
    return ORIGEN_PUDAHUEL;
  }

  async function calcular() {
    if (!sol.direccion) return;
    setCalculando(true);
    const origen = getOrigen() || ORIGEN_PUDAHUEL;
    const result = await calcularTramo(origen, sol.direccion + ", Chile");
    if(result) {
      setTramo({ ...result, origen });
    } else {
      setTramo({km:"N/D", tiempo:"N/D", mapaUrl:null, origen});
    }
    setCalculando(false);
  }

  if (!sol.direccion) return null;

  return (
    <div style={S.detailBlock}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
        <div style={S.fieldLabel}>Ruta del tramo</div>
        {!tramo&&<button style={{...S.exportBtn,fontSize:11,padding:"4px 10px"}} disabled={calculando} onClick={calcular}>
          {calculando?"Calculando...":"🗺 Ver ruta"}
        </button>}
      </div>
      {tramo?(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"flex",gap:10}}>
            <div style={{background:C.navy,borderRadius:8,padding:"8px 12px",flex:1,border:"1px solid "+C.border}}>
              <div style={{fontSize:10,color:C.muted,fontWeight:700}}>DISTANCIA</div>
              <div style={{fontSize:18,fontWeight:900,color:C.cyan}}>{tramo.km} km</div>
            </div>
            <div style={{background:C.navy,borderRadius:8,padding:"8px 12px",flex:1,border:"1px solid "+C.border}}>
              <div style={{fontSize:10,color:C.muted,fontWeight:700}}>TIEMPO EST.</div>
              <div style={{fontSize:18,fontWeight:900,color:C.warning}}>{tramo.tiempo}</div>
            </div>
          </div>
          <div style={{fontSize:11,color:C.muted}}>
            📍 {tramo.origen === ORIGEN_PUDAHUEL ? "Desde Pudahuel" : "Desde entrega anterior"}
          </div>
          <img
            src={tramo.mapaUrl}
            alt="Mapa del tramo"
            style={{width:"100%",borderRadius:10,border:"1px solid "+C.border}}
            onError={e=>e.target.style.display="none"}
          />
          <a href={`https://www.google.com/maps/dir/${encodeURIComponent(tramo.origen)}/${encodeURIComponent(sol.direccion+", Chile")}`}
            target="_blank" rel="noreferrer"
            style={{display:"inline-flex",alignItems:"center",gap:6,background:C.cyan+"22",border:"1px solid "+C.cyan,color:C.cyan,borderRadius:8,padding:"7px 14px",fontSize:12,fontWeight:700,textDecoration:"none"}}>
            🗺 Abrir en Google Maps
          </a>
        </div>
      ):null}
    </div>
  );
}


// ── Modal Firma Receptor ───────────────────────────────────────────────────
function ModalFirma({ solId, onGuardar, onCerrar, rol="receptor" }) {
  const ROL = rol==="despachador" ? "despachador" : "receptor";
  const canvasRef = useRef(null);
  const [dibujando, setDibujando] = useState(false);
  const [nombre, setNombre] = useState("");
  const [hayFirma, setHayFirma] = useState(false);
  const [modo, setModo] = useState("firma"); // firma | rechazo

  function getPos(e, canvas) {
    const rect = canvas.getBoundingClientRect();
    const touch = e.touches?.[0] || e;
    return { x: touch.clientX - rect.left, y: touch.clientY - rect.top };
  }

  function iniciar(e) {
    e.preventDefault();
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const pos = getPos(e, canvas);
    ctx.beginPath();
    ctx.moveTo(pos.x, pos.y);
    setDibujando(true);
  }

  function dibujar(e) {
    e.preventDefault();
    if (!dibujando) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const pos = getPos(e, canvas);
    ctx.lineWidth = 2.5;
    ctx.lineCap = "round";
    ctx.strokeStyle = "#0D1F3C";
    ctx.lineTo(pos.x, pos.y);
    ctx.stroke();
    setHayFirma(true);
  }

  function terminar(e) { e.preventDefault(); setDibujando(false); }

  function limpiar() {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    setHayFirma(false);
  }

  function guardar() {
    if (modo === "rechazo") {
      onGuardar({ rechazo: true, nombre: nombre||"Anónimo", dataUrl: null });
      return;
    }
    if (!hayFirma) return;
    const dataUrl = canvasRef.current.toDataURL("image/png");
    onGuardar({ rechazo: false, nombre: nombre||"Receptor", dataUrl });
  }

  return (
    <div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"#000000CC",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{background:"#fff",borderRadius:16,padding:20,width:"100%",maxWidth:420,display:"flex",flexDirection:"column",gap:14}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{fontSize:16,fontWeight:800,color:C.navy}}>{ROL==="despachador"?"Firma del despachador":"Firma del receptor"}</div>
          <button style={{background:"transparent",border:"none",fontSize:20,cursor:"pointer",color:C.muted}} onClick={onCerrar}>✕</button>
        </div>

        <div style={{display:"flex",gap:8}}>
          <button style={{flex:1,padding:"8px",borderRadius:8,border:"2px solid "+(modo==="firma"?"#7C3AED":"#ddd"),background:modo==="firma"?"#7C3AED22":"transparent",color:modo==="firma"?"#7C3AED":C.muted,fontWeight:700,fontSize:13,cursor:"pointer"}}
            onClick={()=>setModo("firma")}>✍️ Firma</button>
          <button style={{flex:1,padding:"8px",borderRadius:8,border:"2px solid "+(modo==="rechazo"?C.danger:"#ddd"),background:modo==="rechazo"?C.danger+"22":"transparent",color:modo==="rechazo"?C.danger:C.muted,fontWeight:700,fontSize:13,cursor:"pointer"}}
            onClick={()=>setModo("rechazo")}>✗ No es necesaria firma digital</button>
        </div>

        {modo==="firma"?(
          <>
            <div style={{fontSize:12,color:C.muted}}>El {ROL} dibuja su firma con el dedo:</div>
            <div style={{border:"2px solid #ddd",borderRadius:10,overflow:"hidden",background:"#f9f9f9",touchAction:"none"}}>
              <canvas ref={canvasRef} width={380} height={160} style={{display:"block",width:"100%",touchAction:"none"}}
                onMouseDown={iniciar} onMouseMove={dibujar} onMouseUp={terminar} onMouseLeave={terminar}
                onTouchStart={iniciar} onTouchMove={dibujar} onTouchEnd={terminar}/>
            </div>
            <button style={{background:"transparent",border:"1px solid #ddd",borderRadius:8,padding:"6px 12px",fontSize:12,color:C.muted,cursor:"pointer",alignSelf:"flex-start"}}
              onClick={limpiar}>Limpiar firma</button>
          </>
        ):(
          <div style={{background:C.danger+"11",border:"1px solid "+C.danger+"44",borderRadius:10,padding:"12px",fontSize:13,color:C.danger,fontWeight:600}}>
            Se registrará que no fue necesaria la firma digital del {ROL}.
          </div>
        )}

        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          <label style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase"}}>Nombre del {ROL}</label>
          <input style={{border:"1px solid #ddd",borderRadius:8,padding:"9px 12px",fontSize:13,outline:"none"}}
            placeholder="Nombre completo" value={nombre} onChange={e=>setNombre(e.target.value)}/>
        </div>

        <div style={{display:"flex",gap:10}}>
          <button style={{flex:1,background:"transparent",border:"1px solid #ddd",borderRadius:8,padding:"11px",fontWeight:600,fontSize:14,cursor:"pointer",color:C.muted}}
            onClick={onCerrar}>Cancelar</button>
          <button style={{flex:1,background:modo==="rechazo"?C.danger:"#7C3AED",color:"#fff",border:"none",borderRadius:8,padding:"11px",fontWeight:800,fontSize:14,cursor:"pointer",opacity:(modo==="firma"&&!hayFirma)?0.4:1}}
            disabled={modo==="firma"&&!hayFirma} onClick={guardar}>
            {modo==="rechazo"?"Registrar":"Guardar firma"}
          </button>
        </div>
      </div>
    </div>

  );
}

// ── Login Chofer ───────────────────────────────────────────────────────────
function LoginChofer({selChofer,setSelChofer,onAcceder,onVolver,choferes=CHOFERES}){
  const [pin,setPin]=useState("");
  const [err,setErr]=useState("");
  const intentar=()=>{
    const c=choferes.find(ch=>ch.nombre===selChofer);
    if(!c){setErr("Selecciona tu nombre.");return;}
    if((c.pin||"")!==pin){setErr("PIN incorrecto.");return;}
    setErr(""); onAcceder();
  };
  return(
    <div style={{...S.section,maxWidth:400,margin:"40px auto"}}>
      <button style={S.backBtn} onClick={onVolver}>← Volver</button>
      <div style={{textAlign:"center",marginBottom:8}}>
        <img src={LOGO_QUANTREX} alt="Quantrex Abbott" style={{width:110,height:110,borderRadius:"50%",display:"block",margin:"0 auto 12px",boxShadow:"0 0 0 3px rgba(0,174,239,.12), 0 12px 36px rgba(0,0,0,.5), 0 0 44px rgba(0,174,239,.16)"}}/>
        <div style={S.pageTitle}>Acceso Choferes</div>
        <div style={{fontSize:13,color:C.textSecondary,marginTop:4}}>Selecciona tu nombre e ingresa tu PIN</div>
      </div>
      <div style={S.fGroup}>
        <label style={S.label}>Seleccionar chofer</label>
        <select style={{...S.input,fontSize:15,padding:"12px"}} value={selChofer} onChange={e=>{setSelChofer(e.target.value);setErr("");}}>
          <option value="">-- Selecciona tu nombre --</option>
          {choferes.map(c=><option key={c.nombre} value={c.nombre}>{c.nombre} · {c.ppu}</option>)}
        </select>
      </div>
      <div style={S.fGroup}>
        <label style={S.label}>PIN (4 dígitos)</label>
        <input style={{...S.input,fontSize:22,padding:"12px",letterSpacing:8,textAlign:"center"}} type="password" inputMode="numeric"
          maxLength={4} placeholder="••••" value={pin}
          onChange={e=>{setPin(e.target.value.replace(/\D/g,"").slice(0,4));setErr("");}}
          onKeyDown={e=>{if(e.key==="Enter")intentar();}}/>
      </div>
      {err&&<div style={{color:C.danger,fontSize:13,marginBottom:10,textAlign:"center"}}>{err}</div>}
      <button style={{...S.btnPri,width:"100%",padding:"14px",fontSize:15,opacity:(selChofer&&pin.length===4)?1:0.5}}
        disabled={!selChofer||pin.length!==4} onClick={intentar}>Ingresar</button>
    </div>
  );
}

// ── Vista Chofer ───────────────────────────────────────────────────────────
function VistaChofer({chofer,solicitudes,onEstado,onSalir}){
  const hoy = new Date().toISOString().split("T")[0];
  const misSols = solicitudes.filter(s =>
    (s.ppuAsignada === chofer.ppu || s.choferAsignado === chofer.nombre) &&
    s.fecha === hoy &&
    ["en_proceso","pendiente"].includes(s.status)
  );
  const [cargando,setCargando]=useState(null);
  const [fotos,setFotos]=useState({});
  const [fotosManifiesto,setFotosManifiesto]=useState({}); // {solId: [b64,...]} para Carga OL
  const [observaciones,setObservaciones]=useState({}); // {solId: texto} nota opcional del chofer
  const [documentosGD,setDocumentosGD]=useState({}); // {solId: texto} N° GD/documento capturado por el chofer al recibirlo físicamente
  const [errorFoto,setErrorFoto]=useState(null);
  const [firmas,setFirmas]=useState({}); // {solId: {dataUrl, nombre, rechazo}}
  const [modalFirma,setModalFirma]=useState(null); // solId activo
  const [llegadas,setLlegadas]=useState({}); // {solId: {hora, timestamp, geo}}
  const [tiempos,setTiempos]=useState({}); // {solId: segundosTranscurridos}
  const [seleccionada,setSeleccionada]=useState(null); // solId de la solicitud vigente seleccionada para desplegar su formulario de cierre
  const timerRef=useRef({});

  useEffect(()=>{
    return ()=>{ Object.values(timerRef.current).forEach(t=>clearInterval(t)); };
  },[]);

  // ── Trazabilidad GPS ──────────────────────────────────────────────
  // Captura automática desde que el chofer inicia sesión hasta que sale.
  // Throttle: máx 1 punto cada 15s o cada 30m recorridos (lo que ocurra
  // primero), para no saturar Supabase ni gastar batería de más.
  const trackWatchId=useRef(null);
  const trackUltimo=useRef({lat:null,lng:null,ts:0});
  useEffect(()=>{
    if(!("geolocation" in navigator)) return; // dispositivo sin soporte, no bloquea el resto de la vista
    // Densidad aumentada (antes 15s/30m) para que el snap-to-roads tenga
    // suficientes puntos y el trazado siga mejor curvas y esquinas.
    const INTERVALO_MIN_MS=8000, DIST_MIN_M=15;
    const distM=(lat1,lng1,lat2,lng2)=>{
      const R=6371000, rad=x=>x*Math.PI/180;
      const dLat=rad(lat2-lat1), dLng=rad(lng2-lng1);
      const a=Math.sin(dLat/2)**2+Math.cos(rad(lat1))*Math.cos(rad(lat2))*Math.sin(dLng/2)**2;
      return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
    };
    trackWatchId.current=navigator.geolocation.watchPosition(
      pos=>{
        const {latitude,longitude,speed,accuracy}=pos.coords;
        const ahora=Date.now();
        const prev=trackUltimo.current;
        const dt=ahora-prev.ts;
        const dd=prev.lat!=null?distM(prev.lat,prev.lng,latitude,longitude):Infinity;
        if(prev.ts!==0 && dt<INTERVALO_MIN_MS && dd<DIST_MIN_M) return; // throttle
        trackUltimo.current={lat:latitude,lng:longitude,ts:ahora};
        sbInsertTracking({
          vehiculo_id: chofer.ppu||null,
          chofer_id: chofer.nombre||null,
          ruta_id: null,
          origen: "celular",
          lat: latitude,
          lng: longitude,
          velocidad_kmh: speed!=null?Math.max(0,speed*3.6):null,
          precision_m: accuracy??null,
          timestamp_captura: new Date().toISOString(),
        });
      },
      err=>console.error("Tracking GPS error:",err.message),
      {enableHighAccuracy:true, maximumAge:5000, timeout:20000}
    );
    return ()=>{
      if(trackWatchId.current!=null){
        navigator.geolocation.clearWatch(trackWatchId.current);
        trackWatchId.current=null;
      }
    };
  },[chofer.ppu, chofer.nombre]);

  function registrarLlegada(solId){
    const now=new Date();
    const hora=now.toLocaleDateString("es-CL")+" "+now.toLocaleTimeString("es-CL",{hour:"2-digit",minute:"2-digit",hour12:false});
    navigator.geolocation.getCurrentPosition(
      pos=>{
        const geo=pos.coords.latitude.toFixed(6)+","+pos.coords.longitude.toFixed(6);
        setLlegadas(p=>({...p,[solId]:{hora,timestamp:now.getTime(),geo}}));
      },
      ()=>{setLlegadas(p=>({...p,[solId]:{hora,timestamp:now.getTime(),geo:null}}));},
      {timeout:5000}
    );
    // Iniciar cronómetro
    timerRef.current[solId]=setInterval(()=>{
      setTiempos(p=>({...p,[solId]:Math.floor((Date.now()-now.getTime())/1000)}));
    },1000);
  }

  function formatTiempo(seg){
    if(!seg&&seg!==0)return null;
    const h=Math.floor(seg/3600),m=Math.floor((seg%3600)/60),s=seg%60;
    if(h>0)return h+"h "+m+"m "+s+"s";
    if(m>0)return m+"m "+s+"s";
    return s+"s";
  }

  // Compresión de imágenes: balance nitidez/peso pensado para lectura de documentos
  // en escritorio. MAX = lado mayor en px; CALIDAD = factor JPEG (0-1).
  // Subir MAX o CALIDAD mejora la nitidez pero aumenta el peso del base64 que viaja
  // en la fila de Supabase. Valores actuales: ~legibles a tamaño completo, peso moderado.
  const FOTO_MAX=1600, FOTO_CALIDAD=0.82;
  function comprimirImagen(file, cb){
    const reader=new FileReader();
    reader.onload=ev=>{
      const img=new Image();
      img.onload=()=>{
        const canvas=document.createElement("canvas");
        let w=img.width,h=img.height;
        if(w>FOTO_MAX){h=Math.round(h*FOTO_MAX/w);w=FOTO_MAX;}
        if(h>FOTO_MAX){w=Math.round(w*FOTO_MAX/h);h=FOTO_MAX;}
        canvas.width=w; canvas.height=h;
        const ctx=canvas.getContext("2d");
        ctx.imageSmoothingEnabled=true; ctx.imageSmoothingQuality="high";
        ctx.drawImage(img,0,0,w,h);
        cb(canvas.toDataURL("image/jpeg",FOTO_CALIDAD));
      };
      img.src=ev.target.result;
    };
    reader.readAsDataURL(file);
  }

  function capturarFoto(solId){
    const input=document.createElement("input");
    input.type="file"; input.accept="image/*"; input.capture="environment";
    input.onchange=e=>{
      const file=e.target.files[0];
      if(!file)return;
      comprimirImagen(file, b64=>setFotos(p=>({...p,[solId]:[...(p[solId]||[]),b64].slice(0,4)})));
    };
    input.click();
  }
  function quitarFoto(solId,idx){
    setFotos(p=>({...p,[solId]:(p[solId]||[]).filter((_,i)=>i!==idx)}));
  }

  // Carga OL: múltiples fotos del manifiesto (se agregan a un arreglo)
  function capturarFotoManifiesto(solId){
    const input=document.createElement("input");
    input.type="file"; input.accept="image/*"; input.capture="environment";
    input.onchange=e=>{
      const file=e.target.files[0];
      if(!file)return;
      comprimirImagen(file, b64=>setFotosManifiesto(p=>({...p,[solId]:[...(p[solId]||[]),b64].slice(0,10)})));
    };
    input.click();
  }
  function quitarFotoManifiesto(solId,idx){
    setFotosManifiesto(p=>({...p,[solId]:(p[solId]||[]).filter((_,i)=>i!==idx)}));
  }

  async function cerrar(id, estado){
    const sol=misSols.find(x=>x.id===id);
    const esCargaOL=sol?.tipo==="carga_ol";
    // Validar foto(s) obligatoria(s) — Carga OL admite varias, mínimo 1
    if(esCargaOL){
      if((fotosManifiesto[id]||[]).length<1){
        setErrorFoto(id);
        setTimeout(()=>setErrorFoto(null),3000);
        return;
      }
    } else if((fotos[id]||[]).length<1){
      setErrorFoto(id);
      setTimeout(()=>setErrorFoto(null),3000);
      return;
    }
    // Validar firma obligatoria (en Carga OL es la firma del despachador)
    if(!firmas[id]){
      setErrorFoto(id+"firma");
      setTimeout(()=>setErrorFoto(null),3000);
      return;
    }
    setErrorFoto(null);
    setCargando(id+estado);
    // Calcular tiempo en punto
    const llegada=llegadas[id];
    const tiempoEnPunto=llegada?Math.floor((Date.now()-llegada.timestamp)/1000):null;
    const tiempoStr=tiempoEnPunto!==null?formatTiempo(tiempoEnPunto):null;
    // Detener cronómetro
    if(timerRef.current[id]){clearInterval(timerRef.current[id]);delete timerRef.current[id];}
    await onEstado(id, estado, fotos[id]||null, llegada?.hora||null, tiempoStr, firmas[id]||null, fotosManifiesto[id]||null, observaciones[id]||null, documentosGD[id]||null);
    setFotos(p=>{const n={...p};delete n[id];return n;});
    setFotosManifiesto(p=>{const n={...p};delete n[id];return n;});
    setObservaciones(p=>{const n={...p};delete n[id];return n;});
    setDocumentosGD(p=>{const n={...p};delete n[id];return n;});
    setFirmas(p=>{const n={...p};delete n[id];return n;});
    setLlegadas(p=>{const n={...p};delete n[id];return n;});
    setTiempos(p=>{const n={...p};delete n[id];return n;});
    setCargando(null);
  }

  return(
    <>
    <div style={S.section}>
      <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px 20px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div>
          <div style={{fontSize:11,color:C.cyan,fontWeight:700,letterSpacing:1,textTransform:"uppercase"}}>Perfil Chofer</div>
          <div style={{fontSize:18,fontWeight:800,color:C.textPrimary,marginTop:2}}>{chofer.nombre}</div>
          <div style={{fontSize:13,color:C.textSecondary}}>PPU: {chofer.ppu} · {chofer.usuarioDT}</div>
        </div>
        <button style={{...S.btnSec,fontSize:12}} onClick={onSalir}>Salir</button>
      </div>

      <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:1.5,textTransform:"uppercase"}}>
        Entregas de hoy — {new Date().toLocaleDateString("es-CL",{weekday:"long",day:"numeric",month:"long"})}
      </div>

      {misSols.length===0?(
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:12,padding:"40px 0",color:C.muted}}>
          <div style={{fontSize:36}}>✓</div>
          <p style={{margin:0,fontWeight:600}}>Sin entregas pendientes para hoy</p>
        </div>
      ):misSols.map(s=>{
        const tm=TYPE_META[s.tipo]||{label:s.tipo,icon:"·",color:"#6B8CAE"};
        const abierta=seleccionada===s.id;
        const llegadaOk=!!llegadas[s.id];
        const fotosOk=(s.tipo==="carga_ol"?(fotosManifiesto[s.id]||[]):(fotos[s.id]||[])).length>=1;
        const firmaOk=!!firmas[s.id];
        return(
          <div key={s.id} style={{background:C.navySurface,border:"1px solid "+(abierta?C.cyan:C.border),borderRadius:12,overflow:"hidden"}}>
            {/* Fila de lista: cliente + N° de solicitud. Al seleccionar se despliega el formulario de cierre */}
            <div style={{display:"flex",alignItems:"center",gap:12,padding:"14px 16px",cursor:"pointer"}}
              onClick={()=>setSeleccionada(abierta?null:s.id)}>
              <div style={{...S.rowIcon,background:tm.color+"22",color:tm.color,flexShrink:0}}>{tm.icon}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:700,fontSize:14}}>{s.titulo}</div>
                <div style={{fontSize:12,color:C.cyan,fontWeight:700,marginTop:2}}>N° Solicitud: {s.ot||s.id}</div>
                {s.direccion&&<div style={{fontSize:12,color:C.textSecondary,marginTop:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>📍 {s.direccion}</div>}
              </div>
              <div style={{display:"flex",gap:6,flexShrink:0,fontSize:14}}>
                {llegadaOk&&<span title="Llegada registrada">📍</span>}
                {fotosOk&&<span title="Fotos registradas">📷</span>}
                {firmaOk&&<span title="Firma registrada">✍️</span>}
              </div>
              <div style={{color:C.muted,fontSize:16,flexShrink:0}}>{abierta?"▲":"▼"}</div>
            </div>

            {abierta&&(
            <div style={{padding:"0 16px 16px",display:"flex",flexDirection:"column",gap:12,borderTop:"1px solid "+C.border,paddingTop:14}}>
            {s.direccion&&<div style={{background:C.navy,borderRadius:8,padding:"10px 12px",fontSize:13,color:C.textSecondary}}>
              📍 {s.direccion}
              {s.notas&&<div style={{color:C.muted,fontSize:12,marginTop:4}}>💬 {s.notas}</div>}
            </div>}
            {/* GD / Documento Cliente — el chofer la recibe recién en físico, por eso se
                captura aquí al momento del cierre en vez de exigirla al crear la solicitud.
                Si la solicitud ya trae algo cargado (ej. editado por un operador), se precarga
                mostrando solo un GD (prioriza el que mencione "maletas") y queda editable. */}
            {(()=>{
              const lista=(s.documentos||"").split(",").map(d=>d.trim()).filter(Boolean);
              const gdPrecargada=lista.find(d=>/maletas/i.test(d))||lista[0]||"";
              const valor=documentosGD[s.id]!==undefined?documentosGD[s.id]:gdPrecargada;
              return(
                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  <label style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:.5,textTransform:"uppercase"}}>📄 N° GD Cliente</label>
                  <input style={{border:"1px solid "+C.border,background:C.navy,color:C.textPrimary,borderRadius:10,padding:"10px 12px",fontSize:13,outline:"none"}}
                    placeholder="Ej: GD 12345 (según lo indicado en la guía física)"
                    value={valor} onChange={e=>setDocumentosGD(p=>({...p,[s.id]:e.target.value}))}/>
                </div>
              );
            })()}
            {/* Llegada al punto */}
            {!llegadas[s.id]?(
              <button style={{background:C.cyan+"22",border:"1px solid "+C.cyan,color:C.cyan,borderRadius:10,padding:"10px 14px",fontSize:13,fontWeight:700,cursor:"pointer",width:"100%"}}
                onClick={()=>registrarLlegada(s.id)}>
                📍 Llegué al punto de entrega
              </button>
            ):(
              <div style={{background:C.navy,border:"1px solid "+C.cyan,borderRadius:10,padding:"10px 14px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                <div>
                  <div style={{fontSize:11,color:C.cyan,fontWeight:700}}>EN PUNTO DE ENTREGA</div>
                  <div style={{fontSize:11,color:C.muted,marginTop:2}}>Llegada: {llegadas[s.id].hora}</div>
                </div>
                <div style={{fontSize:22,fontWeight:900,color:C.cyan,fontFamily:"monospace"}}>
                  {formatTiempo(tiempos[s.id]||0)}
                </div>
              </div>
            )}
            {/* Captura de foto */}
            {s.tipo==="carga_ol"?(()=>{
              const arr=fotosManifiesto[s.id]||[];
              const ok=arr.length>=1;
              return(<div style={{display:"flex",flexDirection:"column",gap:8}}>
                <div style={{fontSize:11,fontWeight:700,color:ok?C.success:C.danger,letterSpacing:.5,textTransform:"uppercase"}}>
                  Registro Fotográfico Manifiesto DHL — {arr.length} foto{arr.length===1?"":"s"} {ok?"✓":"(mínimo 1)"}
                </div>
                {arr.length>0&&<div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                  {arr.map((b,i)=>(
                    <div key={i} style={{position:"relative"}}>
                      <img src={b} alt={"manifiesto "+(i+1)} style={{width:64,height:64,borderRadius:8,objectFit:"cover",border:"2px solid "+C.success}}/>
                      <button onClick={()=>quitarFotoManifiesto(s.id,i)} style={{position:"absolute",top:-6,right:-6,width:20,height:20,borderRadius:"50%",background:C.danger,color:"#fff",border:"none",cursor:"pointer",fontSize:12,fontWeight:700,lineHeight:1}}>×</button>
                    </div>
                  ))}
                </div>}
                <button style={{background:ok?C.success+"22":C.danger+"22",border:"1px solid "+(ok?C.success:C.danger),color:ok?C.success:C.danger,borderRadius:10,padding:"10px 14px",fontSize:13,fontWeight:700,cursor:"pointer",width:"100%",justifyContent:"center",display:"flex",alignItems:"center",gap:6}}
                  onClick={()=>capturarFotoManifiesto(s.id)}>
                  📷 Agregar foto del manifiesto
                </button>
              </div>);
            })():(()=>{
              const arr=fotos[s.id]||[];
              const ok=arr.length>=1;
              return(<div style={{display:"flex",flexDirection:"column",gap:8}}>
                <div style={{fontSize:11,fontWeight:700,color:ok?C.success:C.danger,letterSpacing:.5,textTransform:"uppercase"}}>
                  Foto documento — {arr.length} de 4 {ok?"✓":"(mínimo 1)"}
                </div>
                {arr.length>0&&<div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                  {arr.map((b,i)=>(
                    <div key={i} style={{position:"relative"}}>
                      <img src={b} alt={"documento "+(i+1)} style={{width:64,height:64,borderRadius:8,objectFit:"cover",border:"2px solid "+C.success}}/>
                      <button onClick={()=>quitarFoto(s.id,i)} style={{position:"absolute",top:-6,right:-6,width:20,height:20,borderRadius:"50%",background:C.danger,color:"#fff",border:"none",cursor:"pointer",fontSize:12,fontWeight:700,lineHeight:1}}>×</button>
                    </div>
                  ))}
                </div>}
                {arr.length<4&&<button style={{background:ok?C.success+"22":C.danger+"22",border:"1px solid "+(ok?C.success:C.danger),color:ok?C.success:C.danger,borderRadius:10,padding:"10px 14px",fontSize:13,fontWeight:700,cursor:"pointer",width:"100%",justifyContent:"center",display:"flex",alignItems:"center",gap:6}}
                  onClick={()=>capturarFoto(s.id)}>
                  📷 {ok?"Agregar otra foto del documento":"Tomar foto del documento (obligatorio)"}
                </button>}
              </div>);
            })()}
            {errorFoto===s.id&&<div style={{background:C.danger+"22",border:"1px solid "+C.danger,borderRadius:8,padding:"8px 12px",fontSize:13,color:C.danger,fontWeight:600}}>
              📷 {s.tipo==="carga_ol"?"Debes registrar al menos una foto del manifiesto DHL antes de cerrar.":"Debes tomar una foto del documento antes de registrar la entrega."}
            </div>}
            {/* Firma del receptor (en Carga OL: firma del despachador) */}
            <button style={{background:firmas[s.id]?C.success+"22":"#7C3AED22",border:"1px solid "+(firmas[s.id]?C.success:"#7C3AED"),color:firmas[s.id]?C.success:"#A78BFA",borderRadius:10,padding:"10px 14px",fontSize:13,fontWeight:700,cursor:"pointer",width:"100%",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}
              onClick={()=>setModalFirma(s.id)}>
              ✍️ {firmas[s.id]?(firmas[s.id].rechazo?"Sin firma digital ✓":"Firma tomada ✓"):(s.tipo==="carga_ol"?"Firma Despachador (obligatorio)":"Firma del receptor (obligatorio)")}
            </button>
            {errorFoto===s.id+"firma"&&<div style={{background:C.danger+"22",border:"1px solid "+C.danger,borderRadius:8,padding:"8px 12px",fontSize:13,color:C.danger,fontWeight:600}}>
              ✍️ {s.tipo==="carga_ol"?"Debes registrar la firma del despachador.":"Debes registrar la firma del receptor o indicar que no es necesaria firma digital."}
            </div>}
            {/* Observación opcional del chofer */}
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              <label style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase"}}>Observación (opcional)</label>
              <textarea style={{border:"1px solid "+C.border,background:C.navy,color:C.textPrimary,borderRadius:10,padding:"10px 12px",fontSize:13,outline:"none",resize:"vertical",minHeight:54,fontFamily:"inherit"}}
                placeholder="Alguna nota o situación de la entrega (ej. recibido por turno noche, acceso restringido, etc.)"
                value={observaciones[s.id]||""} onChange={e=>setObservaciones(p=>({...p,[s.id]:e.target.value}))}/>
            </div>
            <div style={{display:"flex",gap:10}}>
              <button style={{flex:1,background:C.success+"22",border:"1px solid "+C.success,color:C.success,borderRadius:10,padding:"12px",fontWeight:800,fontSize:14,cursor:"pointer",opacity:cargando?0.6:1}}
                disabled={!!cargando} onClick={()=>cerrar(s.id,"completada")}>
                {cargando===s.id+"completada"?"Registrando...":"✓ Completada"}
              </button>
              <button style={{flex:1,background:"#F9731622",border:"1px solid #F97316",color:"#F97316",borderRadius:10,padding:"12px",fontWeight:800,fontSize:14,cursor:"pointer",opacity:cargando?0.6:1}}
                disabled={!!cargando} onClick={()=>cerrar(s.id,"no_entregado")}>
                {cargando===s.id+"no_entregado"?"Registrando...":"✗ No Entregado"}
              </button>
            </div>
            </div>
            )}
          </div>
        );
      })}
    </div>
    {modalFirma&&<ModalFirma solId={modalFirma} rol={misSols.find(x=>x.id===modalFirma)?.tipo==="carga_ol"?"despachador":"receptor"}
      onGuardar={f=>{setFirmas(p=>({...p,[modalFirma]:f}));setModalFirma(null);}}
      onCerrar={()=>setModalFirma(null)}/>}
    </>
  );
}


// ── Resumen KM del día ────────────────────────────────────────────────────
function ResumenKmDia({ solicitudes, rutas=[], compact=false }) {
  const [kmData, setKmData] = useState(null);
  const [calculando, setCalculando] = useState(false);

  const hoy = new Date().toLocaleDateString("en-CA"); // fecha local (Chile), evita salto UTC
  const solsHoy = solicitudes.filter(s =>
    s.fecha === hoy && (s.direccion || s.destino || s.tipo === "li_devol") && (s.status === "completada" || s.status === "devolucion") && s.tipo !== "carga_ol"
  );

  async function calcularKmRuta() {
    if (solsHoy.length === 0 && rutas.filter(r=>r.fecha===hoy&&r.kmTotal).length===0) return;
    setCalculando(true);
    let totalKm = 0;
    const tramos = [];
    // 1) Rutas formales de hoy: ya vienen encadenadas (kmTotal)
    const rutasHoy = rutas.filter(r => r.fecha === hoy && r.kmTotal);
    const solsEnRuta = new Set();
    for (const r of rutasHoy) {
      r.paradas.forEach(p => solsEnRuta.add(p.solId));
      totalKm += parseFloat(r.kmTotal);
      tramos.push({ titulo: r.id + " · " + r.vehiculo, direccion: "Ruta completa", km: r.kmTotal });
    }
    // 2) Solicitudes sueltas: agrupar por PPU y ENCADENAR (Pudahuel → s1 → s2 → ...)
    const sueltas = solsHoy.filter(s => !solsEnRuta.has(s.id));
    const porPpu = {};
    for (const s of sueltas) {
      const ppu = (s.ppuAsignada || "").trim() || "Sin PPU";
      (porPpu[ppu] = porPpu[ppu] || []).push(s);
    }
    for (const ppu of Object.keys(porPpu)) {
      // Orden por hora de entrega real (o programada) para reflejar la secuencia del viaje
      const grupo = porPpu[ppu].slice().sort((a,b)=>(a.horaEntrega||a.hora||"").localeCompare(b.horaEntrega||b.hora||""));
      const tipoCorto = t => ({entrega:"Entrega",li_retiro:"Retiro",li_devol:"Devolución"}[t] || (TYPE_META[t]?.label||t));
      let origen = PUDAHUEL_COORDS;
      let primera = true;
      let prevTramo = null;
      for (const s of grupo) {
        const dest = await coordsSolicitud(s);
        if (!(dest && origen)) continue;
        const km = parseFloat(haversineKm(origen.lat, origen.lon, dest.lat, dest.lon));
        if (prevTramo && !primera && km === 0) {
          // Mismo punto que la parada anterior: agrupar en una sola línea (no suma km)
          prevTramo._ops.push(tipoCorto(s.tipo));
          prevTramo.titulo = prevTramo._base + " (" + prevTramo._ops.join(" + ") + ")";
          continue;
        }
        totalKm += km;
        const base = (ppu!=="Sin PPU"?ppu+" · ":"") + s.titulo;
        const t = {
          _base: base, _ops: [tipoCorto(s.tipo)],
          titulo: base + " (" + tipoCorto(s.tipo) + ")",
          km: km.toFixed(1),
        };
        tramos.push(t);
        prevTramo = t;
        origen = dest; primera = false;
      }
    }
    setKmData({ totalKm: totalKm.toFixed(1), tramos, nSols: solsHoy.length });
    setCalculando(false);
  }

  if (compact) {
    const sinDatos = solsHoy.length === 0 && rutas.filter(r=>r.fecha===hoy&&r.kmTotal).length===0;
    return (
      <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"14px 16px",display:"flex",flexDirection:"column",gap:6}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.2,textTransform:"uppercase"}}>Km del día</div>
        {kmData
          ? <><div style={{fontSize:22,fontWeight:900,color:C.cyan}}>{kmData.totalKm} km</div><div style={{fontSize:10,color:C.muted}}>{kmData.nSols} entregas · desde Pudahuel</div></>
          : sinDatos
            ? <div style={{fontSize:12,color:C.muted}}>Sin entregas completadas hoy.</div>
            : <button style={{...S.exportBtn,fontSize:11,alignSelf:"flex-start"}} disabled={calculando} onClick={calcularKmRuta}>{calculando?"Calculando...":"🗺 Calcular"}</button>}
      </div>
    );
  }

  if (solsHoy.length === 0 && rutas.filter(r=>r.fecha===hoy&&r.kmTotal).length===0) {
    return (
      <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.5,textTransform:"uppercase"}}>Kilómetros del día</div>
        <div style={{fontSize:12,color:C.muted}}>Aún no hay entregas completadas hoy. El cálculo aparecerá cuando se completen entregas con dirección.</div>
      </div>
    );
  }

  return (
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.5,textTransform:"uppercase"}}>Kilómetros del día</div>
        {!kmData&&<button style={{...S.exportBtn,fontSize:11}} disabled={calculando} onClick={calcularKmRuta}>
          {calculando?"Calculando...":"🗺 Calcular km"}
        </button>}
      </div>
      {kmData?(
        <>
          <div style={{display:"flex",alignItems:"center",gap:12}}>
            <div style={{background:C.navy,borderRadius:10,padding:"12px 16px",border:"1px solid "+C.cyan+"44",flex:1}}>
              <div style={{fontSize:11,color:C.muted}}>Total recorrido hoy</div>
              <div style={{fontSize:28,fontWeight:900,color:C.cyan}}>{kmData.totalKm} km</div>
              <div style={{fontSize:10,color:C.muted,marginTop:2}}>desde Pudahuel</div>
            </div>
            <div style={{background:C.navy,borderRadius:10,padding:"12px 16px",border:"1px solid "+C.border,flex:1}}>
              <div style={{fontSize:11,color:C.muted}}>Entregas completadas</div>
              <div style={{fontSize:28,fontWeight:900,color:C.success}}>{kmData.nSols}</div>
            </div>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {kmData.tramos.map((t,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,fontSize:12,color:C.textSecondary}}>
                <span style={{color:C.cyan}}>→</span>
                <span style={{flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.titulo}</span>
                <span style={{color:C.textPrimary,fontWeight:700,flexShrink:0}}>{t.km} km</span>
              </div>
            ))}
          </div>
        </>
      ):(
        <div style={{fontSize:12,color:C.muted}}>{solsHoy.length} entrega(s) completada(s) hoy. Presiona para calcular km desde Pudahuel.</div>
      )}
    </div>
  );
}


// ── Resumen CO2 mensual ────────────────────────────────────────────────────
function ResumenCO2({ solicitudes, rutas=[], compact=false }) {
  const [co2Data, setCo2Data] = useState(null);
  const [calculando, setCalculando] = useState(false);

  const solsConDireccion = solicitudes.filter(s =>
    s.status === "completada" && s.direccion && s.tipo !== "carga_ol"
  );

  async function calcularCO2() {
    if (solsConDireccion.length === 0) return;
    setCalculando(true);
    let totalKm = 0;
    const detalles = [];
    for (const s of solsConDireccion) {
      const km = await calcularKmDesdePudahuel(s.direccion);
      if (km !== null) {
        totalKm += km;
        detalles.push({ titulo: s.titulo, direccion: s.direccion, km });
      }
    }
    const totalKg = solsConDireccion.length * PESO_BASE_KG;
    const co2 = (totalKm * totalKg).toFixed(0);
    setCo2Data({ totalKm: totalKm.toFixed(1), totalKg, co2, detalles, nSols: solsConDireccion.length });
    setCalculando(false);
  }

  if (solsConDireccion.length === 0) return null;

  if (compact) {
    return (
      <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"14px 16px",display:"flex",flexDirection:"column",gap:6}}>
        <div style={{fontSize:11,fontWeight:700,color:C.success,letterSpacing:1.2,textTransform:"uppercase"}}>CO₂ estimado</div>
        {co2Data
          ? <><div style={{fontSize:22,fontWeight:900,color:C.success}}>{(parseInt(co2Data.co2)/1000*0.15).toFixed(1)} kg</div><div style={{fontSize:10,color:C.muted}}>tkm × 0,15 · {co2Data.nSols} entregas</div></>
          : <button style={{...S.exportBtn,fontSize:11,alignSelf:"flex-start"}} disabled={calculando} onClick={calcularCO2}>{calculando?"Calculando...":"🌿 Calcular"}</button>}
      </div>
    );
  }

  return (
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.5,textTransform:"uppercase"}}>Medición CO₂</div>
        {!co2Data&&<button style={{...S.exportBtn,fontSize:11}} disabled={calculando} onClick={calcularCO2}>
          {calculando?"Calculando...":"🌿 Calcular CO₂"}
        </button>}
      </div>
      {co2Data?(
        <>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div style={{background:C.navy,borderRadius:10,padding:"12px",border:"1px solid "+C.border}}>
              <div style={{fontSize:10,color:C.muted,fontWeight:700,marginBottom:4}}>TOTAL KM</div>
              <div style={{fontSize:20,fontWeight:900,color:C.cyan}}>{co2Data.totalKm} km</div>
              <div style={{fontSize:10,color:C.muted,marginTop:2}}>desde Pudahuel · período actual</div>
            </div>
            <div style={{background:C.navy,borderRadius:10,padding:"12px",border:"1px solid "+C.success+"44"}}>
              <div style={{fontSize:10,color:C.success,fontWeight:700,marginBottom:4}}>CO₂ ESTIMADO</div>
              <div style={{fontSize:20,fontWeight:900,color:C.success}}>{(parseInt(co2Data.co2)/1000*0.15).toFixed(1)} kg</div>
              <div style={{fontSize:10,color:C.muted,marginTop:2}}>tkm × 0,15 kg CO₂/tkm</div>
            </div>
          </div>
        </>
      ):(
        <div style={{fontSize:12,color:C.muted}}>Presiona para calcular el CO₂ del período.</div>
      )}
    </div>
  );
}


// ── Resumen rutas del día en Dashboard ───────────────────────────────────
function ResumenRutasDia({ solicitudes }) {
  const [rutas, setRutas] = useState(null);
  const [calculando, setCalculando] = useState(false);

  const hoy = new Date().toISOString().split("T")[0];
  const solsHoy = solicitudes
    .filter(s => s.fecha === hoy && s.direccion && s.status === "completada")
    .sort((a, b) => new Date(a.updatedAt) - new Date(b.updatedAt));

  async function calcularRutas() {
    if (solsHoy.length === 0) return;
    setCalculando(true);
    const tramos = [];
    let totalKm = 0;

    for (let i = 0; i < solsHoy.length; i++) {
      const origen = i === 0 ? ORIGEN_PUDAHUEL : solsHoy[i-1].direccion + ", Chile";
      const destino = solsHoy[i].direccion + ", Chile";
      const result = await calcularTramo(origen, destino);
      if (result) {
        totalKm += parseFloat(result.km);
        tramos.push({
          de: i === 0 ? "Pudahuel (origen)" : solsHoy[i-1].titulo,
          a: solsHoy[i].titulo,
          direccionA: solsHoy[i].direccion,
          km: result.km,
          tiempo: result.tiempo,
          mapaUrl: result.mapaUrl,
        });
      }
    }
    setRutas({ tramos, totalKm: totalKm.toFixed(1) });
    setCalculando(false);
  }

  if (solsHoy.length === 0) return null;

  return (
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:11,fontWeight:700,color:C.cyan,letterSpacing:1.5,textTransform:"uppercase"}}>Rutas del día</div>
        {!rutas&&<button style={{...S.exportBtn,fontSize:11}} disabled={calculando} onClick={calcularRutas}>
          {calculando?"Calculando rutas...":"🗺 Ver rutas del día"}
        </button>}
      </div>

      {rutas?(
        <>
          <div style={{background:C.navy,borderRadius:10,padding:"12px 16px",border:"1px solid "+C.cyan+"44",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div>
              <div style={{fontSize:11,color:C.muted}}>Total recorrido hoy</div>
              <div style={{fontSize:24,fontWeight:900,color:C.cyan}}>{rutas.totalKm} km</div>
            </div>
            <div style={{fontSize:11,color:C.muted,textAlign:"right"}}>
              {rutas.tramos.length} tramo(s)<br/>{solsHoy.length} entrega(s)
            </div>
          </div>

          {rutas.tramos.map((t, i) => (
            <div key={i} style={{background:C.navy,borderRadius:10,padding:"12px",border:"1px solid "+C.border,display:"flex",flexDirection:"column",gap:8}}>
              <div style={{display:"flex",alignItems:"center",gap:8,fontSize:12}}>
                <span style={{color:C.cyan,fontWeight:700}}>Tramo {i+1}</span>
                <span style={{color:C.muted}}>{t.de}</span>
                <span style={{color:C.cyan}}>→</span>
                <span style={{color:C.textPrimary,fontWeight:600,flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.a}</span>
              </div>
              <div style={{display:"flex",gap:8}}>
                <div style={{background:C.navySurface,borderRadius:8,padding:"6px 10px",fontSize:12,fontWeight:700,color:C.cyan}}>{t.km} km</div>
                <div style={{background:C.navySurface,borderRadius:8,padding:"6px 10px",fontSize:12,fontWeight:700,color:C.warning}}>{t.tiempo}</div>
              </div>
              <img src={t.mapaUrl} alt={"Tramo "+(i+1)} style={{width:"100%",borderRadius:8,border:"1px solid "+C.border}} onError={e=>e.target.style.display="none"}/>
              <a href={`https://www.google.com/maps/dir/${encodeURIComponent(i===0?ORIGEN_PUDAHUEL:rutas.tramos[i-1].direccionA+", Chile")}/${encodeURIComponent(t.direccionA+", Chile")}`}
                target="_blank" rel="noreferrer"
                style={{display:"inline-flex",alignItems:"center",gap:6,color:C.cyan,fontSize:11,fontWeight:700,textDecoration:"none"}}>
                🗺 Abrir en Google Maps
              </a>
            </div>
          ))}
        </>
      ):(
        <div style={{fontSize:12,color:C.muted}}>{solsHoy.length} entrega(s) completada(s) hoy. Presiona para ver las rutas.</div>
      )}
    </div>
  );
}

function EmptyState({msg,action}){
  return(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:12,padding:"40px 0",color:C.muted}}>
      <p style={{margin:0}}>{msg}</p>
      {action&&<button style={S.btnPri} onClick={action}>+ Nueva solicitud</button>}
    </div>
  );
}

// ── Trazabilidad GPS: vista admin/operador ─────────────────────────────────
function VistaTrazabilidad({vehiculos=[],choferes=[]}){
  const hoy=new Date().toISOString().split("T")[0];
  const [filtroVehiculo,setFiltroVehiculo]=useState("");
  const [filtroChofer,setFiltroChofer]=useState("");
  const [fechaDesde,setFechaDesde]=useState(hoy);
  const [fechaHasta,setFechaHasta]=useState(hoy);
  const [puntos,setPuntos]=useState([]);
  const [loading,setLoading]=useState(false);
  const [buscado,setBuscado]=useState(false);
  const [error,setError]=useState(null);
  const mapDivRef=useRef(null);
  const mapInstanceRef=useRef(null);

  async function buscar(){
    setLoading(true); setError(null); setBuscado(true);
    try{
      let q=`?order=timestamp_captura.asc&timestamp_captura=gte.${fechaDesde}T00:00:00&timestamp_captura=lte.${fechaHasta}T23:59:59`;
      if(filtroVehiculo) q+=`&vehiculo_id=eq.${encodeURIComponent(filtroVehiculo)}`;
      if(filtroChofer) q+=`&chofer_id=eq.${encodeURIComponent(filtroChofer)}`;
      const data=await sbFetch("GET","tracking_puntos","",q);
      setPuntos(data||[]);
    }catch(e){
      setError("No se pudo cargar la trazabilidad.");
    }
    setLoading(false);
  }

  // Agrupar por vehículo (y dentro de cada vehículo ya viene ordenado por
  // timestamp_captura desde la query). Esto evita sumar el salto entre el
  // último punto de un vehículo y el primer punto de otro cuando el filtro
  // es "Todos los vehículos" — ese salto no es un desplazamiento real.
  const gruposPorVehiculo=(()=>{
    const map=new Map();
    for(const p of puntos){
      const key=p.vehiculo_id||"_sin_vehiculo";
      if(!map.has(key)) map.set(key,[]);
      map.get(key).push(p);
    }
    return [...map.values()];
  })();

  const paradas=gruposPorVehiculo.flatMap(g=>calcularParadas(g));

  function fmtHora(iso){
    if(!iso) return "";
    return new Date(iso).toLocaleString("es-CL",{day:"2-digit",month:"2-digit",hour:"2-digit",minute:"2-digit",hour12:false});
  }

  // Inicializa/actualiza el mapa interactivo (Leaflet + OpenStreetMap) cada
  // vez que cambian los puntos buscados. Reemplaza el mapa estático anterior.
  // El trazado se ajusta a la calle real (snap-to-roads) en vez de solo unir
  // los puntos GPS crudos con líneas rectas; si el snap falla (sin red, cuota
  // de la API, tramo sin cobertura de calles) cae a los puntos crudos para
  // que la trazabilidad nunca quede sin dibujar.
  useEffect(()=>{
    if(!buscado||puntos.length===0||!mapDivRef.current) return;
    if(mapInstanceRef.current){ mapInstanceRef.current.remove(); mapInstanceRef.current=null; }
    const map=L.map(mapDivRef.current,{zoomControl:true,attributionControl:true,scrollWheelZoom:true});
    mapInstanceRef.current=map;
    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{maxZoom:19,attribution:"© OpenStreetMap"}).addTo(map);

    let cancelado=false;
    const paleta=["#00AEEF","#FF7A00","#22C55E","#E11D48","#A855F7"];
    const bounds=[];

    gruposPorVehiculo.forEach((grupo,gi)=>{
      if(grupo.length<2) return;
      const latlngsCrudos=grupo.map(p=>[p.lat,p.lng]);
      bounds.push(...latlngsCrudos);
      const color=paleta[gi%paleta.length];
      // Dibuja de inmediato con los puntos crudos (feedback rápido), y la
      // reemplaza por la versión ajustada a calle apenas responda la API.
      let linea=L.polyline(latlngsCrudos,{color,weight:4,opacity:0.85}).addTo(map);
      snapToRoads(grupo).then(snapped=>{
        if(cancelado) return;
        if(snapped&&snapped.length>=2){
          linea.setLatLngs(snapped);
        }
      });
      const inicio=grupo[0], fin=grupo[grupo.length-1];
      L.circleMarker([inicio.lat,inicio.lng],{radius:7,color:"#fff",weight:2,fillColor:"#22C55E",fillOpacity:1})
        .bindPopup(`<b>Inicio</b><br/>${inicio.vehiculo_id||"Vehículo"}${inicio.chofer_id?" · "+inicio.chofer_id:""}<br/>${fmtHora(inicio.timestamp_captura)}`)
        .addTo(map);
      L.circleMarker([fin.lat,fin.lng],{radius:7,color:"#fff",weight:2,fillColor:"#E11D48",fillOpacity:1})
        .bindPopup(`<b>Última posición</b><br/>${fin.vehiculo_id||"Vehículo"}${fin.chofer_id?" · "+fin.chofer_id:""}<br/>${fmtHora(fin.timestamp_captura)}`)
        .addTo(map);
    });
    paradas.forEach((pa,i)=>{
      L.circleMarker([pa.lat,pa.lng],{radius:6,color:"#fff",weight:2,fillColor:"#F59E0B",fillOpacity:1})
        .bindPopup(`<b>Parada ${i+1}</b><br/>${pa.duracionMin} min detenido<br/>${fmtHora(pa.inicio)} – ${fmtHora(pa.fin)}`)
        .addTo(map);
      bounds.push([pa.lat,pa.lng]);
    });
    if(bounds.length) map.fitBounds(bounds,{padding:[24,24]});

    return ()=>{ cancelado=true; if(mapInstanceRef.current){ mapInstanceRef.current.remove(); mapInstanceRef.current=null; } };
  },[puntos]); // eslint-disable-line

  const distanciaTotalKm=(()=>{
    let d=0;
    for(const grupo of gruposPorVehiculo){
      for(let i=1;i<grupo.length;i++){
        d+=distanciaMetros(grupo[i-1].lat,grupo[i-1].lng,grupo[i].lat,grupo[i].lng);
      }
    }
    return (d/1000).toFixed(1);
  })();
  // Tiempo en movimiento/detenido también se suma por vehículo, no de punta
  // a punta del conjunto global (dos móviles en paralelo no deben duplicar
  // ni mezclar sus ventanas de tiempo).
  const tiempoTotalMin=gruposPorVehiculo.reduce((acc,g)=>{
    if(g.length<2) return acc;
    return acc+Math.round((new Date(g[g.length-1].timestamp_captura)-new Date(g[0].timestamp_captura))/60000);
  },0);
  const tiempoDetenidoMin=paradas.reduce((a,p)=>a+p.duracionMin,0);
  const tiempoMovimientoMin=Math.max(0,tiempoTotalMin-tiempoDetenidoMin);
  const velocidadPromKmh=tiempoMovimientoMin>0?(parseFloat(distanciaTotalKm)/(tiempoMovimientoMin/60)).toFixed(1):"0.0";

  function exportarExcel(){
    const wb=XLSX.utils.book_new();
    const hojaPuntos=puntos.map(p=>({
      Vehiculo:p.vehiculo_id, Chofer:p.chofer_id, Origen:p.origen,
      Latitud:p.lat, Longitud:p.lng, "Velocidad (km/h)":p.velocidad_kmh,
      "Precisión (m)":p.precision_m, Timestamp:fmtHora(p.timestamp_captura),
    }));
    const hojaParadas=paradas.map((p,i)=>({
      "#":i+1, Latitud:p.lat, Longitud:p.lng,
      Inicio:fmtHora(p.inicio), Fin:fmtHora(p.fin), "Duración (min)":p.duracionMin,
    }));
    XLSX.utils.book_append_sheet(wb,XLSX.utils.json_to_sheet(hojaPuntos),"Puntos GPS");
    XLSX.utils.book_append_sheet(wb,XLSX.utils.json_to_sheet(hojaParadas),"Paradas");
    const ts=new Date().toISOString().split("T")[0];
    XLSX.writeFile(wb,`Trazabilidad_${filtroVehiculo||"Flota"}_${ts}.xlsx`);
  }

  return(
    <div style={S.section}>
      <div style={S.pageTitle}>Trazabilidad de Flota</div>

      <div style={S.filters}>
        <select style={S.select} value={filtroVehiculo} onChange={e=>setFiltroVehiculo(e.target.value)}>
          <option value="">Todos los vehículos</option>
          {vehiculos.map(v=><option key={v.ppu} value={v.ppu}>{v.ppu}</option>)}
        </select>
        <select style={S.select} value={filtroChofer} onChange={e=>setFiltroChofer(e.target.value)}>
          <option value="">Todos los choferes</option>
          {choferes.map(c=><option key={c.nombre} value={c.nombre}>{c.nombre}</option>)}
        </select>
        <input style={S.input} type="date" value={fechaDesde} onChange={e=>setFechaDesde(e.target.value)}/>
        <input style={S.input} type="date" value={fechaHasta} onChange={e=>setFechaHasta(e.target.value)}/>
        <button style={S.btnPri} onClick={buscar} disabled={loading}>{loading?"Buscando...":"Buscar"}</button>
        {puntos.length>0&&<button style={S.btnSec} onClick={exportarExcel}>⬇ Exportar Excel</button>}
      </div>

      {error&&<div style={{color:C.danger,fontSize:13}}>{error}</div>}

      {!buscado?(
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:12,padding:"40px 0",color:C.muted}}>
          <p style={{margin:0,fontWeight:600}}>Selecciona filtros y presiona Buscar</p>
        </div>
      ):loading?(
        <div style={S.loadingWrap}><div style={S.spinner}/><p style={{color:C.muted}}>Cargando trazabilidad...</p></div>
      ):puntos.length===0?(
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:12,padding:"40px 0",color:C.muted}}>
          <div style={{fontSize:36}}>·</div>
          <p style={{margin:0,fontWeight:600}}>Sin datos de trazabilidad para este filtro</p>
        </div>
      ):(
        <>
          <div style={S.statsGrid}>
            <div style={S.statCard}><div style={{...S.statNum,color:C.cyan}}>{distanciaTotalKm}</div><div style={S.statLabel}>KM recorridos</div></div>
            <div style={S.statCard}><div style={{...S.statNum,color:C.success}}>{Math.floor(tiempoMovimientoMin/60)}h {tiempoMovimientoMin%60}m</div><div style={S.statLabel}>En movimiento</div></div>
            <div style={S.statCard}><div style={{...S.statNum,color:C.warning}}>{Math.floor(tiempoDetenidoMin/60)}h {tiempoDetenidoMin%60}m</div><div style={S.statLabel}>Detenido</div></div>
            <div style={S.statCard}><div style={S.statNum}>{velocidadPromKmh}</div><div style={S.statLabel}>Vel. promedio km/h</div></div>
            <div style={S.statCard}><div style={S.statNum}>{paradas.length}</div><div style={S.statLabel}>Paradas detectadas</div></div>
          </div>

          <div ref={mapDivRef} style={{width:"100%",height:460,borderRadius:12,overflow:"hidden",border:"1px solid "+C.border}}/>
          <div style={{fontSize:11,color:C.muted}}>Toca cualquier punto del mapa (inicio, última posición o parada) para ver el detalle.</div>

          <div style={S.sectionTitle}>Paradas detectadas ({paradas.length})</div>
          {paradas.length===0?(
            <div style={{color:C.muted,fontSize:13}}>No se detectaron paradas de más de 3 minutos en el rango seleccionado.</div>
          ):paradas.map((p,i)=>(
            <div key={i} style={S.row}>
              <div style={{...S.rowIcon,background:C.warning+"22",color:C.warning}}>{i+1}</div>
              <div style={S.rowBody}>
                <div style={S.rowTitle}>{fmtHora(p.inicio)} → {fmtHora(p.fin)}</div>
                <div style={{...S.rowMeta,color:C.textSecondary}}>
                  {p.duracionMin} min detenido · {p.lat.toFixed(5)}, {p.lng.toFixed(5)}
                </div>
              </div>
            </div>
          ))}
        </>
      )}
    </div>
  );
}

// ── Incidencias (no conformidades NT147, cumplimiento, etc.) ──────────────
function Incidencias({incidencias=[],onSave,onDelete,sesion,vehiculos=[],clientes=[]}){
  const puedeEditar = ["admin","operador"].includes(sesion?.perfil);
  const puedeEliminar = sesion?.perfil==="admin";
  const [nuevo,setNuevo]=useState(false);
  const [editId,setEditId]=useState(null);
  const [expandId,setExpandId]=useState(null);
  const [fEstado,setFEstado]=useState("todas");
  const [fTipo,setFTipo]=useState("todos");
  const EMPTY={fecha:new Date().toISOString().slice(0,10),tipo:"anden_incompatible",contraparte:"",ubicacion:"",descripcion:"",fotos:[],notificado:false,fechaNotificacion:"",estado:"abierta"};
  const [form,setForm]=useState(EMPTY);
  const [subiendo,setSubiendo]=useState(false);

  const FOTO_MAX=1400, FOTO_CALIDAD=0.8;
  function comprimirImagen(file, cb){
    const reader=new FileReader();
    reader.onload=ev=>{
      const img=new Image();
      img.onload=()=>{
        const canvas=document.createElement("canvas");
        let w=img.width,h=img.height;
        if(w>FOTO_MAX){h=Math.round(h*FOTO_MAX/w);w=FOTO_MAX;}
        if(h>FOTO_MAX){w=Math.round(w*FOTO_MAX/h);h=FOTO_MAX;}
        canvas.width=w; canvas.height=h;
        const ctx=canvas.getContext("2d");
        ctx.imageSmoothingEnabled=true; ctx.imageSmoothingQuality="high";
        ctx.drawImage(img,0,0,w,h);
        cb(canvas.toDataURL("image/jpeg",FOTO_CALIDAD));
      };
      img.src=ev.target.result;
    };
    reader.readAsDataURL(file);
  }
  function agregarArchivo(){
    const input=document.createElement("input");
    input.type="file"; input.multiple=true;
    input.accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
    input.onchange=e=>{
      const files=Array.from(e.target.files||[]);
      if(!files.length)return;
      setSubiendo(true);
      let pendientes=files.length;
      const listo=()=>{ pendientes--; if(pendientes<=0) setSubiendo(false); };
      files.forEach(file=>{
        if(file.type.startsWith("image/")){
          comprimirImagen(file, b64=>{ setForm(p=>({...p,fotos:[...(p.fotos||[]),{name:file.name,type:"image",data:b64}].slice(0,10)})); listo(); });
        }else{
          const reader=new FileReader();
          reader.onload=ev=>{ setForm(p=>({...p,fotos:[...(p.fotos||[]),{name:file.name,type:file.type||"file",data:ev.target.result}].slice(0,10)})); listo(); };
          reader.onerror=listo;
          reader.readAsDataURL(file);
        }
      });
    };
    input.click();
  }
  // Un ítem de evidencia puede venir en formato antiguo (string base64 = foto)
  // o nuevo ({name,type,data}) que admite cualquier tipo de archivo.
  function esImagen(ev){ return typeof ev==="string" || (ev&&ev.type==="image"); }
  function evData(ev){ return typeof ev==="string" ? ev : ev?.data; }
  function evNombre(ev,i){ return typeof ev==="string" ? `Evidencia ${i+1}` : (ev?.name||`Archivo ${i+1}`); }
  function evIcono(ev){
    const n=(typeof ev==="object"&&ev?.name||"").toLowerCase();
    if(n.endsWith(".pdf"))return "📕";
    if(n.endsWith(".doc")||n.endsWith(".docx"))return "📘";
    if(n.endsWith(".xls")||n.endsWith(".xlsx"))return "📗";
    return "📎";
  }

  const lista=incidencias
    .filter(i=>fEstado==="todas"||i.estado===fEstado)
    .filter(i=>fTipo==="todos"||i.tipo===fTipo)
    .sort((a,b)=>(b.fecha||"").localeCompare(a.fecha||"")||(b.createdAt||"").localeCompare(a.createdAt||""));

  const abiertas=incidencias.filter(i=>i.estado==="abierta").length;

  function iniciarNueva(){ setForm(EMPTY); setEditId(null); setNuevo(true); setExpandId(null); }
  function iniciarEdicion(i){ setForm({fecha:i.fecha,tipo:i.tipo,contraparte:i.contraparte,ubicacion:i.ubicacion,descripcion:i.descripcion,fotos:i.fotos||[],notificado:i.notificado,fechaNotificacion:i.fechaNotificacion,estado:i.estado}); setEditId(i.id); setNuevo(true); setExpandId(null); }

  async function guardar(){
    if(!form.descripcion.trim()){window.alert("Describe brevemente la incidencia.");return;}
    if(!form.fecha){window.alert("Indica la fecha.");return;}
    const base=editId?incidencias.find(x=>x.id===editId):null;
    const i={
      id: editId || ("inc_"+Date.now().toString()),
      folio: base?.folio || generarFolioIncidencia(incidencias),
      fecha:form.fecha, tipo:form.tipo, contraparte:form.contraparte||"",
      ubicacion:form.ubicacion||"", descripcion:form.descripcion.trim(),
      fotos:form.fotos||[], notificado:!!form.notificado, fechaNotificacion:form.fechaNotificacion||"",
      estado:form.estado||"abierta", autor: base?.autor || (sesion?.nombre||sesion?.email||"—"),
      origen: base?.origen || "manual",
    };
    const ok=await onSave(i);
    if(ok){ setNuevo(false); setEditId(null); setForm(EMPTY); }
  }

  return(
    <div style={S.section}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div>
          <div style={S.pageTitle}>Incidencias</div>
          <div style={{fontSize:12,color:C.textSecondary,marginTop:2}}>No conformidades, cumplimiento NT147 y hallazgos operativos.</div>
        </div>
        {puedeEditar&&!nuevo&&<button style={S.btnPri} onClick={iniciarNueva}>+ Nueva incidencia</button>}
      </div>

      <div style={S.statsGrid}>
        <div style={{...S.statCard,borderTop:`3px solid ${C.danger}`}}><div style={{...S.statNum,color:C.danger}}>{abiertas}</div><div style={S.statLabel}>Abiertas</div></div>
        <div style={{...S.statCard,borderTop:`3px solid ${C.warning}`}}><div style={{...S.statNum,color:C.warning}}>{incidencias.filter(i=>i.estado==="en_revision").length}</div><div style={S.statLabel}>En revisión</div></div>
        <div style={{...S.statCard,borderTop:`3px solid ${C.success}`}}><div style={{...S.statNum,color:C.success}}>{incidencias.filter(i=>i.estado==="cerrada").length}</div><div style={S.statLabel}>Cerradas</div></div>
        <div style={{...S.statCard,borderTop:`3px solid ${C.cyan}`}}><div style={{...S.statNum,color:C.cyan}}>{incidencias.length}</div><div style={S.statLabel}>Total</div></div>
      </div>

      {nuevo&&(
        <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px 18px",display:"flex",flexDirection:"column",gap:12}}>
          <div style={{fontSize:13,fontWeight:800,color:C.cyan}}>{editId?"Editar incidencia":"Nueva incidencia"}</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(180px,1fr))",gap:10}}>
            <div style={S.fGroup}><label style={S.label}>Fecha</label>
              <input style={S.input} type="date" value={form.fecha} onChange={e=>setForm(p=>({...p,fecha:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Tipo</label>
              <select style={S.input} value={form.tipo} onChange={e=>setForm(p=>({...p,tipo:e.target.value}))}>
                {Object.entries(TIPO_INCIDENCIA).map(([k,m])=><option key={k} value={k}>{m.icon} {m.label}</option>)}
              </select></div>
            <div style={S.fGroup}><label style={S.label}>Contraparte (Abbott/DHL/otro)</label>
              <input style={S.input} placeholder="Ej: DHL" value={form.contraparte} onChange={e=>setForm(p=>({...p,contraparte:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Ubicación / andén</label>
              <input style={S.input} placeholder="Ej: Andén 32" value={form.ubicacion} onChange={e=>setForm(p=>({...p,ubicacion:e.target.value}))}/></div>
          </div>
          <div style={S.fGroup}><label style={S.label}>Descripción</label>
            <textarea style={{...S.input,minHeight:80,fontFamily:"inherit",resize:"vertical"}} placeholder="Describe el hallazgo, condición o desviación detectada..." value={form.descripcion} onChange={e=>setForm(p=>({...p,descripcion:e.target.value}))}/></div>
          <div style={{display:"flex",gap:16,alignItems:"center",flexWrap:"wrap"}}>
            <label style={{display:"flex",alignItems:"center",gap:8,fontSize:13,color:C.textSecondary,cursor:"pointer"}}>
              <input type="checkbox" checked={form.notificado} onChange={e=>setForm(p=>({...p,notificado:e.target.checked}))}/>
              Se notificó a la contraparte
            </label>
            {form.notificado&&<input style={{...S.input,maxWidth:180}} type="date" value={form.fechaNotificacion} onChange={e=>setForm(p=>({...p,fechaNotificacion:e.target.value}))}/>}
            {editId&&(
              <select style={{...S.input,maxWidth:180}} value={form.estado} onChange={e=>setForm(p=>({...p,estado:e.target.value}))}>
                {Object.entries(ESTADO_INCIDENCIA).map(([k,m])=><option key={k} value={k}>{m.label}</option>)}
              </select>
            )}
          </div>
          <div>
            <label style={S.label}>Evidencia (fotos, PDF, Word, Excel, capturas)</label>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",marginTop:6}}>
              {(form.fotos||[]).map((ev,i)=>(
                <div key={i} style={{position:"relative"}}>
                  {esImagen(ev)
                    ?<img src={evData(ev)} alt={evNombre(ev,i)} style={{width:80,height:80,borderRadius:8,objectFit:"cover",border:"1px solid "+C.border}}/>
                    :<div style={{width:80,height:80,borderRadius:8,border:"1px solid "+C.border,background:C.navy,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,padding:4}}>
                        <div style={{fontSize:22}}>{evIcono(ev)}</div>
                        <div style={{fontSize:8,color:C.muted,textAlign:"center",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:72}}>{evNombre(ev,i)}</div>
                      </div>}
                  <button style={{position:"absolute",top:-6,right:-6,background:C.danger,border:"none",color:"#fff",borderRadius:"50%",width:20,height:20,fontSize:11,cursor:"pointer",lineHeight:1}} onClick={()=>setForm(p=>({...p,fotos:p.fotos.filter((_,j)=>j!==i)}))}>✕</button>
                </div>
              ))}
              {(form.fotos||[]).length<10&&<button style={{...S.exportBtn,width:80,height:80,fontSize:11}} disabled={subiendo} onClick={agregarArchivo}>{subiendo?"...":"📎 Agregar"}</button>}
            </div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button style={S.btnSec} onClick={()=>{setNuevo(false);setEditId(null);setForm(EMPTY);}}>Cancelar</button>
            <button style={S.btnPri} onClick={guardar}>Guardar</button>
          </div>
        </div>
      )}

      <div style={S.filters}>
        <select style={S.select} value={fEstado} onChange={e=>setFEstado(e.target.value)}>
          <option value="todas">Todos los estados</option>
          {Object.entries(ESTADO_INCIDENCIA).map(([k,m])=><option key={k} value={k}>{m.label}</option>)}
        </select>
        <select style={S.select} value={fTipo} onChange={e=>setFTipo(e.target.value)}>
          <option value="todos">Todos los tipos</option>
          {Object.entries(TIPO_INCIDENCIA).map(([k,m])=><option key={k} value={k}>{m.icon} {m.label}</option>)}
        </select>
      </div>

      {lista.length===0?(
        <EmptyState msg="Sin incidencias registradas para este filtro."/>
      ):lista.map(i=>{
        const tm=metaTipoIncidencia(i.tipo);
        const em=ESTADO_INCIDENCIA[i.estado]||ESTADO_INCIDENCIA.abierta;
        const expandido=expandId===i.id;
        return (
          <div key={i.id} style={{...S.row,flexDirection:"column",alignItems:"stretch",cursor:"pointer"}} onClick={()=>setExpandId(expandido?null:i.id)}>
            <div style={{display:"flex",alignItems:"center",gap:14}}>
              <div style={{...S.rowIcon,background:tm.color+"22",color:tm.color}}>{tm.icon}</div>
              <div style={S.rowBody}>
                <div style={S.rowTitle}>{i.folio} · {tm.label}{i.contraparte?` · ${i.contraparte}`:""}</div>
                <div style={{...S.rowMeta,color:C.textSecondary}}>{i.fecha}{i.ubicacion?` · ${i.ubicacion}`:""}</div>
              </div>
              <span style={{...S.badge,background:em.color+"22",color:em.color,flexShrink:0}}>{em.label}</span>
            </div>
            {expandido&&(
              <div style={{marginTop:12,paddingTop:12,borderTop:"1px solid "+C.border,display:"flex",flexDirection:"column",gap:10}} onClick={e=>e.stopPropagation()}>
                <div style={{fontSize:13,color:C.textPrimary}}>{i.descripcion}</div>
                <div style={{fontSize:11.5,color:C.muted}}>
                  Registrado por {i.autor||"—"}{i.origen==="alerta"?" · generado desde alerta de flota":i.origen==="sistema"?" · generado automáticamente por el sistema":""}
                  {i.notificado?` · Notificado a la contraparte${i.fechaNotificacion?" el "+i.fechaNotificacion:""}`:" · Sin notificar a la contraparte"}
                </div>
                {(i.fotos||[]).length>0&&(
                  <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                    {i.fotos.map((ev,idx)=>(
                      <a key={idx} href={esImagen(ev)?ev:ev?.data} download={evNombre(ev,idx)} target="_blank" rel="noreferrer" title={evNombre(ev,idx)}>
                        {esImagen(ev)
                          ?<img src={typeof ev==="string"?ev:ev.data} alt={evNombre(ev,idx)} style={{width:88,height:88,borderRadius:8,objectFit:"cover",border:"1px solid "+C.border}}/>
                          :<div style={{width:88,height:88,borderRadius:8,border:"1px solid "+C.border,background:C.navy,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,padding:4}}>
                              <div style={{fontSize:24}}>{evIcono(ev)}</div>
                              <div style={{fontSize:9,color:C.muted,textAlign:"center",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:80}}>{evNombre(ev,idx)}</div>
                            </div>}
                      </a>
                    ))}
                  </div>
                )}
                {puedeEditar&&(
                  <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                    {Object.entries(ESTADO_INCIDENCIA).filter(([k])=>k!==i.estado).map(([k,m])=>(
                      <button key={k} style={{...S.statusBtn,border:"1px solid "+m.color,color:m.color}} onClick={()=>onSave({...i,estado:k})}>Marcar {m.label}</button>
                    ))}
                    <button style={{...S.exportBtn,fontSize:12}} onClick={()=>iniciarEdicion(i)}>✎ Editar</button>
                    {puedeEliminar&&<button style={{...S.exportBtn,fontSize:12,borderColor:C.danger,color:C.danger}} onClick={()=>{if(window.confirm("¿Eliminar esta incidencia?"))onDelete(i.id);}}>Eliminar</button>}
                  </div>
                )}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}
function estadoVencimiento(fecha){
  if(!fecha) return null;
  const hoy=new Date(); hoy.setHours(0,0,0,0);
  const v=new Date(fecha+"T12:00:00");
  if(isNaN(v)) return null;
  const dias=Math.round((v-hoy)/86400000);
  if(dias<0) return {dias, label:`Vencido hace ${Math.abs(dias)} d`, color:C.danger};
  if(dias<=30) return {dias, label:`Vence en ${dias} d`, color:C.warning};
  return {dias, label:"Vigente", color:C.success};
}
// Cuenta rápida de alertas pendientes (para el badge de la campana en el header).
function calcularAlertas(gastos, recordatorios, limiteDias=60){
  const dismissedIds=new Set((recordatorios||[]).map(r=>r.id));
  const map={};
  (gastos||[]).forEach(g=>{
    if(!g.vencimiento||!metaCategoria(g.categoria).vencimiento)return;
    const k=g.ppu+"|"+g.categoria;
    if(!map[k]||g.vencimiento>map[k].vencimiento)map[k]=g;
  });
  const auto=Object.values(map).map(g=>({id:"venc_"+g.ppu+"_"+g.categoria, fecha:g.vencimiento, est:estadoVencimiento(g.vencimiento)}))
    .filter(it=>!dismissedIds.has(it.id));
  const manual=(recordatorios||[]).filter(r=>!(r.notas||"").startsWith("Ticket ")&&!r.hecho)
    .map(r=>({id:r.id, fecha:r.fecha, est:estadoVencimiento(r.fecha)}));
  const items=[...auto,...manual].filter(it=>it.est&&it.est.dias<=limiteDias);
  const nVencidos=items.filter(it=>it.est.dias<0).length;
  return {total:items.length, vencidos:nVencidos};
}

function GastosVehiculos({gastos=[],vehiculos=[],choferes=[],onSaveGasto,onDeleteGasto,setView,sesion}){
  const soloLectura = sesion?.perfil==="cliente";
  const [fPpu,setFPpu]=useState("todos");
  const [fCat,setFCat]=useState("todos");
  const [fMes,setFMes]=useState("todos");
  const [fQ,setFQ]=useState("");
  const [nuevo,setNuevo]=useState(false);
  const [editId,setEditId]=useState(null);
  const EMPTY={ppu:"",fecha:new Date().toISOString().slice(0,10),categoria:"combustible",monto:"",proveedor:"",documento:"",odometro:"",vencimiento:"",notas:""};
  const [form,setForm]=useState(EMPTY);

  const ppusDisponibles=(vehiculos||[]).filter(v=>v&&v.ppu).map(v=>v.ppu);
  const descPpu=(ppu)=>{
    const v=(vehiculos||[]).find(x=>x.ppu===ppu);
    const ch=(choferes||[]).find(c=>c.ppu===ppu);
    const partes=[v&&[v.marca,v.modelo].filter(Boolean).join(" "),ch&&ch.nombre].filter(Boolean);
    return partes.length?partes.join(" · "):"";
  };

  const meses=Array.from(new Set(gastos.map(g=>(g.fecha||"").slice(0,7)).filter(Boolean))).sort().reverse();

  const lista=gastos.filter(g=>{
    if(fPpu!=="todos"&&g.ppu!==fPpu)return false;
    if(fCat!=="todos"&&g.categoria!==fCat)return false;
    if(fMes!=="todos"&&(g.fecha||"").slice(0,7)!==fMes)return false;
    if(fQ.trim()){
      const q=fQ.toLowerCase();
      const hay=[g.descripcion,g.proveedor,g.documento,g.ppu,metaCategoria(g.categoria).label].join(" ").toLowerCase();
      if(!hay.includes(q))return false;
    }
    return true;
  }).sort((a,b)=>(b.fecha||"").localeCompare(a.fecha||""));

  const total=lista.reduce((s,g)=>s+(Number(g.monto)||0),0);
  const totalFijo=lista.filter(g=>metaCategoria(g.categoria).tipo==="fijo").reduce((s,g)=>s+(Number(g.monto)||0),0);
  const totalVar=total-totalFijo;

  // Próximos vencimientos: último registro por (ppu+categoría con vencimiento)
  const vencs=(()=>{
    const map={};
    gastos.forEach(g=>{
      if(!g.vencimiento||!metaCategoria(g.categoria).vencimiento)return;
      const k=g.ppu+"|"+g.categoria;
      if(!map[k]||(g.vencimiento>map[k].vencimiento)) map[k]=g;
    });
    return Object.values(map)
      .map(g=>({...g,est:estadoVencimiento(g.vencimiento)}))
      .filter(g=>g.est&&g.est.dias<=45)
      .sort((a,b)=>a.est.dias-b.est.dias);
  })();

  function guardar(){
    if(!form.ppu){window.alert("Selecciona la PPU del vehículo.");return;}
    if(form.monto===""||isNaN(Number(form.monto))){window.alert("Ingresa el monto del gasto.");return;}
    const g={
      id: editId || ("g_"+Date.now()+"_"+Math.random().toString(36).slice(2,7)),
      ppu:form.ppu, fecha:form.fecha||new Date().toISOString().slice(0,10),
      categoria:form.categoria, descripcion:form.descripcion||"",
      monto:Number(form.monto), proveedor:form.proveedor||"", documento:form.documento||"",
      odometro:form.odometro===""?"":Number(form.odometro),
      vencimiento:metaCategoria(form.categoria).vencimiento?(form.vencimiento||""):"",
      notas:form.notas||"",
    };
    onSaveGasto(g).then(ok=>{ if(ok){ setNuevo(false); setEditId(null); setForm(EMPTY); } });
  }

  function exportarBitacora(){
    const cab=["Fecha","PPU","Vehículo","Categoría","Tipo","Descripción","Monto (CLP)","Proveedor/Taller","N° Documento","Odómetro (km)","Próx. vencimiento"];
    const filas=lista.map(g=>{
      const m=metaCategoria(g.categoria);
      return [g.fecha||"", g.ppu||"", descPpu(g.ppu), m.label, m.tipo, g.descripcion||"",
        Number(g.monto)||0, g.proveedor||"", g.documento||"", g.odometro===""||g.odometro==null?"":Number(g.odometro), g.vencimiento||""];
    });
    filas.push([]);
    filas.push(["","","","","","TOTAL", total, "", "", "", ""]);
    const ws=XLSX.utils.aoa_to_sheet([cab,...filas]);
    ws["!cols"]=[{wch:12},{wch:10},{wch:22},{wch:22},{wch:9},{wch:30},{wch:14},{wch:22},{wch:16},{wch:14},{wch:14}];
    const wb=XLSX.utils.book_new();

    // ── Resumen Ejecutivo: costo por vehículo, mes a mes (según filtro activo) ──
    const mesesOrdenados=Array.from(new Set(lista.map(g=>(g.fecha||"").slice(0,7)).filter(Boolean))).sort();
    const ppusEnLista=Array.from(new Set(lista.map(g=>g.ppu).filter(Boolean)));
    const cabResumen=["PPU","Vehículo",...mesesOrdenados,"Total"];
    const filasResumen=ppusEnLista.map(ppu=>{
      const porMes={}; mesesOrdenados.forEach(m=>porMes[m]=0);
      let totalPpu=0;
      lista.filter(g=>g.ppu===ppu).forEach(g=>{
        const m=(g.fecha||"").slice(0,7);
        if(porMes[m]!=null){ const v=Number(g.monto)||0; porMes[m]+=v; totalPpu+=v; }
      });
      return [ppu, descPpu(ppu), ...mesesOrdenados.map(m=>porMes[m]), totalPpu];
    });
    const totalesPorMes=mesesOrdenados.map(m=>lista.filter(g=>(g.fecha||"").slice(0,7)===m).reduce((s,g)=>s+(Number(g.monto)||0),0));
    const totalGeneral=totalesPorMes.reduce((a,b)=>a+b,0);
    filasResumen.push([]);
    filasResumen.push(["","TOTAL MENSUAL",...totalesPorMes,totalGeneral]);

    // Bloque adicional: total por categoría (todas las PPU del filtro activo)
    const catsPresentes=Array.from(new Set(lista.map(g=>g.categoria)));
    const filasCategoria=[[],["Resumen por categoría"],["Categoría","Tipo","Total (CLP)"]];
    catsPresentes
      .map(c=>({c,m:metaCategoria(c),t:lista.filter(g=>g.categoria===c).reduce((s,g)=>s+(Number(g.monto)||0),0)}))
      .sort((a,b)=>b.t-a.t)
      .forEach(({c,m,t})=>filasCategoria.push([m.label, m.tipo==="fijo"?"Fijo":"Variable", t]));

    const wsResumen=XLSX.utils.aoa_to_sheet([cabResumen,...filasResumen,...filasCategoria]);
    wsResumen["!cols"]=[{wch:10},{wch:24},...mesesOrdenados.map(()=>({wch:13})),{wch:14}];
    XLSX.utils.book_append_sheet(wb,wsResumen,"Resumen Ejecutivo");
    XLSX.utils.book_append_sheet(wb,ws,"Bitácora");
    XLSX.writeFile(wb,`Quantrex_Bitacora_Vehiculos_${new Date().toISOString().slice(0,10)}.xlsx`);
  }

  const catMeta=metaCategoria(form.categoria);

  return(
    <div style={S.section}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={S.pageTitle}>Bitácora de Costos por Vehículo</div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          {gastos.length>0&&<button style={{...S.exportBtn,display:"flex",alignItems:"center",gap:6}} onClick={exportarBitacora}><span>📥</span><span>Excel</span></button>}
          <button style={{...S.exportBtn,display:"flex",alignItems:"center",gap:6}} onClick={()=>setView("certificado_aseo")}><span>🧾</span><span>Certificado de Aseo</span></button>
          {!soloLectura&&<button style={S.btnPri} onClick={()=>{setNuevo(true);setEditId(null);setForm(EMPTY);}}>+ Nuevo gasto</button>}
        </div>
      </div>
      <div style={{fontSize:12.5,color:C.textSecondary,marginTop:-6}}>
        Registra todo costo asociado a cada patente (PPU): combustible, mantención, repuestos, neumáticos, accesorios, revisión técnica, permiso de circulación, SOAP, seguros, peajes/TAG, multas y partes. Cada registro alimenta el total por vehículo del panel.
      </div>

      {/* Resumen filtrado */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))",gap:12}}>
        <div style={{...S.statCard,borderTop:`3px solid ${C.cyan}`}}>
          <div style={{fontSize:24,fontWeight:900,color:C.cyan,lineHeight:1.1}}>{fmtCLP(total)}</div>
          <div style={S.statLabel}>Total ({lista.length} registros)</div>
        </div>
        <div style={{...S.statCard,borderTop:`3px solid ${C.warning}`}}>
          <div style={{fontSize:24,fontWeight:900,color:C.warning,lineHeight:1.1}}>{fmtCLP(totalVar)}</div>
          <div style={S.statLabel}>Costos variables</div>
        </div>
        <div style={{...S.statCard,borderTop:`3px solid ${C.success}`}}>
          <div style={{fontSize:24,fontWeight:900,color:C.success,lineHeight:1.1}}>{fmtCLP(totalFijo)}</div>
          <div style={S.statLabel}>Costos fijos</div>
        </div>
      </div>

      {/* Próximos vencimientos */}
      {vencs.length>0&&(
        <div style={{background:C.navySurface,border:"1px solid "+C.warning,borderRadius:12,padding:"12px 16px",display:"flex",flexDirection:"column",gap:8}}>
          <div style={{fontSize:11,fontWeight:700,color:C.warning,letterSpacing:1.2,textTransform:"uppercase"}}>⏰ Próximos vencimientos (45 días)</div>
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {vencs.map((g,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:10,flexWrap:"wrap",fontSize:13}}>
                <span style={{fontWeight:700,color:C.textPrimary}}>{g.ppu}</span>
                <span style={{color:C.textSecondary}}>{metaCategoria(g.categoria).icon} {metaCategoria(g.categoria).label}</span>
                <span style={{color:C.muted}}>· {g.vencimiento}</span>
                <span style={{...S.badge,background:g.est.color+"22",color:g.est.color}}>{g.est.label}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Formulario */}
      {(nuevo||editId)&&!soloLectura&&(
        <div style={{background:C.navySurface,border:"1px solid "+C.cyan,borderRadius:12,padding:"16px"}}>
          <div style={{fontWeight:700,color:C.cyan,marginBottom:12}}>{editId?"Editar gasto":"Nuevo gasto"}</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))",gap:10}}>
            <div style={S.fGroup}><label style={S.label}>Vehículo (PPU)</label>
              {ppusDisponibles.length>0?(
                <select style={S.input} value={form.ppu} onChange={e=>setForm(p=>({...p,ppu:e.target.value}))}>
                  <option value="">— Selecciona —</option>
                  {ppusDisponibles.map(p=><option key={p} value={p}>{p}{descPpu(p)?" · "+descPpu(p):""}</option>)}
                </select>
              ):(
                <input style={S.input} placeholder="Ej: KRYX27" value={form.ppu} onChange={e=>setForm(p=>({...p,ppu:e.target.value.toUpperCase().replace(/\s/g,"")}))}/>
              )}
            </div>
            <div style={S.fGroup}><label style={S.label}>Fecha</label>
              <input style={S.input} type="date" value={form.fecha} onChange={e=>setForm(p=>({...p,fecha:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Categoría</label>
              <select style={S.input} value={form.categoria} onChange={e=>setForm(p=>({...p,categoria:e.target.value}))}>
                {Object.entries(GASTO_CATEGORIAS).map(([k,m])=><option key={k} value={k}>{m.icon} {m.label}</option>)}
              </select></div>
            <div style={S.fGroup}><label style={S.label}>Monto (CLP)</label>
              <input style={S.input} inputMode="numeric" placeholder="Ej: 45000" value={form.monto}
                onChange={e=>setForm(p=>({...p,monto:e.target.value.replace(/\D/g,"")}))}/>
              {form.monto!==""&&<div style={{fontSize:11,color:C.cyan,marginTop:2}}>{fmtCLP(form.monto)}</div>}
            </div>
            <div style={S.fGroup}><label style={S.label}>Proveedor / Taller</label>
              <input style={S.input} placeholder="Ej: Copec, Taller X" value={form.proveedor} onChange={e=>setForm(p=>({...p,proveedor:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>N° Documento (boleta/factura/folio)</label>
              <input style={S.input} placeholder="Ej: 12345" value={form.documento} onChange={e=>setForm(p=>({...p,documento:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Odómetro (km) — opcional</label>
              <input style={S.input} inputMode="numeric" placeholder="Ej: 84200" value={form.odometro}
                onChange={e=>setForm(p=>({...p,odometro:e.target.value.replace(/\D/g,"")}))}/></div>
            {catMeta.vencimiento&&(
              <div style={S.fGroup}><label style={S.label}>Próximo vencimiento</label>
                <input style={S.input} type="date" value={form.vencimiento} onChange={e=>setForm(p=>({...p,vencimiento:e.target.value}))}/></div>
            )}
          </div>
          <div style={{...S.fGroup,marginTop:10}}><label style={S.label}>Descripción / Notas</label>
            <input style={S.input} placeholder="Ej: Cambio de aceite y filtros" value={form.notas} onChange={e=>setForm(p=>({...p,notas:e.target.value}))}/></div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
            <button style={S.btnSec} onClick={()=>{setNuevo(false);setEditId(null);setForm(EMPTY);}}>Cancelar</button>
            <button style={S.btnPri} onClick={guardar}>Guardar</button>
          </div>
        </div>
      )}

      {/* Filtros */}
      <div style={S.filters}>
        <input style={S.searchInput} placeholder="Buscar (descripción, proveedor, documento...)" value={fQ} onChange={e=>setFQ(e.target.value)}/>
        <select style={S.select} value={fPpu} onChange={e=>setFPpu(e.target.value)}>
          <option value="todos">Todas las PPU</option>
          {Array.from(new Set([...ppusDisponibles,...gastos.map(g=>g.ppu)].filter(Boolean))).map(p=><option key={p} value={p}>{p}</option>)}
        </select>
        <select style={S.select} value={fCat} onChange={e=>setFCat(e.target.value)}>
          <option value="todos">Todas las categorías</option>
          {Object.entries(GASTO_CATEGORIAS).map(([k,m])=><option key={k} value={k}>{m.label}</option>)}
        </select>
        <select style={S.select} value={fMes} onChange={e=>setFMes(e.target.value)}>
          <option value="todos">Todos los meses</option>
          {meses.map(m=><option key={m} value={m}>{m}</option>)}
        </select>
      </div>

      {/* Listado */}
      {lista.length===0?<EmptyState msg="No hay gastos registrados con estos filtros." action={!soloLectura?()=>{setNuevo(true);setEditId(null);setForm(EMPTY);}:undefined}/>
        :lista.map(g=>{
          const m=metaCategoria(g.categoria);
          const est=estadoVencimiento(g.vencimiento);
          return(
            <div key={g.id} style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:12,padding:"12px 16px",display:"flex",alignItems:"center",gap:14}}>
              <div style={{width:40,height:40,borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,background:m.color+"22",color:m.color,flexShrink:0}}>{m.icon}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:700,fontSize:13.5,display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                  <span style={{color:C.cyan}}>{g.ppu}</span>
                  <span style={{color:C.textPrimary}}>{m.label}</span>
                  {est&&<span style={{...S.badge,background:est.color+"22",color:est.color,fontSize:10}}>{est.label}</span>}
                </div>
                <div style={{fontSize:12,color:C.muted,marginTop:2}}>
                  {g.fecha}{g.notas?" · "+g.notas:""}{g.proveedor?" · "+g.proveedor:""}{g.documento?" · N° "+g.documento:""}{g.odometro!==""&&g.odometro!=null?" · "+Number(g.odometro).toLocaleString("es-CL")+" km":""}
                </div>
              </div>
              <div style={{textAlign:"right",flexShrink:0}}>
                <div style={{fontSize:15,fontWeight:900,color:m.color}}>{fmtCLP(g.monto)}</div>
                {!soloLectura&&<div style={{display:"flex",gap:6,marginTop:6,justifyContent:"flex-end"}}>
                  <button style={{...S.exportBtn,fontSize:11,padding:"4px 8px"}} onClick={()=>{setEditId(g.id);setNuevo(false);setForm({ppu:g.ppu||"",fecha:g.fecha||new Date().toISOString().slice(0,10),categoria:g.categoria||"otro",monto:g.monto===""||g.monto==null?"":String(g.monto),proveedor:g.proveedor||"",documento:g.documento||"",odometro:g.odometro===""||g.odometro==null?"":String(g.odometro),vencimiento:g.vencimiento||"",notas:g.notas||""});}}>✎</button>
                  <button style={{...S.exportBtn,fontSize:11,padding:"4px 8px",borderColor:C.danger,color:C.danger}} onClick={()=>{if(window.confirm("¿Eliminar este gasto?"))onDeleteGasto(g.id);}}>✕</button>
                </div>}
              </div>
            </div>
          );
        })}
    </div>
  );
}

// ── Certificado de Higienización y Sanitización de Flota ───────────────────
// Filtra solo categoría "Lavado / Aseo" y certifica cumplimiento del programa
// mensual de aseo (relevante para control de plagas y evidencia frente a
// Abbott). Formato inspirado en certificados de limpieza/desinfección de
// transporte usados en logística de alimentos/farma: identifica cada
// vehículo, fecha del servicio, proveedor/ejecutor, y estado de cumplimiento.
function CertificadoAseo({gastos=[],vehiculos=[],choferes=[],setView,sesion}){
  const hoy=new Date();
  const [anio,setAnio]=useState(hoy.getFullYear());
  const [mes,setMes]=useState(hoy.getMonth()+1); // 1-12
  const [responsable,setResponsable]=useState(sesion?.nombre||"");
  const [cargo,setCargo]=useState("Encargado de Flota");
  const [empresa,setEmpresa]=useState("Inversiones Logísticas Quantrex SpA");
  const [programa,setPrograma]=useState("Programa de Aseo Mensual — Control de Plagas y Sanitización de Flota");
  const todasPpus=(vehiculos||[]).filter(v=>v&&v.ppu).map(v=>v.ppu);
  const [ppusSel,setPpusSel]=useState(todasPpus); // por defecto, toda la flota seleccionada
  function togglePpu(ppu){
    setPpusSel(p=>p.includes(ppu)?p.filter(x=>x!==ppu):[...p,ppu]);
  }

  const periodoStr=`${String(mes).padStart(2,"0")}-${anio}`;
  // Período de cierre Quantrex-Abbott: del 26 del mes anterior al 25 del mes
  // seleccionado (mismo criterio que getPeriodoActual/getNombrePeriodo).
  // Ej: "Julio 2026" = 26/06/2026 al 25/07/2026.
  const inicioPeriodo=new Date(anio,mes-2,26);
  const finPeriodo=new Date(anio,mes-1,25);
  const mesLabel=getNombrePeriodo(inicioPeriodo,finPeriodo);
  const fmtFecha=(d)=>d.toLocaleDateString("es-CL",{day:"2-digit",month:"2-digit",year:"numeric"});
  const rangoStr=`${fmtFecha(inicioPeriodo)} – ${fmtFecha(finPeriodo)}`;

  const descPpu=(ppu)=>{
    const v=(vehiculos||[]).find(x=>x.ppu===ppu);
    return v?[v.marca,v.modelo].filter(Boolean).join(" "):"";
  };

  // Solo categoría "lavado", dentro del período de cierre seleccionado
  const registrosMes=gastos.filter(g=>g.categoria==="lavado"&&fechaEnPeriodo(g.fecha,inicioPeriodo,finPeriodo));

  // Agrupa por PPU: todas las fechas de aseo del mes, ordenadas
  const porPpu={};
  registrosMes.forEach(g=>{
    if(!porPpu[g.ppu]) porPpu[g.ppu]=[];
    porPpu[g.ppu].push(g);
  });
  Object.values(porPpu).forEach(arr=>arr.sort((a,b)=>(a.fecha||"").localeCompare(b.fecha||"")));

  // Universo de vehículos a certificar: solo las PPU seleccionadas
  const flota=(vehiculos||[]).filter(v=>v&&v.ppu&&ppusSel.includes(v.ppu));
  const filasCert=flota.map(v=>{
    const regs=porPpu[v.ppu]||[];
    return {
      ppu:v.ppu, desc:descPpu(v.ppu),
      fechas:regs.map(r=>r.fecha),
      proveedores:Array.from(new Set(regs.map(r=>r.proveedor).filter(Boolean))),
      cumple:regs.length>0,
      cantidad:regs.length,
    };
  });
  const cumplen=filasCert.filter(f=>f.cumple).length;
  const noCumplen=filasCert.length-cumplen;

  function imprimir(){ window.print(); }

  return(
    <div style={S.section}>
      <style>{`
        @media print {
          body * { visibility: hidden; }
          #areaCertificado, #areaCertificado * { visibility: visible; }
          #areaCertificado { position: absolute; top: 0; left: 0; width: 100%; }
          .no-imprimir { display: none !important; }
        }
      `}</style>

      <div className="no-imprimir" style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div style={S.pageTitle}>Certificado de Aseo — Flota</div>
        <div style={{display:"flex",gap:8}}>
          <button style={S.btnSec} onClick={()=>setView("gastos")}>← Volver a Bitácora</button>
          <button style={S.btnPri} onClick={imprimir}>🖨 Imprimir / Guardar PDF</button>
        </div>
      </div>

      <div className="no-imprimir" style={{...S.filters}}>
        <select style={S.select} value={mes} onChange={e=>setMes(Number(e.target.value))}>
          {Array.from({length:12},(_,i)=>i+1).map(m=><option key={m} value={m}>{new Date(2024,m-1,1).toLocaleDateString("es-CL",{month:"long"})}</option>)}
        </select>
        <select style={S.select} value={anio} onChange={e=>setAnio(Number(e.target.value))}>
          {[hoy.getFullYear()-1,hoy.getFullYear(),hoy.getFullYear()+1].map(a=><option key={a} value={a}>{a}</option>)}
        </select>
        <input style={S.input} placeholder="Nombre responsable" value={responsable} onChange={e=>setResponsable(e.target.value)}/>
        <input style={S.input} placeholder="Cargo" value={cargo} onChange={e=>setCargo(e.target.value)}/>
      </div>

      <div className="no-imprimir" style={{display:"flex",flexDirection:"column",gap:8}}>
        <div style={S.sectionTitle}>Vehículos a certificar</div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          <button style={{...S.exportBtn,fontSize:11}} onClick={()=>setPpusSel(todasPpus)}>Marcar todos</button>
          <button style={{...S.exportBtn,fontSize:11}} onClick={()=>setPpusSel([])}>Desmarcar todos</button>
        </div>
        <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
          {todasPpus.map(ppu=>{
            const v=(vehiculos||[]).find(x=>x.ppu===ppu);
            const label=v?[ppu,[v.marca,v.modelo].filter(Boolean).join(" ")].filter(Boolean).join(" · "):ppu;
            const on=ppusSel.includes(ppu);
            return(
              <label key={ppu} style={{display:"flex",alignItems:"center",gap:6,background:on?C.cyan+"22":"transparent",border:"1px solid "+(on?C.cyan:C.border),borderRadius:8,padding:"6px 10px",fontSize:12,cursor:"pointer",color:on?C.cyan:C.textSecondary}}>
                <input type="checkbox" checked={on} onChange={()=>togglePpu(ppu)} style={{cursor:"pointer"}}/>
                {label}
              </label>
            );
          })}
          {todasPpus.length===0&&<div style={{fontSize:12,color:C.muted}}>No hay vehículos registrados.</div>}
        </div>
      </div>

      {/* Área certificable: fondo blanco, formato formal, es lo único visible al imprimir */}
      <div id="areaCertificado" style={{background:"#fff",color:"#111",borderRadius:8,padding:"36px 40px",fontFamily:"'DM Sans','Segoe UI',sans-serif"}}>
        <div style={{textAlign:"center",borderBottom:"2px solid #111",paddingBottom:16,marginBottom:20}}>
          <div style={{fontSize:12,letterSpacing:2,color:"#555",fontWeight:700}}>{empresa.toUpperCase()}</div>
          <div style={{fontSize:20,fontWeight:900,marginTop:8,letterSpacing:.5}}>CERTIFICADO DE HIGIENIZACIÓN Y SANITIZACIÓN DE FLOTA VEHICULAR</div>
          <div style={{fontSize:12,color:"#555",marginTop:4}}>{programa}</div>
        </div>

        <p style={{fontSize:13,lineHeight:1.6,marginBottom:16}}>
          Por medio del presente documento, {empresa} certifica que los vehículos detallados a continuación
          fueron sometidos a procedimiento de aseo, higienización y sanitización durante el período{" "}
          <b>{mesLabel}</b> (<b>{rangoStr}</b>), conforme al programa de aseo mensual vigente de la flota, orientado a mantener
          condiciones sanitarias adecuadas y prevención de plagas en unidades de transporte.
        </p>

        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,marginBottom:16}}>
          <thead>
            <tr style={{background:"#f0f0f0"}}>
              <th style={{border:"1px solid #ccc",padding:"6px 8px",textAlign:"left"}}>PPU</th>
              <th style={{border:"1px solid #ccc",padding:"6px 8px",textAlign:"left"}}>Vehículo</th>
              <th style={{border:"1px solid #ccc",padding:"6px 8px",textAlign:"left"}}>Fecha(s) de aseo</th>
              <th style={{border:"1px solid #ccc",padding:"6px 8px",textAlign:"left"}}>Proveedor / Ejecutor</th>
              <th style={{border:"1px solid #ccc",padding:"6px 8px",textAlign:"center"}}>Estado</th>
            </tr>
          </thead>
          <tbody>
            {filasCert.map(f=>(
              <tr key={f.ppu}>
                <td style={{border:"1px solid #ccc",padding:"6px 8px",fontWeight:700}}>{f.ppu}</td>
                <td style={{border:"1px solid #ccc",padding:"6px 8px"}}>{f.desc||"—"}</td>
                <td style={{border:"1px solid #ccc",padding:"6px 8px"}}>{f.fechas.length?f.fechas.join(", "):"—"}</td>
                <td style={{border:"1px solid #ccc",padding:"6px 8px"}}>{f.proveedores.length?f.proveedores.join(", "):"—"}</td>
                <td style={{border:"1px solid #ccc",padding:"6px 8px",textAlign:"center",fontWeight:700,color:f.cumple?"#15803D":"#B91C1C"}}>
                  {f.cumple?"CUMPLE":"SIN REGISTRO"}
                </td>
              </tr>
            ))}
            {filasCert.length===0&&(
              <tr><td colSpan={5} style={{border:"1px solid #ccc",padding:"10px",textAlign:"center",color:"#777"}}>No hay vehículos seleccionados para certificar.</td></tr>
            )}
          </tbody>
        </table>

        <p style={{fontSize:12,color:"#333",marginBottom:24}}>
          Resumen del período: <b>{cumplen}</b> de <b>{filasCert.length}</b> vehículo(s) con registro de aseo conforme al programa mensual.
          {noCumplen>0&&<span style={{color:"#B91C1C",fontWeight:700}}> {noCumplen} vehículo(s) sin registro en este período.</span>}
        </p>

        <div style={{display:"flex",justifyContent:"space-between",marginTop:60,fontSize:12}}>
          <div style={{textAlign:"center",width:220}}>
            <div style={{borderTop:"1px solid #111",paddingTop:6}}>{responsable||"________________________"}</div>
            <div style={{color:"#555"}}>{cargo}</div>
          </div>
          <div style={{textAlign:"center",width:220}}>
            <img src={LOGO_QUANTREX_TIMBRE} alt="Timbre Quantrex" style={{width:130,opacity:.85,marginBottom:6}}/>
            <div style={{borderTop:"1px solid #111",paddingTop:6}}>{hoy.toLocaleDateString("es-CL",{day:"2-digit",month:"2-digit",year:"numeric"})}</div>
            <div style={{color:"#555"}}>Fecha de emisión</div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Resumen de costos por vehículo (dashboard) ─────────────────────────────
function ResumenCostosVehiculo({gastos=[],vehiculos=[],inicio,fin,setView}){
  const [modo,setModo]=useState("periodo"); // periodo | historico
  const di=inicio?inicio.toISOString().slice(0,10):null;
  const df=fin?fin.toISOString().slice(0,10):null;
  const enRango=(g)=>{
    if(modo==="historico"||!di||!df)return true;
    const f=g.fecha||"";
    return f>=di&&f<=df;
  };
  const datos=gastos.filter(enRango);
  const total=datos.reduce((s,g)=>s+(Number(g.monto)||0),0);

  // Agrupar por PPU
  const porPpu={};
  datos.forEach(g=>{
    const k=g.ppu||"(sin PPU)";
    if(!porPpu[k])porPpu[k]={ppu:k,total:0,cats:{}};
    porPpu[k].total+=Number(g.monto)||0;
    porPpu[k].cats[g.categoria]=(porPpu[k].cats[g.categoria]||0)+(Number(g.monto)||0);
  });
  const filas=Object.values(porPpu).sort((a,b)=>b.total-a.total);
  const descPpu=(ppu)=>{const v=(vehiculos||[]).find(x=>x.ppu===ppu);return v?[v.marca,v.modelo].filter(Boolean).join(" "):"";};
  const maxTotal=Math.max(1,...filas.map(f=>f.total));

  return(
    <div style={{background:C.navySurface,border:"1px solid "+C.border,borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:14}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:10,flexWrap:"wrap"}}>
        <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:1.5,textTransform:"uppercase"}}>🚚 Costos por Vehículo (PPU)</div>
        <div style={{display:"flex",gap:6}}>
          {[["periodo","Período"],["historico","Histórico"]].map(([id,l])=>(
            <button key={id} style={{...S.statusBtn,fontSize:11,padding:"5px 12px",background:modo===id?C.cyan+"33":"transparent",border:"1px solid "+(modo===id?C.cyan:C.border),color:modo===id?C.cyan:C.muted,fontWeight:700}}
              onClick={()=>setModo(id)}>{l}</button>
          ))}
        </div>
      </div>

      {filas.length===0?(
        <div style={{fontSize:13,color:C.textSecondary,display:"flex",alignItems:"center",gap:10,flexWrap:"wrap"}}>
          <span>Sin gastos registrados {modo==="periodo"?"en el período activo":"aún"}.</span>
          <button style={{...S.exportBtn,fontSize:11}} onClick={()=>setView("gastos")}>Ir a la bitácora →</button>
        </div>
      ):(<>
        <div style={{display:"flex",alignItems:"baseline",gap:10,flexWrap:"wrap"}}>
          <div style={{fontSize:26,fontWeight:900,color:C.cyan}}>{fmtCLP(total)}</div>
          <div style={{fontSize:12,color:C.textSecondary}}>total {modo==="periodo"?"del período":"histórico"} · {filas.length} vehículo(s)</div>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {filas.map(f=>{
            const cats=Object.entries(f.cats).sort((a,b)=>b[1]-a[1]);
            return(
              <div key={f.ppu} style={{display:"flex",flexDirection:"column",gap:6}}>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,flexWrap:"wrap"}}>
                  <div style={{fontSize:13,fontWeight:700,color:C.textPrimary}}>{f.ppu}{descPpu(f.ppu)?<span style={{color:C.muted,fontWeight:500}}> · {descPpu(f.ppu)}</span>:null}</div>
                  <div style={{fontSize:14,fontWeight:900,color:C.cyan}}>{fmtCLP(f.total)}</div>
                </div>
                {/* Barra apilada por categoría */}
                <div style={{display:"flex",height:10,borderRadius:6,overflow:"hidden",background:C.navy,width:`${Math.max(8,(f.total/maxTotal)*100)}%`,minWidth:60}}>
                  {cats.map(([cat,val])=>(
                    <div key={cat} title={`${metaCategoria(cat).label}: ${fmtCLP(val)}`} style={{width:`${(val/f.total)*100}%`,background:metaCategoria(cat).color}}/>
                  ))}
                </div>
                <div style={{display:"flex",gap:10,flexWrap:"wrap",fontSize:11,color:C.textSecondary}}>
                  {cats.slice(0,4).map(([cat,val])=>(
                    <span key={cat} style={{display:"inline-flex",alignItems:"center",gap:4}}>
                      <span style={{width:8,height:8,borderRadius:2,background:metaCategoria(cat).color,display:"inline-block"}}/>
                      {metaCategoria(cat).label} {fmtCLP(val)}
                    </span>
                  ))}
                  {cats.length>4&&<span style={{color:C.muted}}>+{cats.length-4} más</span>}
                </div>
              </div>
            );
          })}
        </div>
        <button style={{...S.linkBtn,alignSelf:"flex-start"}} onClick={()=>setView("gastos")}>Ver bitácora completa →</button>
      </>)}
    </div>
  );
}

// ── Alertas y recordatorios (dashboard) ────────────────────────────────────
const TIPO_RECORDATORIO = {
  pago:       { label:"Pago",              icon:"💳", color:"#F59E0B" },
  tramite:    { label:"Documento / Trámite",icon:"📄", color:"#00AEEF" },
  mantencion: { label:"Mantención prog.",  icon:"🔧", color:"#A78BFA" },
  reunion:    { label:"Reunión / Evento",  icon:"📅", color:"#14B8A6" },
  otro:       { label:"Otro",              icon:"📌", color:"#8BAFD4" },
};
function metaTipoRec(t){ return TIPO_RECORDATORIO[t] || TIPO_RECORDATORIO.otro; }

// ── Incidencias (no conformidades NT147, cumplimiento de flota, etc.) ──────
const TIPO_INCIDENCIA = {
  anden_incompatible: { label:"Andén / vehículo incompatible", icon:"🚛", color:"#F59E0B" },
  temperatura:        { label:"Cadena de frío / temperatura",  icon:"🌡", color:"#EF4444" },
  humedad_hongos:     { label:"Humedad / hongos en instalación",icon:"💧", color:"#8B5CF6" },
  documentacion:      { label:"Documentación / manifiesto",    icon:"📄", color:"#38BDF8" },
  retraso_capacidad:  { label:"Retraso / capacidad excedida",  icon:"⏱", color:"#F97316" },
  precierre_facturacion: { label:"Pre-Cierre / Facturación",   icon:"🧾", color:"#22C55E" },
  cumplimiento_flota: { label:"Cumplimiento de flota",         icon:"🔧", color:"#00AEEF" },
  inactividad_usuario:{ label:"Inactividad de usuario",        icon:"🔒", color:"#EF4444" },
  otro:               { label:"Otro",                          icon:"•",  color:"#8BAFD4" },
};
function metaTipoIncidencia(t){ return TIPO_INCIDENCIA[t] || TIPO_INCIDENCIA.otro; }
const ESTADO_INCIDENCIA = {
  abierta:     { label:"Abierta",      color:"#EF4444" },
  en_revision: { label:"En revisión",  color:"#F59E0B" },
  cerrada:     { label:"Cerrada",      color:"#22C55E" },
};
function generarFolioIncidencia(incidencias){
  let max=0;
  for(const i of (incidencias||[])){
    const m=/^INC-(\d+)$/.exec((i.folio||"").trim());
    if(m){ const n=parseInt(m[1],10); if(n>max) max=n; }
  }
  return `INC-${String(max+1).padStart(3,"0")}`;
}

function AlertasRecordatorios({gastos=[],vehiculos=[],recordatorios=[],onSave,onDelete,onGenerarTicket,setView}){
  const [ventana,setVentana]=useState("mes"); // mes | 60
  const [verHechos,setVerHechos]=useState(false);
  const [nuevo,setNuevo]=useState(false);
  const [editId,setEditId]=useState(null);
  const EMPTY={titulo:"",fecha:new Date().toISOString().slice(0,10),tipo:"pago",ppu:"",notas:""};
  const [form,setForm]=useState(EMPTY);

  const hoy=new Date(); hoy.setHours(0,0,0,0);
  const finMes=new Date(hoy.getFullYear(),hoy.getMonth()+1,0); finMes.setHours(0,0,0,0);
  const diasFinMes=Math.round((finMes-hoy)/86400000);
  const limite=ventana==="mes"?diasFinMes:60;

  const ppusDisponibles=Array.from(new Set([...(vehiculos||[]).map(v=>v&&v.ppu),...gastos.map(g=>g.ppu)].filter(Boolean)));

  // ids ya "resueltos" vía ticket (recordatorio-sombra creado al generar el ticket)
  const dismissedIds=new Set((recordatorios||[]).map(r=>r.id));

  // a) Vencimientos automáticos desde la bitácora (gastos fijos con vencimiento)
  const auto=(()=>{
    const map={};
    gastos.forEach(g=>{
      if(!g.vencimiento||!metaCategoria(g.categoria).vencimiento)return;
      const k=g.ppu+"|"+g.categoria;
      if(!map[k]||g.vencimiento>map[k].vencimiento)map[k]=g;
    });
    return Object.values(map).map(g=>{
      const m=metaCategoria(g.categoria);
      return {kind:"venc", id:"venc_"+g.ppu+"_"+g.categoria, fecha:g.vencimiento,
        titulo:m.label, ppu:g.ppu, icon:m.icon, color:m.color, est:estadoVencimiento(g.vencimiento)};
    }).filter(it=>!dismissedIds.has(it.id));
  })();

  // b) Recordatorios manuales (excluye los "sombra" generados al emitir un ticket)
  const manual=recordatorios.filter(r=>!(r.notas||"").startsWith("Ticket ")).map(r=>{
    const m=metaTipoRec(r.tipo);
    return {kind:"rec", id:r.id, fecha:r.fecha, titulo:r.titulo, ppu:r.ppu, tipo:r.tipo,
      notas:r.notas, hecho:r.hecho, icon:m.icon, color:m.color, est:estadoVencimiento(r.fecha), raw:r};
  });

  const items=[...auto,...manual]
    .filter(it=>it.est) // requiere fecha válida
    .filter(it=>it.kind==="venc" ? it.est.dias<=limite
              : (verHechos ? true : (!it.hecho && it.est.dias<=limite)))
    .sort((a,b)=>a.est.dias-b.est.dias);

  const nVencidos=items.filter(it=>it.est.dias<0&&!(it.kind==="rec"&&it.hecho)).length;

  function guardar(){
    if(!form.titulo.trim()){window.alert("Ponle un título al recordatorio.");return;}
    if(!form.fecha){window.alert("Indica la fecha.");return;}
    const r={
      id: editId || ("r_"+Date.now()+"_"+Math.random().toString(36).slice(2,7)),
      titulo:form.titulo.trim(), fecha:form.fecha, tipo:form.tipo,
      ppu:form.ppu||"", notas:form.notas||"",
      hecho: editId ? (recordatorios.find(x=>x.id===editId)?.hecho||false) : false,
    };
    onSave(r).then(ok=>{ if(ok){ setNuevo(false); setEditId(null); setForm(EMPTY); } });
  }
  function toggleHecho(r){ onSave({...r, hecho:!r.hecho}); }

  return(
    <div style={{background:C.navySurface,border:"1px solid "+(nVencidos>0?C.danger:C.border),borderRadius:14,padding:"16px 18px",display:"flex",flexDirection:"column",gap:12}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:10,flexWrap:"wrap"}}>
        <div style={{fontSize:11,fontWeight:700,color:nVencidos>0?C.danger:C.muted,letterSpacing:1.4,textTransform:"uppercase",display:"flex",alignItems:"center",gap:8}}>
          🔔 Alertas y recordatorios
          {items.length>0&&<span style={{...S.badge,background:(nVencidos>0?C.danger:C.cyan)+"22",color:nVencidos>0?C.danger:C.cyan,fontSize:10}}>{items.length}{nVencidos>0?` · ${nVencidos} vencido(s)`:""}</span>}
        </div>
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {[["mes","Este mes"],["60","60 días"]].map(([id,l])=>(
            <button key={id} style={{...S.statusBtn,fontSize:11,padding:"5px 12px",background:ventana===id?C.cyan+"33":"transparent",border:"1px solid "+(ventana===id?C.cyan:C.border),color:ventana===id?C.cyan:C.muted,fontWeight:700}}
              onClick={()=>setVentana(id)}>{l}</button>
          ))}
          <button style={{...S.exportBtn,fontSize:11,padding:"5px 12px"}} onClick={()=>{setNuevo(v=>!v);setEditId(null);setForm(EMPTY);}}>+ Recordatorio</button>
        </div>
      </div>

      {(nuevo||editId)&&(
        <div style={{background:C.navy,border:"1px solid "+C.cyan,borderRadius:10,padding:"12px 14px"}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))",gap:10}}>
            <div style={S.fGroup}><label style={S.label}>Título</label>
              <input style={S.input} placeholder="Ej: Pagar permiso circulación" value={form.titulo} onChange={e=>setForm(p=>({...p,titulo:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Fecha</label>
              <input style={S.input} type="date" value={form.fecha} onChange={e=>setForm(p=>({...p,fecha:e.target.value}))}/></div>
            <div style={S.fGroup}><label style={S.label}>Tipo</label>
              <select style={S.input} value={form.tipo} onChange={e=>setForm(p=>({...p,tipo:e.target.value}))}>
                {Object.entries(TIPO_RECORDATORIO).map(([k,m])=><option key={k} value={k}>{m.icon} {m.label}</option>)}
              </select></div>
            <div style={S.fGroup}><label style={S.label}>Vehículo (PPU) — opcional</label>
              <select style={S.input} value={form.ppu} onChange={e=>setForm(p=>({...p,ppu:e.target.value}))}>
                <option value="">— Ninguno —</option>
                {ppusDisponibles.map(p=><option key={p} value={p}>{p}</option>)}
              </select></div>
          </div>
          <div style={{...S.fGroup,marginTop:10}}><label style={S.label}>Notas — opcional</label>
            <input style={S.input} placeholder="Detalle del recordatorio" value={form.notas} onChange={e=>setForm(p=>({...p,notas:e.target.value}))}/></div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:10}}>
            <button style={S.btnSec} onClick={()=>{setNuevo(false);setEditId(null);setForm(EMPTY);}}>Cancelar</button>
            <button style={S.btnPri} onClick={guardar}>Guardar</button>
          </div>
        </div>
      )}

      {items.length===0&&!nuevo&&!editId?(
        <div style={{fontSize:13,color:C.textSecondary}}>Sin vencimientos ni recordatorios {ventana==="mes"?"para este mes":"en los próximos 60 días"}. 👍</div>
      ):(
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {items.map(it=>(
            <div key={it.id} style={{display:"flex",alignItems:"center",gap:12,background:C.navy,border:"1px solid "+C.border,borderLeft:"3px solid "+it.est.color,borderRadius:10,padding:"10px 12px",opacity:(it.kind==="rec"&&it.hecho)?0.55:1}}>
              <div style={{fontSize:18,flexShrink:0}}>{it.icon}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:13.5,fontWeight:700,color:C.textPrimary,textDecoration:(it.kind==="rec"&&it.hecho)?"line-through":"none"}}>
                  {it.titulo}{it.ppu?<span style={{color:C.cyan,fontWeight:700}}> · {it.ppu}</span>:null}
                </div>
                <div style={{fontSize:11.5,color:C.muted,marginTop:2}}>
                  {it.fecha}{it.kind==="venc"?" · vencimiento (bitácora)":(it.notas?" · "+it.notas:"")}
                </div>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
                <span style={{...S.badge,background:it.est.color+"22",color:it.est.color,fontSize:10}}>{it.est.label}</span>
                {onGenerarTicket&&<button title="Generar ticket de cumplimiento (la alerta desaparece)" style={{...S.exportBtn,fontSize:11,padding:"4px 8px",borderColor:C.warning,color:C.warning}} onClick={()=>{if(window.confirm(`¿Generar ticket de cumplimiento para "${it.titulo}"? La alerta se marcará como resuelta.`))onGenerarTicket(it);}}>🎫 Ticket</button>}
                {it.kind==="venc"
                  ?<button style={{...S.exportBtn,fontSize:11,padding:"4px 8px"}} onClick={()=>setView("gastos")}>Ver →</button>
                  :<>
                    <button title={it.hecho?"Marcar pendiente":"Marcar hecho"} style={{...S.exportBtn,fontSize:11,padding:"4px 8px",borderColor:it.hecho?C.muted:C.success,color:it.hecho?C.muted:C.success}} onClick={()=>toggleHecho(it.raw)}>✓</button>
                    <button style={{...S.exportBtn,fontSize:11,padding:"4px 8px"}} onClick={()=>{setEditId(it.id);setNuevo(false);setForm({titulo:it.titulo||"",fecha:it.fecha||new Date().toISOString().slice(0,10),tipo:it.tipo||"otro",ppu:it.ppu||"",notas:it.notas||""});}}>✎</button>
                    <button style={{...S.exportBtn,fontSize:11,padding:"4px 8px",borderColor:C.danger,color:C.danger}} onClick={()=>{if(window.confirm("¿Eliminar este recordatorio?"))onDelete(it.id);}}>✕</button>
                  </>}
              </div>
            </div>
          ))}
        </div>
      )}

      {recordatorios.some(r=>r.hecho)&&(
        <button style={{...S.linkBtn,alignSelf:"flex-start",fontSize:12}} onClick={()=>setVerHechos(v=>!v)}>
          {verHechos?"Ocultar completados":"Ver completados"}
        </button>
      )}
    </div>
  );
}

const S={
  root:{minHeight:"100vh",background:C.navy,color:C.textPrimary,fontFamily:"'DM Sans','Segoe UI',sans-serif",display:"flex",flexDirection:"column"},
  header:{background:C.navyMid,borderBottom:`1px solid ${C.border}`,padding:"0 20px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,flexWrap:"wrap",minHeight:68,boxShadow:"0 2px 12px #00000040"},
  logoWrap:{display:"flex",alignItems:"center",gap:12},
  logoTitle:{fontWeight:900,fontSize:15,letterSpacing:3,color:"#ffffff",fontStyle:"italic"},
  logoSub:{fontSize:10,color:C.cyan,letterSpacing:2,fontWeight:600},
  nav:{display:"flex",gap:4,alignItems:"center",flexWrap:"wrap"},
  navBtn:{background:"transparent",border:"none",color:C.muted,padding:"8px 12px",borderRadius:8,cursor:"pointer",fontSize:13,fontWeight:600},
  navBtnActive:{background:C.cyan+"22",color:C.cyan},
  exportBtn:{background:"transparent",border:`1px solid ${C.cyan}`,color:C.cyan,padding:"7px 14px",borderRadius:8,cursor:"pointer",fontSize:12,fontWeight:700},
  btnCierre:{background:`linear-gradient(135deg,${C.cyan},${C.blue})`,color:"#fff",border:"none",borderRadius:8,padding:"10px 20px",fontWeight:800,fontSize:13,cursor:"pointer",whiteSpace:"nowrap"},
  periodoBanner:{background:C.navySurface,border:"1px solid",borderRadius:12,padding:"16px 20px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:16,flexWrap:"wrap"},
  main:{flex:1,maxWidth:740,width:"100%",margin:"0 auto",padding:"24px 16px"},
  section:{display:"flex",flexDirection:"column",gap:16},
  pageTitle:{fontSize:22,fontWeight:800,color:C.textPrimary,letterSpacing:-.5},
  sectionTitle:{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:1.5,textTransform:"uppercase",marginTop:8},
  statsGrid:{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:12},
  statCard:{background:C.navySurface,borderRadius:12,padding:"16px 14px",border:`1px solid ${C.border}`},
  statNum:{fontSize:32,fontWeight:900,lineHeight:1},
  statLabel:{fontSize:11,color:C.textSecondary,marginTop:4,fontWeight:600},
  row:{background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:12,padding:"14px 16px",display:"flex",alignItems:"center",gap:14},
  rowIcon:{width:40,height:40,borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:700,flexShrink:0},
  rowBody:{flex:1,minWidth:0},
  rowTitle:{fontWeight:700,fontSize:14,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"},
  rowMeta:{fontSize:12,marginTop:2},
  badge:{padding:"4px 10px",borderRadius:20,fontSize:11,fontWeight:700,flexShrink:0,whiteSpace:"nowrap"},
  filters:{display:"flex",gap:8,flexWrap:"wrap"},
  searchInput:{flex:1,minWidth:160,background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:8,padding:"8px 12px",color:C.textPrimary,fontSize:13,outline:"none"},
  select:{background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:8,padding:"8px 10px",color:C.textPrimary,fontSize:13,outline:"none",cursor:"pointer"},
  formGrid:{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14},
  fGroup:{display:"flex",flexDirection:"column",gap:6},
  label:{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase"},
  input:{background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:8,padding:"9px 12px",color:C.textPrimary,fontSize:13,outline:"none",fontFamily:"inherit"},
  btnPri:{background:`linear-gradient(135deg,${C.cyan},${C.blue})`,color:"#fff",border:"none",borderRadius:8,padding:"10px 22px",fontWeight:800,fontSize:14,cursor:"pointer"},
  btnSec:{background:"transparent",color:C.muted,border:`1px solid ${C.border}`,borderRadius:8,padding:"10px 18px",fontWeight:600,fontSize:14,cursor:"pointer"},
  detailHeader:{display:"flex",alignItems:"flex-start",gap:14,flexWrap:"wrap"},
  detailIcon:{width:52,height:52,borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,fontWeight:700,flexShrink:0},
  detailGrid:{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12},
  detailField:{background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:10,padding:"12px 14px"},
  detailBlock:{background:C.navySurface,border:`1px solid ${C.border}`,borderRadius:10,padding:"12px 14px"},
  fieldLabel:{fontSize:10,fontWeight:700,color:C.muted,letterSpacing:.5,textTransform:"uppercase",marginBottom:4},
  fieldValue:{fontSize:14,color:C.textPrimary},
  statusBtns:{display:"flex",gap:8,flexWrap:"wrap",marginTop:6},
  statusBtn:{padding:"7px 14px",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",background:"transparent"},
  deleteBtn:{background:"transparent",border:`1px solid ${C.danger}`,color:C.danger,borderRadius:8,padding:"8px 16px",fontSize:13,fontWeight:700,cursor:"pointer"},
  backBtn:{background:"transparent",border:"none",color:C.cyan,cursor:"pointer",fontSize:13,fontWeight:700,padding:0},
  linkBtn:{color:C.cyan,background:"transparent",border:"none",cursor:"pointer",fontSize:13,fontWeight:700,padding:"4px 0",alignSelf:"flex-start"},
  toast:{position:"fixed",bottom:24,left:"50%",transform:"translateX(-50%)",padding:"10px 22px",borderRadius:10,color:"#fff",fontWeight:700,fontSize:14,zIndex:999,boxShadow:"0 4px 20px #0006",whiteSpace:"nowrap"},
  loadingWrap:{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16,minHeight:300},
  spinner:{width:36,height:36,border:`3px solid ${C.border}`,borderTop:`3px solid ${C.cyan}`,borderRadius:"50%",animation:"spin 1s linear infinite"},
};

if(typeof document!=="undefined"){
  const s=document.createElement("style");
  s.textContent=`@keyframes spin{to{transform:rotate(360deg)}} @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;600;700;800;900&display=swap'); *{box-sizing:border-box} ::-webkit-scrollbar{width:6px} ::-webkit-scrollbar-track{background:#0D1F3C} ::-webkit-scrollbar-thumb{background:#1E3A6E;border-radius:3px}`;
  document.head.appendChild(s);
}
